import { GoogleGenAI, Type } from "@google/genai";
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { Transaction, TransactionType, TransactionAttachment } from '../types';
import { formatCurrency } from '../utils/formatters';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number;
  units: number;
  date: string;
  isin: string;
  stt: number;
  allocatedCharges: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, uploadToDrive } = useFinance();
  const familyMembers = (state.profile?.familyMembers || []).filter(m => m.status === 'verified');
  const natures = state.transactionNatures || [];

  const [showModal, setShowModal] = useState(false);
  const [modalMode, setModalMode] = useState<'single' | 'broker_note'>('single');
  const [editingId, setEditingId] = useState<string | null>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [viewingAttachments, setViewingAttachments] = useState<Transaction | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const uploadInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || 'General',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  // Set default account when in broker note mode
  useEffect(() => {
    if (modalMode === 'broker_note' && scanResult) {
       // Try to find an investment account or default
       const invAccount = allAccounts.find(a => a.name.toLowerCase().includes('zerodha') || a.name.toLowerCase().includes('demat') || a.name.toLowerCase().includes('investment'));
       if (invAccount) {
         setFormData(prev => ({ ...prev, accountId: invAccount.id }));
       }
    }
  }, [modalMode, scanResult, allAccounts]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const processDocumentWithAI = async (file: File) => {
    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') return;

    setIsScanning(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(file);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: file.type, data: base64Data } },
            { text: "Analyze this financial document. Extract: netTotal (number), date (YYYY-MM-DD), merchant (string), description (string). If it is a stock contract note, extract trades array with scrip, type (BUY/SELL), units, netTotal for each trade line." }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              netTotal: { type: Type.NUMBER },
              date: { type: Type.STRING },
              merchant: { type: Type.STRING },
              description: { type: Type.STRING },
              trades: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    scrip: { type: Type.STRING },
                    type: { type: Type.STRING },
                    units: { type: Type.NUMBER },
                    netTotal: { type: Type.NUMBER },
                  }
                }
              }
            }
          }
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);

        // Populate standard form
        setFormData(prev => ({
          ...prev,
          amount: data.netTotal ? String(data.netTotal) : prev.amount,
          date: data.date || prev.date,
          description: data.description || (data.merchant ? `Payment to ${data.merchant}` : prev.description),
          nature: (data.trades && data.trades.length > 0) ? 'Investment' : prev.nature
        }));

        // Populate scan result for broker notes
        if (data.trades && data.trades.length > 0) {
           setScanResult({
             date: data.date || new Date().toISOString().split('T')[0],
             otherCharges: 0,
             trades: data.trades.map((t: any) => ({
               scrip: t.scrip,
               type: t.type?.toUpperCase() || 'BUY',
               units: t.units || 0,
               netTotal: t.netTotal || 0,
               grossValue: t.netTotal || 0,
               date: data.date || new Date().toISOString().split('T')[0],
               isin: '',
               stt: 0,
               allocatedCharges: 0
             }))
           });
           setModalMode('broker_note'); // Auto-switch if trades detected
        }
      }
    } catch (e) {
      console.error("AI Scan failed", e);
      alert("Could not analyze document. Please try again or enter manually.");
    } finally {
      setIsScanning(false);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files);
      setPendingFiles(prev => [...prev, ...files]);
      if (files.length > 0) {
        processDocumentWithAI(files[0]);
      }
    }
  };

  const removeFile = (index: number) => {
    setPendingFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleQuickAdd = (type: TransactionType) => {
    setFormData({ ...initialFormState, type });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleBrokerAnalysis = () => {
    setFormData({ ...initialFormState, nature: 'Investment', type: 'Asset' });
    setModalMode('broker_note');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleEdit = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || '',
      estimatedLife: String(t.estimatedLife || 1)
    });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this record?')) {
      deleteTransaction(id);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select target account.");

    setIsUploading(true);

    const uploadedAttachments: TransactionAttachment[] = [];
    for (const file of pendingFiles) {
      try {
        const attachment = await uploadToDrive(file);
        uploadedAttachments.push(attachment);
      } catch (error) {
        console.error("Upload failed for file", file.name, error);
      }
    }

    if (modalMode === 'broker_note' && scanResult && scanResult.trades.length > 0) {
      // Batch Import
      for (const trade of scanResult.trades) {
        const tradeTx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          type: trade.type === 'BUY' ? 'Asset' : 'Income', // Buy stock = Asset, Sell stock = Income (realized) - simplified
          amount: trade.netTotal,
          nature: 'Investment',
          description: `${trade.type} ${trade.units} ${trade.scrip}`,
          accountId: formData.accountId,
          accountType: account.type as any,
          date: scanResult.date,
          ownerId: formData.ownerId,
          stockName: trade.scrip,
          units: trade.units,
          status: 'active',
          attachments: uploadedAttachments // Attach note to all derived txs
        };
        addTransaction(tradeTx);
      }
    } else {
      // Single Transaction
      const transactionData: Transaction = {
        id: editingId || Math.random().toString(36).substr(2, 9),
        type: formData.type, 
        amount: Number(formData.amount), 
        nature: formData.nature,
        description: formData.description, 
        accountId: formData.accountId, 
        accountType: account.type as any,
        date: formData.date, 
        ownerId: formData.ownerId, 
        isin: formData.isin, 
        stockName: formData.stockName,
        units: formData.units ? Number(formData.units) : undefined, 
        billingPeriod: formData.billingPeriod,
        estimatedLife: Number(formData.estimatedLife), 
        status: 'active',
        attachments: uploadedAttachments
      };

      if (editingId) updateTransaction(transactionData);
      else addTransaction(transactionData);
    }

    setIsUploading(false);
    setPendingFiles([]);
    setShowModal(false);
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">

      {/* Top Action Bar */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
         <button onClick={() => handleQuickAdd('Expense')} className="p-4 bg-rose-50 border border-rose-100 rounded-[2rem] hover:shadow-lg hover:border-rose-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💸</div>
            <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">New Expense</p>
         </button>
         <button onClick={() => handleQuickAdd('Income')} className="p-4 bg-emerald-50 border border-emerald-100 rounded-[2rem] hover:shadow-lg hover:border-emerald-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💰</div>
            <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">New Income</p>
         </button>
         <button onClick={() => handleQuickAdd('Asset')} className="p-4 bg-indigo-50 border border-indigo-100 rounded-[2rem] hover:shadow-lg hover:border-indigo-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💎</div>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">New Asset</p>
         </button>
         <button onClick={() => handleQuickAdd('Liability')} className="p-4 bg-amber-50 border border-amber-100 rounded-[2rem] hover:shadow-lg hover:border-amber-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💳</div>
            <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest">New Liability</p>
         </button>
         <button onClick={handleBrokerAnalysis} className="p-4 bg-slate-900 text-white border border-slate-800 rounded-[2rem] hover:shadow-xl hover:-translate-y-1 transition-all group text-left relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 text-4xl opacity-10 font-black">AI</div>
            <div className="w-10 h-10 bg-white/10 rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">🤖</div>
            <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest">Broker Analysis</p>
         </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="p-8 border-b border-slate-100 flex justify-between items-center">
           <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Audit Ledger</h3>
           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{transactionList.length} Records Verified</span>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[900px]">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Date</th>
                <th className="px-8 py-6">Nature</th>
                <th className="px-8 py-6">Description</th>
                <th className="px-8 py-6">Entity</th>
                <th className="px-8 py-6 text-right">Amount</th>
                <th className="px-8 py-6 text-center">Docs</th>
                <th className="px-8 py-6 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-500 uppercase tracking-widest">{t.date}</td>
                  <td className="px-8 py-6">
                    <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${
                      t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' :
                      t.type === 'Expense' ? 'bg-rose-50 text-rose-500' :
                      t.type === 'Asset' ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'
                    }`}>{t.type}</span>
                    <p className="text-[9px] font-bold text-slate-400 uppercase mt-1 ml-1">{t.nature}</p>
                  </td>
                  <td className="px-8 py-6">
                    <p className="text-sm font-black text-slate-800 tracking-tight">{t.description}</p>
                    {t.stockName && <p className="text-[9px] text-indigo-500 font-bold uppercase mt-0.5">{t.units} Units • {t.stockName}</p>}
                  </td>
                  <td className="px-8 py-6 text-[10px] font-black text-slate-600 uppercase tracking-widest">
                     {t.ownerId ? (familyMembers.find(m => m.id === t.ownerId)?.name || 'Member') : 'Me'}
                  </td>
                  <td className="px-8 py-6 text-right font-black tracking-tight text-sm text-slate-800">
                     {formatCurrency(t.amount, currency)}
                  </td>
                  <td className="px-8 py-6 text-center">
                    {(t.attachments && t.attachments.length > 0) ? (
                      <button onClick={() => setViewingAttachments(t)} className="w-8 h-8 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center hover:bg-indigo-100 transition-colors">
                        📎
                      </button>
                    ) : (
                      <span className="text-slate-200 text-lg">•</span>
                    )}
                  </td>
                  <td className="px-8 py-6 text-center">
                     <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => handleEdit(t)} className="text-slate-400 hover:text-indigo-600 font-black text-xs">✎</button>
                        <button onClick={() => handleDelete(t.id)} className="text-slate-400 hover:text-rose-500 font-black text-xs">✕</button>
                     </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center mb-8 shrink-0">
               <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">
                 {modalMode === 'broker_note' ? 'Broker Note Extraction' : 'Record Transaction'}
               </h3>
               <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-600 text-2xl font-black">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
              <form onSubmit={handleSubmit} className="space-y-8">

                {/* Upload Section - Prominent in Broker Mode */}
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Supporting Evidence (AI Scan)</label>
                  <div 
                    className={`border-2 border-dashed rounded-3xl p-8 text-center transition-all ${state.profile.googleDriveConfig?.isConnected ? 'border-slate-200 hover:border-indigo-400 cursor-pointer bg-slate-50' : 'border-slate-100 bg-slate-50 opacity-60 cursor-not-allowed'}`}
                    onClick={() => state.profile.googleDriveConfig?.isConnected && uploadInputRef.current?.click()}
                  >
                     {state.profile.googleDriveConfig?.isConnected ? (
                       <>
                          <input type="file" ref={uploadInputRef} className="hidden" multiple onChange={handleFileSelect} accept="image/*,.pdf" />
                          <div className={`text-3xl mb-3 transition-transform ${isScanning ? 'animate-bounce' : ''}`}>
                             {isScanning ? '🤖' : '📄'}
                          </div>
                          <p className="text-[10px] font-black text-slate-600 uppercase tracking-tight">
                            {isScanning ? 'Analyzing Document Structure...' : 'Click to Upload & Scan'}
                          </p>
                          <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">
                             {state.profile.googleDriveConfig.linkedEmail} • {state.profile.googleDriveConfig.folderName}
                          </p>
                       </>
                     ) : (
                       <div className="py-2">
                         <div className="text-2xl mb-2 grayscale opacity-50">☁️</div>
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-tight">Cloud Storage Not Linked</p>
                         <p className="text-[8px] font-bold text-rose-400 uppercase mt-1">Login to Google Drive in Profile to enable uploads</p>
                       </div>
                     )}
                  </div>

                  {/* Pending Files List */}
                  {pendingFiles.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-4">
                       {pendingFiles.map((file, idx) => (
                         <div key={idx} className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-600 rounded-xl border border-indigo-100">
                            <span className="text-xs">📄</span>
                            <span className="text-[9px] font-black uppercase truncate max-w-[100px]">{file.name}</span>
                            <button type="button" onClick={() => removeFile(idx)} className="text-[9px] hover:text-rose-500 font-black ml-1">✕</button>
                         </div>
                       ))}
                    </div>
                  )}
                </div>

                {/* Conditional Rendering based on Mode and Scan Result */}
                {modalMode === 'broker_note' && scanResult && scanResult.trades.length > 0 ? (
                  <div className="space-y-6 animate-in slide-in-from-bottom-4">
                     <div className="flex items-center justify-between p-4 bg-emerald-50 border border-emerald-100 rounded-2xl">
                        <div>
                           <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Extraction Successful</p>
                           <p className="text-xs font-black text-slate-800 mt-1">{scanResult.trades.length} Trades Identified</p>
                        </div>
                        <div className="text-right">
                           <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Date</p>
                           <p className="text-xs font-black text-slate-800">{scanResult.date}</p>
                        </div>
                     </div>

                     <div className="border border-slate-100 rounded-2xl overflow-hidden">
                        <table className="w-full text-left">
                           <thead className="bg-slate-50 text-[8px] font-black text-slate-400 uppercase tracking-widest">
                              <tr>
                                 <th className="p-3">Scrip</th>
                                 <th className="p-3">Action</th>
                                 <th className="p-3 text-right">Units</th>
                                 <th className="p-3 text-right">Net Value</th>
                              </tr>
                           </thead>
                           <tbody className="divide-y divide-slate-50">
                              {scanResult.trades.map((trade, idx) => (
                                <tr key={idx} className="text-[10px] font-black text-slate-700">
                                   <td className="p-3">{trade.scrip}</td>
                                   <td className="p-3"><span className={trade.type === 'BUY' ? 'text-emerald-600' : 'text-rose-500'}>{trade.type}</span></td>
                                   <td className="p-3 text-right">{trade.units}</td>
                                   <td className="p-3 text-right">{formatCurrency(trade.netTotal, currency)}</td>
                                </tr>
                              ))}
                           </tbody>
                        </table>
                     </div>

                     <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Target Investment Account</label>
                        <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                          <option value="">Select Account</option>
                          {allAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                        </select>
                     </div>
                  </div>
                ) : (
                  // Standard Form
                  <div className="space-y-8 animate-in fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Transaction Type</label>
                        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.type} onChange={e => setFormData({ ...formData, type: e.target.value as TransactionType })}>
                          <option value="Expense">Expense</option>
                          <option value="Income">Income</option>
                          <option value="Asset">Asset</option>
                          <option value="Liability">Liability</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Date</label>
                        <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase cursor-pointer" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Net Amount ({currency})</label>
                      <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} placeholder="0.00" />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2">
                         <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Description</label>
                         <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} placeholder="Narrative..." />
                      </div>
                      <div className="space-y-2">
                         <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature / Category</label>
                         <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })} list="nature-list" />
                         <datalist id="nature-list">{natures.map(n => <option key={n} value={n} />)}</datalist>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Account Instrument</label>
                          <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                            <option value="">Select Account</option>
                            {allAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                          </select>
                       </div>
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Entity Owner</label>
                          <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                            <option value="">Me (Primary)</option>
                            {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                          </select>
                       </div>
                    </div>
                  </div>
                )}

                {/* Actions Footer */}
                <div className="flex gap-4 pt-4 border-t border-slate-100">
                   <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl hover:bg-slate-200 transition-colors">Abort</button>
                   <button type="submit" disabled={isUploading} className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-70">
                     {isUploading ? <span className="animate-spin">⏳ Processing...</span> : (modalMode === 'broker_note' && scanResult?.trades.length ? `Import ${scanResult.trades.length} Trades` : 'Commit Record')}
                   </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Attachments Viewer */}
      {viewingAttachments && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/80 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Digital Evidence</h3>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mt-1">Stored in Secure Vault</p>
                </div>
                <button onClick={() => setViewingAttachments(null)} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {viewingAttachments.attachments?.map((att, idx) => (
                   <a key={idx} href={att.url} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-indigo-50 hover:border-indigo-100 transition-all group">
                      <div className="flex items-center gap-4 overflow-hidden">
                         <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-lg shadow-sm">📄</div>
                         <div>
                            <p className="text-[10px] font-black text-slate-800 uppercase truncate max-w-[150px]">{att.name}</p>
                            <p className="text-[8px] font-bold text-slate-400 uppercase">{new Date(att.uploadDate).toLocaleDateString()}</p>
                         </div>
                      </div>
                      <span className="text-xs text-slate-300 group-hover:text-indigo-500">↗</span>
                   </a>
                 ))}
                 {(viewingAttachments.attachments || []).length === 0 && <p className="text-center text-[10px] font-black text-slate-400 py-8">No files attached.</p>}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import { GoogleGenAI, Type } from "@google/genai";
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { Transaction, TransactionType, TransactionAttachment } from '../types';
import { formatCurrency } from '../utils/formatters';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number;
  units: number;
  date: string;
  isin: string;
  stt: number;
  allocatedCharges: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, uploadToDrive } = useFinance();
  const familyMembers = (state.profile?.familyMembers || []).filter(m => m.status === 'verified');
  const natures = state.transactionNatures || [];

  const [showModal, setShowModal] = useState(false);
  const [modalMode, setModalMode] = useState<'single' | 'broker_note'>('single');
  const [editingId, setEditingId] = useState<string | null>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [viewingAttachments, setViewingAttachments] = useState<Transaction | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const uploadInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || 'General',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  // Set default account when in broker note mode
  useEffect(() => {
    if (modalMode === 'broker_note' && scanResult) {
       // Try to find an investment account or default
       const invAccount = allAccounts.find(a => a.name.toLowerCase().includes('zerodha') || a.name.toLowerCase().includes('demat') || a.name.toLowerCase().includes('investment'));
       if (invAccount) {
         setFormData(prev => ({ ...prev, accountId: invAccount.id }));
       }
    }
  }, [modalMode, scanResult, allAccounts]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const processDocumentWithAI = async (file: File) => {
    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') return;

    setIsScanning(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(file);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: file.type, data: base64Data } },
            { text: "Analyze this financial document. Extract: netTotal (number), date (YYYY-MM-DD), merchant (string), description (string). If it is a stock contract note, extract trades array with scrip, type (BUY/SELL), units, netTotal for each trade line." }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              netTotal: { type: Type.NUMBER },
              date: { type: Type.STRING },
              merchant: { type: Type.STRING },
              description: { type: Type.STRING },
              trades: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    scrip: { type: Type.STRING },
                    type: { type: Type.STRING },
                    units: { type: Type.NUMBER },
                    netTotal: { type: Type.NUMBER },
                  }
                }
              }
            }
          }
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);

        // Populate standard form
        setFormData(prev => ({
          ...prev,
          amount: data.netTotal ? String(data.netTotal) : prev.amount,
          date: data.date || prev.date,
          description: data.description || (data.merchant ? `Payment to ${data.merchant}` : prev.description),
          nature: (data.trades && data.trades.length > 0) ? 'Investment' : prev.nature
        }));

        // Populate scan result for broker notes
        if (data.trades && data.trades.length > 0) {
           setScanResult({
             date: data.date || new Date().toISOString().split('T')[0],
             otherCharges: 0,
             trades: data.trades.map((t: any) => ({
               scrip: t.scrip,
               type: t.type?.toUpperCase() || 'BUY',
               units: t.units || 0,
               netTotal: t.netTotal || 0,
               grossValue: t.netTotal || 0,
               date: data.date || new Date().toISOString().split('T')[0],
               isin: '',
               stt: 0,
               allocatedCharges: 0
             }))
           });
           setModalMode('broker_note'); // Auto-switch if trades detected
        }
      }
    } catch (e) {
      console.error("AI Scan failed", e);
      alert("Could not analyze document. Please try again or enter manually.");
    } finally {
      setIsScanning(false);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files) as File[];
      setPendingFiles(prev => [...prev, ...files]);
      if (files.length > 0) {
        processDocumentWithAI(files[0]);
      }
    }
  };

  const removeFile = (index: number) => {
    setPendingFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleQuickAdd = (type: TransactionType) => {
    setFormData({ ...initialFormState, type });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleBrokerAnalysis = () => {
    setFormData({ ...initialFormState, nature: 'Investment', type: 'Asset' });
    setModalMode('broker_note');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleEdit = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || '',
      estimatedLife: String(t.estimatedLife || 1)
    });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this record?')) {
      deleteTransaction(id);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select target account.");

    setIsUploading(true);

    const uploadedAttachments: TransactionAttachment[] = [];
    for (const file of pendingFiles) {
      try {
        const attachment = await uploadToDrive(file);
        uploadedAttachments.push(attachment);
      } catch (error) {
        console.error("Upload failed for file", file.name, error);
      }
    }

    if (modalMode === 'broker_note' && scanResult && scanResult.trades.length > 0) {
      // Batch Import
      for (const trade of scanResult.trades) {
        const tradeTx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          type: trade.type === 'BUY' ? 'Asset' : 'Income', // Buy stock = Asset, Sell stock = Income (realized) - simplified
          amount: trade.netTotal,
          nature: 'Investment',
          description: `${trade.type} ${trade.units} ${trade.scrip}`,
          accountId: formData.accountId,
          accountType: account.type as any,
          date: scanResult.date,
          ownerId: formData.ownerId,
          stockName: trade.scrip,
          units: trade.units,
          status: 'active',
          attachments: uploadedAttachments // Attach note to all derived txs
        };
        addTransaction(tradeTx);
      }
    } else {
      // Single Transaction
      const transactionData: Transaction = {
        id: editingId || Math.random().toString(36).substr(2, 9),
        type: formData.type, 
        amount: Number(formData.amount), 
        nature: formData.nature,
        description: formData.description, 
        accountId: formData.accountId, 
        accountType: account.type as any,
        date: formData.date, 
        ownerId: formData.ownerId, 
        isin: formData.isin, 
        stockName: formData.stockName,
        units: formData.units ? Number(formData.units) : undefined, 
        billingPeriod: formData.billingPeriod,
        estimatedLife: Number(formData.estimatedLife), 
        status: 'active',
        attachments: uploadedAttachments
      };

      if (editingId) updateTransaction(transactionData);
      else addTransaction(transactionData);
    }

    setIsUploading(false);
    setPendingFiles([]);
    setShowModal(false);
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">

      {/* Top Action Bar */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
         <button onClick={() => handleQuickAdd('Expense')} className="p-4 bg-rose-50 border border-rose-100 rounded-[2rem] hover:shadow-lg hover:border-rose-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💸</div>
            <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">New Expense</p>
         </button>
         <button onClick={() => handleQuickAdd('Income')} className="p-4 bg-emerald-50 border border-emerald-100 rounded-[2rem] hover:shadow-lg hover:border-emerald-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💰</div>
            <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">New Income</p>
         </button>
         <button onClick={() => handleQuickAdd('Asset')} className="p-4 bg-indigo-50 border border-indigo-100 rounded-[2rem] hover:shadow-lg hover:border-indigo-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💎</div>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">New Asset</p>
         </button>
         <button onClick={() => handleQuickAdd('Liability')} className="p-4 bg-amber-50 border border-amber-100 rounded-[2rem] hover:shadow-lg hover:border-amber-200 hover:-translate-y-1 transition-all group text-left">
            <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">💳</div>
            <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest">New Liability</p>
         </button>
         <button onClick={handleBrokerAnalysis} className="p-4 bg-slate-900 text-white border border-slate-800 rounded-[2rem] hover:shadow-xl hover:-translate-y-1 transition-all group text-left relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 text-4xl opacity-10 font-black">AI</div>
            <div className="w-10 h-10 bg-white/10 rounded-full flex items-center justify-center text-xl shadow-sm mb-3 group-hover:scale-110 transition-transform">🤖</div>
            <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest">Broker Analysis</p>
         </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="p-8 border-b border-slate-100 flex justify-between items-center">
           <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Audit Ledger</h3>
           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{transactionList.length} Records Verified</span>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[900px]">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Date</th>
                <th className="px-8 py-6">Nature</th>
                <th className="px-8 py-6">Description</th>
                <th className="px-8 py-6">Entity</th>
                <th className="px-8 py-6 text-right">Amount</th>
                <th className="px-8 py-6 text-center">Docs</th>
                <th className="px-8 py-6 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-500 uppercase tracking-widest">{t.date}</td>
                  <td className="px-8 py-6">
                    <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${
                      t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' :
                      t.type === 'Expense' ? 'bg-rose-50 text-rose-500' :
                      t.type === 'Asset' ? 'bg-indigo-50 text-indigo-600' : 'bg-amber-50 text-amber-600'
                    }`}>{t.type}</span>
                    <p className="text-[9px] font-bold text-slate-400 uppercase mt-1 ml-1">{t.nature}</p>
                  </td>
                  <td className="px-8 py-6">
                    <p className="text-sm font-black text-slate-800 tracking-tight">{t.description}</p>
                    {t.stockName && <p className="text-[9px] text-indigo-500 font-bold uppercase mt-0.5">{t.units} Units • {t.stockName}</p>}
                  </td>
                  <td className="px-8 py-6 text-[10px] font-black text-slate-600 uppercase tracking-widest">
                     {t.ownerId ? (familyMembers.find(m => m.id === t.ownerId)?.name || 'Member') : 'Me'}
                  </td>
                  <td className="px-8 py-6 text-right font-black tracking-tight text-sm text-slate-800">
                     {formatCurrency(t.amount, currency)}
                  </td>
                  <td className="px-8 py-6 text-center">
                    {(t.attachments && t.attachments.length > 0) ? (
                      <button onClick={() => setViewingAttachments(t)} className="w-8 h-8 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center hover:bg-indigo-100 transition-colors">
                        📎
                      </button>
                    ) : (
                      <span className="text-slate-200 text-lg">•</span>
                    )}
                  </td>
                  <td className="px-8 py-6 text-center">
                     <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => handleEdit(t)} className="text-slate-400 hover:text-indigo-600 font-black text-xs">✎</button>
                        <button onClick={() => handleDelete(t.id)} className="text-slate-400 hover:text-rose-500 font-black text-xs">✕</button>
                     </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center mb-8 shrink-0">
               <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">
                 {modalMode === 'broker_note' ? 'Broker Note Extraction' : 'Record Transaction'}
               </h3>
               <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-600 text-2xl font-black">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
              <form onSubmit={handleSubmit} className="space-y-8">

                {/* Upload Section - Prominent in Broker Mode */}
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Supporting Evidence (AI Scan)</label>
                  <div 
                    className={`border-2 border-dashed rounded-3xl p-8 text-center transition-all ${state.profile.googleDriveConfig?.isConnected ? 'border-slate-200 hover:border-indigo-400 cursor-pointer bg-slate-50' : 'border-slate-100 bg-slate-50 opacity-60 cursor-not-allowed'}`}
                    onClick={() => state.profile.googleDriveConfig?.isConnected && uploadInputRef.current?.click()}
                  >
                     {state.profile.googleDriveConfig?.isConnected ? (
                       <>
                          <input type="file" ref={uploadInputRef} className="hidden" multiple onChange={handleFileSelect} accept="image/*,.pdf" />
                          <div className={`text-3xl mb-3 transition-transform ${isScanning ? 'animate-bounce' : ''}`}>
                             {isScanning ? '🤖' : '📄'}
                          </div>
                          <p className="text-[10px] font-black text-slate-600 uppercase tracking-tight">
                            {isScanning ? 'Analyzing Document Structure...' : 'Click to Upload & Scan'}
                          </p>
                          <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">
                             {state.profile.googleDriveConfig.linkedEmail} • {state.profile.googleDriveConfig.folderName}
                          </p>
                       </>
                     ) : (
                       <div className="py-2">
                         <div className="text-2xl mb-2 grayscale opacity-50">☁️</div>
                         <p className="text-[10px] font-black text-slate-400 uppercase tracking-tight">Cloud Storage Not Linked</p>
                         <p className="text-[8px] font-bold text-rose-400 uppercase mt-1">Login to Google Drive in Profile to enable uploads</p>
                       </div>
                     )}
                  </div>

                  {/* Pending Files List */}
                  {pendingFiles.length > 0 && (
