import React, { useState, useRef, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { MonitoredApp, MemberPermissions } from '../types';

// Declare Google Types for TypeScript
declare global {
  interface Window {
    google: any;
    gapi: any;
  }
}

const Profile: React.FC = () => {
  const { state, updateProfile, addFamilyMember, removeFamilyMember, updateMemberPermissions, verifyFamilyMember, simulateIncomingRequest } = useFinance();
  const profile = state.profile;
  const [showAddMember, setShowAddMember] = useState(false);
  const [showPermissions, setShowPermissions] = useState<string | null>(null);
  const [newMember, setNewMember] = useState({ name: '', relation: 'Spouse', mobile: '' });

  // Google Drive State
  const [isConnecting, setIsConnecting] = useState(false);
  const [showFolderSelection, setShowFolderSelection] = useState(false);
  const [showDriveConfig, setShowDriveConfig] = useState(false);
  const [driveConfigData, setDriveConfigData] = useState({ clientId: profile.googleDriveConfig?.clientId || '', apiKey: profile.googleDriveConfig?.apiKey || '' });
  const [availableFolders, setAvailableFolders] = useState<any[]>([]);
  const [tokenClient, setTokenClient] = useState<any>(null);

  // Initialize Google Scripts
  useEffect(() => {
    if (profile.googleDriveConfig?.clientId && profile.googleDriveConfig?.apiKey) {
      // Re-initialize if credentials exist
      initializeGapiClient();
    }
  }, [profile.googleDriveConfig?.clientId]);

  const initializeGapiClient = () => {
    if (!window.gapi || !window.google) return;

    // Load GAPI Client
    window.gapi.load('client', async () => {
      await window.gapi.client.init({
        apiKey: profile.googleDriveConfig?.apiKey || driveConfigData.apiKey,
        discoveryDocs: ['https://www.googleapis.com/discovery/v1/apis/drive/v3/rest'],
      });
    });

    // Init Token Client
    const client = window.google.accounts.oauth2.initTokenClient({
      client_id: profile.googleDriveConfig?.clientId || driveConfigData.clientId,
      scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/drive.readonly',
      callback: async (response: any) => {
        if (response.error !== undefined) {
          throw (response);
        }
        await listDriveFolders();
      },
    });
    setTokenClient(client);
  };

  const listDriveFolders = async () => {
    try {
      setIsConnecting(true);
      const response = await window.gapi.client.drive.files.list({
        'pageSize': 10,
        'fields': "nextPageToken, files(id, name)",
        'q': "mimeType = 'application/vnd.google-apps.folder' and trashed = false"
      });
      const files = response.result.files;
      if (files && files.length > 0) {
         setAvailableFolders(files);
         setShowFolderSelection(true);
      } else {
         alert('No folders found in Drive. Please create one.');
      }
    } catch (err) {
      console.error('Error listing folders', err);
      alert('Failed to fetch Drive folders. Check API Key restrictions.');
    } finally {
      setIsConnecting(false);
    }
  };

  const handleAddMember = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newMember.name && newMember.mobile) {
      await addFamilyMember({
        id: Math.random().toString(36).substr(2, 9),
        name: newMember.name,
        relation: newMember.relation,
        mobileNumber: newMember.mobile,
        status: 'pending_invitation',
        permissions: { viewDashboard: true, viewStatements: true, viewBudget: true, viewTransactions: true, viewCalendar: true, viewAccounts: true, canCreateTransactions: true }
      });
      setNewMember({ name: '', relation: 'Spouse', mobile: '' });
      setShowAddMember(false);
    }
  };

  const handleDeleteMember = (id: string, name: string) => {
    if (confirm(`Are you sure you want to remove ${name} from your family vault? This will revoke all their access.`)) {
      removeFamilyMember(id);
    }
  };

  const handleGoogleLogin = () => {
    // Check if credentials exist
    if (!profile.googleDriveConfig?.clientId && !driveConfigData.clientId) {
      setShowDriveConfig(true);
      return;
    }

    // If we have data in state but not yet committed to profile or initialized
    if (!tokenClient && driveConfigData.clientId) {
      initializeGapiClient();
      setTimeout(() => {
         if (window.google && window.gapi) {
            const client = window.google.accounts.oauth2.initTokenClient({
               client_id: driveConfigData.clientId,
               scope: 'https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/drive.readonly',
               callback: async (response: any) => {
                 if (response.error) {
                    console.error(response);
                    return;
                 }
                 // Fetch user info for email
                 try {
                    // We can't easily get email without userinfo.profile scope which needs more verification.
                    // Just proceeding to list folders.
                    await listDriveFolders();
                 } catch (e) {
                    console.error(e);
                 }
               },
            });
            client.requestAccessToken();
         }
      }, 500);
      return;
    }

    if (tokenClient) {
      tokenClient.requestAccessToken({ prompt: 'consent' });
    }
  };

  const handleSaveDriveConfig = (e: React.FormEvent) => {
    e.preventDefault();
    updateProfile({
      ...profile,
      googleDriveConfig: {
        ...profile.googleDriveConfig!,
        clientId: driveConfigData.clientId,
        apiKey: driveConfigData.apiKey
      }
    });
    setShowDriveConfig(false);
    // Trigger login immediately after save
    setTimeout(handleGoogleLogin, 500);
  };

  const confirmFolderSelection = (folderId: string, folderName: string) => {
    updateProfile({
      ...profile,
      googleDriveConfig: {
        ...profile.googleDriveConfig!,
        isConnected: true,
        linkedEmail: 'Connected Account', // We don't fetch email to avoid extra scope
        folderId: folderId,
        folderName: folderName
      }
    });
    setShowFolderSelection(false);
  };

  const handleDisconnect = () => {
    if (window.confirm("Disconnect Google Drive? This will stop evidence synchronization.")) {
      const { clientId, apiKey } = profile.googleDriveConfig || {};
      updateProfile({
        ...profile,
        googleDriveConfig: {
          isConnected: false,
          linkedEmail: '',
          folderId: '',
          folderName: '',
          clientId, // Retain credentials
          apiKey
        }
      });
    }
  };

  const togglePermission = (id: string, key: keyof MemberPermissions) => {
    const member = profile.familyMembers.find(m => m.id === id);
    if (member) {
      updateMemberPermissions(id, { ...member.permissions, [key]: !member.permissions[key] });
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20 px-3 md:px-0 mx-auto">
      <div className="bg-white md:rounded-[3rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="h-40 bg-indigo-600 p-8 flex items-end relative">
           <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/10 tracking-tighter uppercase">MF</div>
           <div className="w-24 h-24 bg-white p-1 translate-y-12 z-10 shadow-xl rounded-[2rem]">
               <div className="w-full h-full bg-slate-100 flex items-center justify-center text-4xl font-black text-indigo-600 rounded-2xl uppercase">{profile?.name?.charAt(0) || '?'}</div>
           </div>
        </div>
        <div className="px-8 pt-16 pb-10">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="text-3xl font-black text-slate-800 tracking-tight uppercase">{profile?.name}</h3>
              <p className="text-xs font-black text-indigo-500 uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 p-6 bg-slate-50 border border-slate-100 rounded-[2rem]">
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Local Identity</p><p className="text-xs font-black text-slate-800 uppercase">{profile?.city}, {profile?.country}</p></div>
             <div><p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Audit Currency</p><p className="text-xs font-black text-indigo-600 uppercase">{profile?.currency}</p></div>
          </div>
        </div>
      </div>

      {/* Google Drive Configuration Card (Real Integration) */}
      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-sm relative overflow-hidden group">
         <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-indigo-600">DRIVE</div>

         <div className="flex justify-between items-center mb-6 relative z-10">
           <div className="flex items-center gap-2">
              <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Google Drive Integration</h4>
              {!profile.googleDriveConfig?.isConnected && (
                <button onClick={() => setShowDriveConfig(true)} className="text-[8px] font-black uppercase text-indigo-500 hover:text-indigo-700 bg-indigo-50 px-2 py-1 rounded-lg">⚙ Config</button>
              )}
           </div>
           {profile.googleDriveConfig?.isConnected ? (
             <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[8px] font-black uppercase tracking-widest border border-emerald-100">● Logged In</span>
           ) : (
             <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-lg text-[8px] font-black uppercase tracking-widest">○ Not Connected</span>
           )}
         </div>

         <div className="relative z-10">
            {!profile.googleDriveConfig?.isConnected ? (
               <div className="flex flex-col items-start gap-6">
                 <p className="text-[10px] font-medium text-slate-500 leading-relaxed max-w-lg">
                    Authenticate with your Google account to enable evidence synchronization. Requires Client ID and API Key from Google Cloud Console.
                 </p>
                 <button 
                   onClick={handleGoogleLogin} 
                   disabled={isConnecting}
                   className="flex items-center gap-3 px-6 py-4 bg-white border border-slate-200 rounded-2xl shadow-lg hover:shadow-xl hover:bg-slate-50 transition-all active:scale-95 disabled:opacity-70 disabled:pointer-events-none"
                 >
                    {isConnecting ? (
                      <>
                        <div className="w-5 h-5 border-2 border-slate-300 border-t-indigo-600 rounded-full animate-spin"></div>
                        <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Connecting to Google...</span>
                      </>
                    ) : (
                      <>
                        <img src="https://upload.wikimedia.org/wikipedia/commons/1/12/Google_Drive_icon_%282020%29.svg" alt="Drive" className="w-5 h-5" />
                        <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Login to Google Drive</span>
                      </>
                    )}
                 </button>
               </div>
            ) : (
               <div className="space-y-6">
                 <div className="p-6 bg-slate-50 border border-slate-100 rounded-[2rem] flex items-center justify-between">
                    <div className="flex items-center gap-4">
                       <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center shadow-sm">
                          <img src="https://lh3.googleusercontent.com/a/default-user=s100" alt="User" className="w-8 h-8 rounded-full" />
                       </div>
                       <div>
                          <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{profile.googleDriveConfig.linkedEmail}</p>
                          <p className="text-[8px] font-bold text-emerald-500 uppercase tracking-widest mt-0.5">● Session Active</p>
                       </div>
                    </div>
                    <button 
                      onClick={handleDisconnect}
                      className="px-4 py-2 bg-white border border-slate-200 text-rose-500 text-[8px] font-black uppercase rounded-xl hover:bg-rose-50 hover:border-rose-100 transition-colors"
                    >
                      Logout
                    </button>
                 </div>

                 <div className="flex items-center gap-4 px-2">
                    <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-lg">📂</div>
                    <div>
                       <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Target Folder</p>
                       <p className="text-[10px] font-black text-slate-800 uppercase">{profile.googleDriveConfig.folderName}</p>
                    </div>
                 </div>
               </div>
            )}
         </div>
      </div>

      <div className="bg-white p-8 rounded-[3rem] border border-slate-200 shadow-sm">
        <div className="flex justify-between items-center mb-8">
          <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Family Vault Access</h4>
          <button onClick={() => setShowAddMember(true)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl">+ Invite Member</button>
        </div>
        <div className="space-y-4">
          {profile?.familyMembers.map(member => (
            <div key={member.id} className="p-6 bg-slate-50 border border-slate-100 rounded-[2rem] flex flex-col md:flex-row md:items-center justify-between gap-6 group">
              <div className="flex items-center gap-5">
                <div className={`w-12 h-12 flex items-center justify-center font-black rounded-2xl border border-slate-200 uppercase text-xl ${member.status === 'verified' ? 'bg-indigo-600 text-white' : 'bg-white text-slate-300'}`}>
                   {member.status === 'verified' ? '✓' : '⏳'}
                </div>
                <div>
                  <p className="text-sm font-black text-slate-800 uppercase">{member.name}</p>
                  <p className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{member.relation} • {member.status === 'verified' ? 'Verified Session' : 'Pending Verification'}</p>
                </div>
              </div>
              <div className="flex items-center gap-3">
                 {member.status === 'pending_invitation' && (
                   <button onClick={() => verifyFamilyMember(member.id)} className="px-4 py-2 bg-emerald-50 text-emerald-600 border border-emerald-100 text-[8px] font-black uppercase rounded-xl">Simulate Accept</button>
                 )}
                 <button onClick={() => setShowPermissions(member.id)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 text-[8px] font-black uppercase rounded-xl hover:bg-slate-100">Manage Access</button>
                 <button onClick={() => handleDeleteMember(member.id, member.name)} className="px-4 py-2 bg-white border border-slate-200 text-rose-500 text-[8px] font-black uppercase rounded-xl hover:bg-rose-50 hover:border-rose-100">Remove</button>
              </div>
            </div>
          ))}
          {profile?.familyMembers.length === 0 && <p className="py-12 text-center text-slate-300 italic text-[10px] uppercase tracking-widest">No participant links active</p>}
        </div>
      </div>

      {/* Developer / Demo Tools for Request Simulation */}
      <div className="bg-slate-900 text-white p-8 rounded-[3rem] shadow-xl relative overflow-hidden">
         <div className="relative z-10">
           <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-4">Simulation Zone</h4>
           <div className="flex flex-col md:flex-row justify-between items-center gap-6">
             <div className="space-y-1">
               <p className="text-lg font-black uppercase tracking-tight">Test Incoming Requests</p>
               <p className="text-[9px] text-slate-400 uppercase tracking-widest">Simulate another user requesting to link with your vault.</p>
             </div>
             <button 
               onClick={() => simulateIncomingRequest('Demo User', '9999999999', 'Partner')}
               className="px-6 py-4 bg-white/10 hover:bg-white/20 rounded-2xl text-[9px] font-black uppercase tracking-widest border border-white/10 transition-colors"
             >
               Trigger Remote Request
             </button>
           </div>
         </div>
      </div>

      {/* Drive Credentials Modal */}
      {showDriveConfig && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-2">Cloud Credentials</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-6">Enter details from Google Cloud Console</p>

              <form onSubmit={handleSaveDriveConfig} className="space-y-4">
                 <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">Client ID</label>
                    <input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl text-[10px] font-black outline-none" value={driveConfigData.clientId} onChange={e => setDriveConfigData({...driveConfigData, clientId: e.target.value})} placeholder="xxxxxxxx-xxxxxxxx.apps.googleusercontent.com" />
                 </div>
                 <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">API Key</label>
                    <input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl text-[10px] font-black outline-none" value={driveConfigData.apiKey} onChange={e => setDriveConfigData({...driveConfigData, apiKey: e.target.value})} placeholder="AIzaSy..." />
                 </div>

                 <div className="pt-4 flex gap-3">
                   <button type="button" onClick={() => setShowDriveConfig(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                   <button type="submit" className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl">Save & Connect</button>
                 </div>
              </form>
           </div>
        </div>
      )}

      {/* Folder Selection Modal (Real Data) */}
      {showFolderSelection && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-2">Select Destination Folder</h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-6">Choose a folder to store receipts</p>

              <div className="space-y-3 mb-8 max-h-[300px] overflow-y-auto custom-scrollbar">
                 {availableFolders.map(folder => (
                   <button 
                     key={folder.id}
                     onClick={() => confirmFolderSelection(folder.id, folder.name)}
                     className="w-full flex items-center gap-4 p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-indigo-50 hover:border-indigo-100 transition-all group text-left"
                   >
                      <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center shadow-sm text-lg">📂</div>
                      <div>
                         <p className="text-xs font-black text-slate-700 uppercase group-hover:text-indigo-600 truncate max-w-[200px]">{folder.name}</p>
                         <p className="text-[8px] font-bold text-slate-400 uppercase">ID: {folder.id.substr(0, 8)}...</p>
                      </div>
                   </button>
                 ))}
                 {availableFolders.length === 0 && <p className="text-center text-xs p-4">No folders found.</p>}
              </div>

              <button onClick={() => setShowFolderSelection(false)} className="w-full py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
           </div>
        </div>
      )}

      {showPermissions && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-lg rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-200">
              <div className="flex justify-between items-center mb-10">
                 <div>
                   <h4 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Permission Matrix</h4>
                   <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-1">Audit Constraints for {profile.familyMembers.find(m => m.id === showPermissions)?.name}</p>
                 </div>
                 <button onClick={() => setShowPermissions(null)} className="text-slate-200 hover:text-slate-800 text-2xl font-black transition-colors">✕</button>
              </div>

              <div className="space-y-3">
                {[
                  { key: 'viewDashboard', label: 'Dashboard Access', desc: 'Summary metrics & live burn rates' },
                  { key: 'viewStatements', label: 'Audit Statements', desc: 'P&L and Balance Sheet details' },
                  { key: 'viewTransactions', label: 'History Ledger', desc: 'Full transaction timeline' },
                  { key: 'viewBudget', label: 'Budget Architect', desc: 'Target allocation controls' },
                  { key: 'viewCalendar', label: 'Fiscal Sentinel', desc: 'Due date pressure analysis' },
                  { key: 'viewAccounts', label: 'Instrument Vault', desc: 'Bank & Credit Card configurations' },
                  { key: 'canCreateTransactions', label: 'Write Access', desc: 'Ability to record new transactions' }
                ].map((perm) => (
                  <div key={perm.key} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl group hover:border-indigo-200 transition-all cursor-pointer" onClick={() => togglePermission(showPermissions, perm.key as keyof MemberPermissions)}>
                    <div>
                      <p className="text-[10px] font-black text-slate-800 uppercase tracking-tight">{perm.label}</p>
                      <p className="text-[8px] text-slate-400 font-medium">{perm.desc}</p>
                    </div>
                    <div className={`w-12 h-7 rounded-full relative transition-all ${profile.familyMembers.find(m => m.id === showPermissions)?.permissions[perm.key as keyof MemberPermissions] ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <div className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow-sm transition-all ${profile.familyMembers.find(m => m.id === showPermissions)?.permissions[perm.key as keyof MemberPermissions] ? 'left-6' : 'left-1'}`}></div>
                    </div>
                  </div>
                ))}
              </div>

              <button onClick={() => setShowPermissions(null)} className="w-full mt-10 py-5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-slate-200 active:scale-95 transition-all">Apply Constraints</button>
           </div>
        </div>
      )}

      {showAddMember && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 shadow-2xl animate-in zoom-in duration-200">
             <h4 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">Link Participant</h4>
             <form onSubmit={handleAddMember} className="space-y-6">
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase" value={newMember.name} onChange={e => setNewMember({...newMember, name: e.target.value})} placeholder="Legal Name" />
                <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={newMember.relation} onChange={e => setNewMember({...newMember, relation: e.target.value})}>
                  <option>Spouse</option><option>Child</option><option>Parent</option><option>Partner</option>
                </select>
                <input required type="tel" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={newMember.mobile} onChange={e => setNewMember({...newMember, mobile: e.target.value.replace(/\D/g, '')})} placeholder="Identification Key (Mobile)" />
                <div className="flex gap-4 pt-6">
                  <button type="button" onClick={() => setShowAddMember(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Abort</button>
                  <button type="submit" className="flex-[2] px-4 py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl">Send Invite</button>
                </div>
             </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default Profile;

