              <span className="text-xl">{item.icon}</span><span className="uppercase tracking-widest text-[11px]">{item.label}</span>
            </button>
          ))}

          <div className="my-4 mx-5 h-px bg-white/10"></div>

          <button onClick={handleSignOut} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all text-slate-400 hover:text-rose-400 hover:bg-white/5 group">
