          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto custom-scrollbar md:ml-72 pb-24 md:pb-0">
        <header className={`sticky top-0 bg-slate-50/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'}`}>
          <div className="flex items-center gap-4">
             {/* Mobile Logo Only */}
             <div className="md:hidden flex items-center gap-2">
                <div className="w-8 h-8 bg-[#03246B] rounded-lg flex items-center justify-center font-bold text-white text-xs">M</div>
