                   {/* Actuals Row */}
                   <tr className="hover:bg-slate-50/30 transition-colors bg-slate-50/10">
                      <td className="p-6">
                         <span className="text-xs font-black text-slate-800 uppercase tracking-tight">Actuals</span>
                         <span className="ml-2 px-2 py-0.5 bg-[#FEFE1F] text-[#03246B] text-[8px] font-black rounded-full uppercase tracking-widest">Live</span>
