import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { useFinance } from '../store/FinanceContext';

// Lazy load modal
const BulkAuditModal = lazy(() => import('./BulkAuditModal'));

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, approveTransaction, rejectTransaction, handleFamilyRequest } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);
  const [showBulkAudit, setShowBulkAudit] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];

  // Get permissions for the currently active view
  const activePermissions = React.useMemo(() => {
    if (activeMemberIds.length === 0 || activeMemberIds.includes('all')) return null; // Owner or Consolidated has full access
    if (activeMemberIds.length === 1) {
      return familyMembers.find(m => m.id === activeMemberIds[0])?.permissions || null;
    }
    return null;
  }, [activeMemberIds, familyMembers]);

  useEffect(() => {
    const handleScroll = () => { if (mainRef.current) setIsShrunk(mainRef.current.scrollTop > 30); };
    const currentMain = mainRef.current;
    if (currentMain) currentMain.addEventListener('scroll', handleScroll);
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  const rawNavItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', perm: 'viewDashboard' },
    { id: 'rankings', label: 'Rankings', icon: '🏆', perm: 'viewDashboard' },
    { id: 'accounts', label: 'Accounts', icon: '🏦', perm: 'viewAccounts' },
    { id: 'transactions', label: 'Transactions', icon: '💸', perm: 'viewTransactions' },
    { id: 'budget', label: 'Budget', icon: '🎯', perm: 'viewBudget' },
    { id: 'calendar', label: 'Calendar', icon: '📅', perm: 'viewCalendar' },
    { id: 'statements', label: 'Reports', icon: '📜', perm: 'viewStatements' },
    { id: 'profile', label: 'You', icon: '👤', perm: null },
  ];

  const navItems = rawNavItems.filter(item => {
    if (!activePermissions || !item.perm) return true;
    return (activePermissions as any)[item.perm];
  });

  const mobileTabIds = ['dashboard', 'transactions', 'statements', 'profile'];
  const mobileNavItems = navItems.filter(item => mobileTabIds.includes(item.id));

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Entire Family';
    if (isMeSelected) return state.profile.name || 'Me'; // Use user name instead of "Mine"
    const member = familyMembers.find(m => m.id === activeMemberIds[0]);
    return member ? member.name : 'Group View';
  };

  const pendingApprovals = state.notifications.filter(n => n.type === 'approval_request' || n.type === 'family_request');

  const handleSignOut = async () => {
    await resetBoarding();
  };

  return (
    <div className="h-[100dvh] w-full flex bg-slate-50 font-sans selection:bg-brand-yellow/30 overflow-hidden relative">

      {/* Desktop Sidebar (Persistent) */}
