        <div className="p-8 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-[#FEFE1F] text-[#03246B] rounded-lg flex items-center justify-center font-black">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
        </div>
        <nav className="flex-1 px-4 py-4 space-y-1 overflow-y-auto custom-scrollbar">
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-[#FEFE1F] text-[#03246B] shadow-lg shadow-yellow-500/20' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}>
              <span className="text-xl">{item.icon}</span><span className="uppercase tracking-widest text-[11px]">{item.label}</span>
            </button>
          ))}

          <div className="my-4 mx-5 h-px bg-white/10"></div>

          <button onClick={handleSignOut} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all text-slate-400 hover:text-rose-400 hover:bg-white/5 group">
            <span className="text-xl group-hover:scale-110 transition-transform">🚪</span><span className="uppercase tracking-widest text-[11px]">Sign Out</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto custom-scrollbar md:ml-72 pb-28 md:pb-0">
        <header className={`sticky top-0 bg-slate-50/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'}`}>
          <div className="flex items-center gap-4">
             {/* Mobile Logo / Back Button */}
             <div className="md:hidden flex items-center gap-2">
                {activeTab !== 'dashboard' ? (
                   <button onClick={() => setActiveTab('dashboard')} className="flex items-center gap-2 px-3 py-2 bg-slate-200/50 rounded-xl text-[#03246B] active:scale-95 transition-transform">
                      <span className="text-sm font-bold">←</span>
                      <span className="text-[10px] font-black uppercase tracking-widest">Home</span>
                   </button>
                ) : (
                   <>
                      <div className="w-8 h-8 bg-[#03246B] rounded-lg flex items-center justify-center font-bold text-white text-xs">M</div>
                      <h1 className="text-lg font-black text-[#03246B] tracking-tight">MyFin</h1>
                   </>
                )}
             </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative">
              <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="flex items-center gap-2 px-4 py-2.5 bg-white rounded-2xl text-[9px] font-black uppercase tracking-widest border border-slate-200 text-[#03246B] shadow-sm">
                <span className="text-xs">👥</span><span className="max-w-[100px] truncate">{getSelectionLabel()}</span>
              </button>
              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-white border border-slate-200 rounded-[2rem] shadow-2xl z-50 p-3 space-y-1">
                    <button onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isMeSelected ? 'bg-[#03246B] text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>👤 My Vault</button>
                    <button onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isAllSelected ? 'bg-[#03246B] text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>🌍 Consolidated</button>
                    <div className="h-px bg-slate-100 my-2"></div>
                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { setActiveMemberIds([m.id]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-[#03246B] text-white shadow-lg' : 'hover:bg-slate-50 text-slate-500'}`}>
                        {m.name} {m.status === 'pending_invitation' && '⏳'}
                      </button>
                    ))}
                </div>
              )}
            </div>

            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 bg-white rounded-2xl text-[#03246B] flex items-center justify-center border border-slate-200 transition-all hover:bg-slate-50">
               <span className="text-xl">🔔</span>
               {pendingApprovals.length > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
            </button>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-12">{children}</div>

        {showNotifications && pendingApprovals.length > 0 && (
          <div className="fixed top-24 right-4 w-80 bg-white border border-slate-200 rounded-[2.5rem] shadow-2xl z-50 p-6 animate-in slide-in-from-right-10 flex flex-col max-h-[70vh]">
            <div className="flex justify-between items-center mb-6">
               <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Action Required</h4>
               {pendingApprovals.filter(n => n.type === 'approval_request').length > 1 && (
                 <button 
                   onClick={() => { setShowBulkAudit(true); setShowNotifications(false); }}
                   className="text-[9px] font-black text-[#03246B] uppercase tracking-widest bg-indigo-50 px-2 py-1 rounded-lg"
                 >
                   Bulk Audit
                 </button>
               )}
            </div>

            <div className="space-y-4 overflow-y-auto custom-scrollbar flex-1 pr-1">
               {pendingApprovals.map(n => {
                 const isFamilyRequest = n.type === 'family_request';
                 return (
                   <div key={n.id} className={`p-4 rounded-2xl border ${isFamilyRequest ? 'bg-indigo-50 border-indigo-200 shadow-sm' : 'bg-slate-50 border-slate-100'}`}>
                      {isFamilyRequest && <span className="inline-block bg-[#03246B] text-white text-[7px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest mb-2">Priority Request</span>}
                      <p className="text-[10px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                      <p className="text-[9px] text-slate-500 font-medium mt-1">{n.message}</p>
                      <div className="flex gap-2 mt-4">
                         {isFamilyRequest ? (
                           <>
                              <button onClick={() => handleFamilyRequest(n.id, true)} className="flex-1 py-2 bg-[#03246B] text-white text-[8px] font-black uppercase rounded-lg shadow-lg shadow-indigo-200">Verify & Link</button>
                              <button onClick={() => handleFamilyRequest(n.id, false)} className="flex-1 py-2 bg-white text-slate-400 border border-slate-200 text-[8px] font-black uppercase rounded-lg">Ignore</button>
                           </>
                         ) : (
                           <>
                              <button onClick={() => approveTransaction(n.transactionId!)} className="flex-1 py-2 bg-emerald-600 text-white text-[8px] font-black uppercase rounded-lg">Approve</button>
                              <button onClick={() => rejectTransaction(n.transactionId!)} className="flex-1 py-2 bg-rose-50 text-rose-500 text-[8px] font-black uppercase rounded-lg">Reject</button>
                           </>
                         )}
                      </div>
                   </div>
                 );
               })}
            </div>
          </div>
        )}

        {showBulkAudit && (
          <Suspense fallback={<div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md"><div className="w-10 h-10 border-4 border-white/20 border-t-white rounded-full animate-spin"></div></div>}>
            <BulkAuditModal onClose={() => setShowBulkAudit(false)} />
          </Suspense>
        )}
      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-xl border-t border-slate-200 px-6 py-2 z-[60] flex justify-between items-center pb-[calc(env(safe-area-inset-bottom)+0.5rem)] shadow-[0_-5px_20px_-5px_rgba(0,0,0,0.05)]">
          {mobileNavItems.map(item => (
            <button 
               key={item.id} 
               onClick={() => setActiveTab(item.id)}
               className={`flex flex-col items-center justify-center w-14 h-14 rounded-2xl transition-all active:scale-95 group ${activeTab === item.id ? 'text-[#03246B]' : 'text-slate-400 hover:text-slate-600'}`}
            >
               <span className={`text-2xl mb-1 transition-transform ${activeTab === item.id ? 'scale-110 -translate-y-1' : ''}`}>{item.icon}</span>
               {activeTab === item.id && <span className="w-1 h-1 rounded-full bg-[#03246B] animate-in zoom-in"></span>}
               {activeTab !== item.id && <span className="text-[9px] font-black uppercase tracking-widest scale-0 group-hover:scale-100 transition-transform absolute -top-8 bg-slate-800 text-white px-2 py-1 rounded opacity-0 group-hover:opacity-100">{item.label}</span>}
            </button>
          ))}
      </nav>

    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type RateDisplayMode = 'hourly' | 'daily' | 'monthly';

interface DashboardProps {
  onNavigate: (tab: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onNavigate }) => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [displayMode, setDisplayMode] = useState<RateDisplayMode>('hourly');
  const [hoursPerDay, setHoursPerDay] = useState(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;

  const familyNotifications = state.notifications.slice(0, 4);
  const isConsolidated = activeMemberIds.includes('all') || activeMemberIds.length > 1;

  // Permission Logic for Nav Cards
  const familyMembers = state.profile?.familyMembers || [];
  const activePermissions = useMemo(() => {
    if (activeMemberIds.length === 0 || activeMemberIds.includes('all')) return null;
    if (activeMemberIds.length === 1) {
      return familyMembers.find(m => m.id === activeMemberIds[0])?.permissions || null;
    }
    return null;
  }, [activeMemberIds, familyMembers]);

  const navItems = [
    { id: 'rankings', label: 'Rankings', icon: '🏆', perm: 'viewDashboard' as const },
    { id: 'accounts', label: 'Accounts', icon: '🏦', perm: 'viewAccounts' as const },
    { id: 'budget', label: 'Budget', icon: '🎯', perm: 'viewBudget' as const },
    { id: 'calendar', label: 'Calendar', icon: '📅', perm: 'viewCalendar' as const },
  ];

  const visibleNavItems = navItems.filter(item => {
    if (!activePermissions || !item.perm) return true;
    return (activePermissions as any)[item.perm];
  });

  // Actual "Live" Derived Calculations (Simple date-based division)
  const dailyIncome = rawRates.income / rawRates.daysPassed;
  const dailyExpense = rawRates.expense / rawRates.daysPassed;
  const dailySavings = dailyIncome - dailyExpense;

  const getDisplayValues = () => {
    switch (displayMode) {
      case 'monthly':
        return {
          income: rawRates.income,
          expense: rawRates.expense,
          savings: rawRates.monthlySurplus,
          cycle: 'mo'
        };
      case 'daily':
        return {
          income: dailyIncome,
          expense: dailyExpense,
          savings: dailySavings,
          cycle: 'day'
        };
      case 'hourly':
      default:
        return {
          income: dailyIncome / hoursPerDay,
          expense: dailyExpense / hoursPerDay,
          savings: dailySavings / hoursPerDay,
          cycle: 'hr'
        };
    }
  };

  const currentDisplay = getDisplayValues();

  // Planned "Budgeted" Derived Calculations (Simplified annual to daily/hourly/monthly)
  const budgetedAnnualIncome = (filteredState.incomes || []).reduce((acc, inc) => acc + (inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity]), 0);
  const budgetedAnnualExpense = (filteredState.budgets || []).reduce((acc, bud) => acc + (bud.amount), 0);

  const getBudgetedDisplayValues = () => {
    const dailyBIncome = budgetedAnnualIncome / 365;
    const dailyBExpense = budgetedAnnualExpense / 365;
    const dailyBSavings = dailyBIncome - dailyBExpense;

    switch (displayMode) {
      case 'monthly':
        return {
          income: budgetedAnnualIncome / 12,
          expense: budgetedAnnualExpense / 12,
          savings: (budgetedAnnualIncome - budgetedAnnualExpense) / 12
        };
      case 'daily':
        return {
          income: dailyBIncome,
          expense: dailyBExpense,
          savings: dailyBSavings
        };
      case 'hourly':
      default:
        return {
          income: dailyBIncome / hoursPerDay,
          expense: dailyBExpense / hoursPerDay,
          savings: dailyBSavings / hoursPerDay
        };
    }
  };

  const budgetedDisplay = getBudgetedDisplayValues();

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#4f46e5' },
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#cbd5e1' },
  ];

  // Greeting Logic
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 17) return "Good afternoon";
    return "Good evening";
  };

  const getGreetingName = () => {
    if (activeMemberIds.includes('all')) {
        // Consolidated View -> Surname
        const userSurname = state.profile.name?.trim().split(' ').pop();
        return userSurname ? `The ${userSurname}s` : 'Family';
    } else if (activeMemberIds.length > 0) {
        // Specific Member -> First Name
        const m = familyMembers.find(mem => mem.id === activeMemberIds[0]);
        return m ? m.name.split(' ')[0] : 'User';
    } else {
        // Self -> First Name
        return state.profile.name?.split(' ')[0] || 'User';
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-full">

      {/* Greeting Header */}
      <div className="mb-2">
         <h1 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight">
           {getGreeting()}, <span className="text-indigo-600">{getGreetingName()}</span>
         </h1>
         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Financial Overview</p>
      </div>

      {/* Rate Metric Controls - Fixed layout for better mobile visibility */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white/50 p-3 rounded-[2rem] border border-slate-200 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-1 p-1 bg-slate-100/50 rounded-2xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button 
            onClick={() => setDisplayMode('hourly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'hourly' ? 'bg-[#03246B] text-[#FEFE1F] shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Hourly
          </button>
          <button 
            onClick={() => setDisplayMode('daily')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'daily' ? 'bg-[#03246B] text-[#FEFE1F] shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Daily
          </button>
          <button 
            onClick={() => setDisplayMode('monthly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'monthly' ? 'bg-[#03246B] text-[#FEFE1F] shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Monthly
          </button>
        </div>

        <div className={`flex items-center gap-3 px-2 w-full sm:w-auto justify-center sm:justify-end transition-opacity duration-300 ${displayMode === 'hourly' ? 'opacity-100' : 'opacity-30 pointer-events-none'}`}>
          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Cycle Base</label>
          <select 
            value={hoursPerDay} 
            onChange={(e) => setHoursPerDay(Number(e.target.value))}
            disabled={displayMode !== 'hourly'}
            className="bg-white border border-slate-200 rounded-xl px-2 py-2 text-[9px] font-black outline-none focus:ring-4 focus:ring-indigo-500/10 disabled:opacity-30 cursor-pointer min-w-[100px]"
          >
            {[4, 6, 8, 10, 12, 16, 20, 24].map(h => (
              <option key={h} value={h}>{h} HR / Day</option>
            ))}
          </select>
        </div>
      </div>

      {/* MOBILE NAVIGATION GRID (Replaces Bottom Bar) */}
      <div className="md:hidden grid grid-cols-2 gap-3">
         {visibleNavItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => onNavigate(item.id)}
              className="bg-white p-4 rounded-[1.5rem] border border-slate-100 shadow-sm flex flex-col items-center justify-center gap-2 active:scale-95 transition-transform hover:bg-slate-50"
            >
               <span className="text-2xl filter drop-shadow-sm">{item.icon}</span>
               <span className="text-[8px] font-black text-[#03246B] uppercase tracking-widest">{item.label}</span>
            </button>
         ))}
      </div>

      {/* Main Stats Grid: Table + Key Cards */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 md:gap-8">

         {/* Comparison Table */}
         <div className="xl:col-span-2 bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col justify-center">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[500px]">
                <thead>
                  <tr className="bg-slate-50/50 border-b border-slate-100">
                    <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Particulars</th>
                    <th className="p-6 text-[10px] font-black text-[#03246B] uppercase tracking-widest">Earnings / {currentDisplay.cycle || 'cycle'}</th>
                    <th className="p-6 text-[10px] font-black text-rose-500 uppercase tracking-widest">Spends / {currentDisplay.cycle || 'cycle'}</th>
                    <th className="p-6 text-[10px] font-black text-emerald-600 uppercase tracking-widest">Savings / {currentDisplay.cycle || 'cycle'}</th>
                  </tr>
                </thead>
                <tbody>
                   {/* Budgeted Row */}
                   <tr className="border-b border-slate-50 hover:bg-slate-50/30 transition-colors">
                      <td className="p-6">
                         <span className="text-xs font-black text-slate-800 uppercase tracking-tight">Budgeted</span>
                      </td>
                      <td className="p-6 text-sm font-black text-slate-500">
                        {formatCurrency(budgetedDisplay.income, currency)}
                      </td>
                      <td className="p-6 text-sm font-black text-slate-500">
                        {formatCurrency(budgetedDisplay.expense, currency)}
                      </td>
                      <td className="p-6 text-sm font-black text-slate-500">
                        {formatCurrency(budgetedDisplay.savings, currency)}
                      </td>
                   </tr>
                   {/* Actuals Row */}
                   <tr className="hover:bg-slate-50/30 transition-colors bg-slate-50/10">
                      <td className="p-6">
                         <span className="text-xs font-black text-slate-800 uppercase tracking-tight">Actuals</span>
                         <span className="ml-2 px-2 py-0.5 bg-[#FEFE1F] text-[#03246B] text-[8px] font-black rounded-full uppercase tracking-widest">Live</span>
                      </td>
                      <td className="p-6 text-xl font-black text-[#03246B]">
                        {formatCurrency(currentDisplay.income, currency)}
                      </td>
                      <td className="p-6 text-xl font-black text-rose-500">
                        {formatCurrency(currentDisplay.expense, currency)}
                      </td>
                      <td className={`p-6 text-xl font-black ${currentDisplay.savings >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                        {formatCurrency(currentDisplay.savings, currency)}
                      </td>
                   </tr>
                </tbody>
              </table>
            </div>
         </div>

         {/* Secondary Stats Cards */}
         <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-1 gap-6">
            <div className="p-6 rounded-[2rem] border border-slate-200 bg-white shadow-sm flex flex-col justify-center h-full min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-slate-800">ASSETS</div>
               <p className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-400">Total Assets</p>
               <h3 className="text-2xl font-black tracking-tight text-slate-800 mt-2">{formatCurrency(netWorthData.assets, currency)}</h3>
               <div className="w-full h-1 bg-slate-100 rounded-full mt-4 overflow-hidden">
                 <div className="h-full bg-indigo-600 w-full"></div>
               </div>
            </div>

            <div className="p-6 rounded-[2rem] border border-[#03246B] bg-[#03246B] shadow-lg flex flex-col justify-center h-full min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 text-6xl opacity-10 font-black text-white">NET</div>
               <p className="text-[9px] font-black uppercase tracking-[0.2em] text-white/60">Net Worth</p>
               <h3 className="text-2xl font-black tracking-tight text-white mt-2">{formatCurrency(netWorthData.netWorth, currency)}</h3>
               <div className="w-full h-1 bg-white/20 rounded-full mt-4 overflow-hidden">
                 <div className="h-full bg-[#FEFE1F] w-full"></div>
               </div>
            </div>
         </div>
      </div>

