                  </div>
                </div>

                <div className="p-6 md:p-8 bg-[#03246B] text-white rounded-[2rem] md:rounded-[2.5rem] shadow-xl relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-4 text-4xl opacity-10 group-hover:scale-110 transition-transform">📈</div>
                  <div className="flex justify-between items-center relative z-10">
                    <div>
                      <span className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest">Monthly Surplus</span>
                      <p className="text-xl md:text-2xl font-black tracking-tight mt-1">{formatCurrency(rawRates.monthlySurplus, currency)}</p>
                    </div>
