        </div>

        <div className="bg-white p-6 md:p-10 rounded-[2.5rem] border border-slate-200 shadow-sm flex flex-col">
          <h4 className="text-[10px] md:text-xs font-black text-slate-800 uppercase tracking-widest mb-6 md:mb-10">Activity Pulse</h4>
          <div className="space-y-6 md:space-y-8 flex-1">
            {familyNotifications.length > 0 ? familyNotifications.map(n => (
              <div key={n.id} className="flex gap-4 md:gap-5 border-b border-slate-50 pb-4 md:pb-6 last:border-0 last:pb-0 group/notif">
                <div className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl flex items-center justify-center flex-shrink-0 text-lg md:text-xl shadow-sm transition-all group-hover/notif:scale-105 ${n.title.includes('Expense') ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>
                   {n.title.includes('Expense') ? '💸' : '💰'}
                </div>
