import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';

const DecisionMaker: React.FC = () => {
  const { filteredState, state } = useFinance();
  const currency = state.profile.currency;

  // Financial Context
  const rates = calculateRates(filteredState);
  const netWorth = calculateNetWorth(filteredState);
  const liquidity = (filteredState.banks || []).reduce((acc, b) => acc + b.balance, 0) + 
                   (filteredState.wallets || []).reduce((acc, w) => acc + w.balance, 0);

  const [query, setQuery] = useState('');
  const [result, setResult] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleAnalyze = async () => {
    if (!query.trim()) return;
    setIsLoading(true);
    setResult(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const prompt = `
        You are a prudent and objective financial advisor assistant called "MyFin Decision Maker".

        Current Financial Context for User:
        - Monthly Income: ${formatCurrency(rates.income, currency)}
        - Monthly Expense: ${formatCurrency(rates.expense, currency)}
        - Monthly Surplus/Deficit: ${formatCurrency(rates.monthlySurplus, currency)}
        - Total Liquid Assets (Cash/Bank): ${formatCurrency(liquidity, currency)}
        - Total Net Worth: ${formatCurrency(netWorth.netWorth, currency)}
        - Currency: ${currency}

        User Question: "${query}"

        Based on the financial context provided, give a recommendation. 
        - If the user proposes a purchase, analyze if they can afford it based on liquidity and surplus.
        - If it's a general question, provide strategic advice.
        - Be concise, professional, and use bullet points for clarity.
        - If the purchase seems risky (e.g., exceeds surplus or depletes significant liquidity), warn the user.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      setResult(response.text || "Unable to generate a recommendation at this time.");
    } catch (error) {
      console.error("AI Decision Error:", error);
      setResult("System Error: Could not reach the financial intelligence engine. Please check your connection or API key.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20 max-w-4xl mx-auto">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Decision Maker</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">AI-Powered Financial Guidance</p>
        </div>
        <div className="bg-indigo-600 px-6 py-3 rounded-2xl text-white shadow-xl shadow-indigo-100/50">
           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Engine Status</p>
           <p className="text-sm font-black uppercase tracking-tight">Online & Ready</p>
        </div>
      </div>

      {/* Context Summary Card */}
      <div className="bg-white p-6 md:p-8 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 text-8xl opacity-5 font-black grayscale select-none">⚖️</div>

        <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 relative z-10">Active Context Snapshot</h3>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 relative z-10">
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Monthly Surplus</p>
            <p className={`text-lg font-black ${rates.monthlySurplus >= 0 ? 'text-emerald-600' : 'text-rose-500'}`}>
              {formatCurrency(rates.monthlySurplus, currency)}
            </p>
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Liquid Cash</p>
            <p className="text-lg font-black text-indigo-600">{formatCurrency(liquidity, currency)}</p>
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Net Worth</p>
            <p className="text-lg font-black text-slate-800">{formatCurrency(netWorth.netWorth, currency)}</p>
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Runway Status</p>
            <p className="text-lg font-black text-slate-800">
               {rates.expense > 0 ? (liquidity / rates.expense).toFixed(1) + ' Months' : '∞'}
            </p>
          </div>
        </div>
      </div>

      {/* Input Section */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-xl overflow-hidden flex flex-col md:flex-row">
        <div className="p-8 md:p-12 flex-1 space-y-6">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">What financial choice are you weighing?</label>
              <textarea 
                className="w-full h-32 p-6 bg-slate-50 border border-slate-200 rounded-3xl outline-none font-black text-sm text-slate-800 resize-none focus:ring-4 focus:ring-indigo-500/10 transition-all placeholder:text-slate-300"
                placeholder="e.g., Should I buy a new car for $25,000 given my current savings? Or, how can I increase my monthly surplus?"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
              />
           </div>

           <button 
             onClick={handleAnalyze}
             disabled={isLoading || !query.trim()}
             className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-xl hover:bg-black transition-all active:scale-95 disabled:opacity-50 disabled:active:scale-100 flex items-center justify-center gap-3"
           >
             {isLoading ? (
               <>
                 <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                 <span>Analyzing Scenario...</span>
               </>
             ) : (
               <>
                 <span>⚡</span>
                 <span>Analyze Impact</span>
               </>
             )}
           </button>
        </div>

        {/* Result Panel */}
        <div className="bg-slate-50 border-t md:border-t-0 md:border-l border-slate-200 p-8 md:p-12 md:w-[45%] flex flex-col justify-center">
           {result ? (
             <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4">
                <div className="flex items-center gap-2 mb-2">
                   <div className="w-8 h-8 bg-indigo-600 text-white rounded-lg flex items-center justify-center text-sm shadow-md">⚖️</div>
                   <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Recommendation</span>
                </div>
                <div className="prose prose-sm prose-slate font-medium text-slate-600 text-xs leading-relaxed">
                   <div dangerouslySetInnerHTML={{ __html: result.replace(/\n/g, '<br/>').replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>') }} />
                </div>
             </div>
           ) : (
             <div className="text-center opacity-40">
                <div className="text-6xl mb-4 grayscale">🧠</div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Waiting for input...</p>
                <p className="text-[9px] font-bold text-slate-300 mt-2 max-w-[200px] mx-auto">Enter a scenario to receive personalized financial advice based on your vault data.</p>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

