import React, { useState, Suspense, lazy } from 'react';
import { FinanceProvider, useFinance } from './store/FinanceContext';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';

// Lazy load secondary components to optimize initial bundle size
// Dashboard is eager loaded to ensure instant transition after login
const Accounts = lazy(() => import('./components/Accounts'));
const Statements = lazy(() => import('./components/Statements'));
const Profile = lazy(() => import('./components/Profile'));
const Onboarding = lazy(() => import('./components/Onboarding'));
const Transactions = lazy(() => import('./components/Transactions'));
const Rewards = lazy(() => import('./components/Rewards'));
const BudgetPlanner = lazy(() => import('./components/BudgetPlanner'));
const FiscalSentinel = lazy(() => import('./components/FiscalSentinel'));
const Ranking = lazy(() => import('./components/Ranking'));
const DecisionMaker = lazy(() => import('./components/DecisionMaker'));

const LoadingFallback = () => (
  <div className="flex items-center justify-center h-full min-h-[50vh]">
    <div className="flex flex-col items-center gap-3">
      <div className="w-8 h-8 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Loading Resource...</p>
    </div>
  </div>
);

const MainApp: React.FC = () => {
  const { state, isAuthenticated } = useFinance();
  const [activeTab, setActiveTab] = useState('dashboard');

  if (!isAuthenticated || !state.profile.isBoarded) {
    return (
      <Suspense fallback={<div className="h-screen w-full flex items-center justify-center bg-slate-50"><LoadingFallback /></div>}>
        <Onboarding />
      </Suspense>
    );
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      <Suspense fallback={<LoadingFallback />}>
        {activeTab === 'dashboard' && <Dashboard onNavigate={setActiveTab} />}
        {activeTab === 'rankings' && <Ranking />}
        {activeTab === 'transactions' && <Transactions />}
        {activeTab === 'accounts' && <Accounts />}
        {activeTab === 'statements' && <Statements />}
        {activeTab === 'profile' && <Profile />}
        {activeTab === 'rewards' && <Rewards />}
        {activeTab === 'budget' && <BudgetPlanner />}
        {activeTab === 'calendar' && <FiscalSentinel />}
        {activeTab === 'decision' && <DecisionMaker />}
      </Suspense>
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <FinanceProvider>
      <MainApp />
    </FinanceProvider>
  );
};

export default App;

