             <div className="text-center opacity-40">
                <div className="text-6xl mb-4 grayscale">🧠</div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Waiting for input...</p>
                <p className="text-[9px] font-bold text-slate-300 mt-2 max-w-[200px] mx-auto">Enter a scenario to receive personalized financial advice based on your vault data.</p>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

