    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: '',
    dueDate: '',
    dateOfReceipt: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  const getWindowMultiplier = (view: ViewWindow, freq: Periodicity) => {
    if (view === 'Financial Year') return ANNUAL_MULTIPLIERS[freq];
    const map: Record<Exclude<ViewWindow, 'Financial Year'>, Record<Periodicity, number>> = {
      'This Month': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'Last Month': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'This Quarter': { 'Daily': 91, 'Weekly': 13, 'Fortnightly': 6, 'Monthly': 3, 'Quarterly': 1, 'Half-Yearly': 0.5, 'Annually': 0.25 },
      'Custom': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 }
    };
    return map[view as Exclude<ViewWindow, 'Financial Year'>][freq] || 1;
  };

  useEffect(() => {
    const total = (formData.amountPerPeriod || 0) * ANNUAL_MULTIPLIERS[formData.frequency as Periodicity];
    if (activeTab === 'expense' && Math.abs((formData.amount || 0) - total) > 0.01) {
      setFormData(prev => ({ ...prev, amount: total }));
    } else if (activeTab === 'income') {
       // For income, amount IS the per-period amount usually, but let's keep consistent
       setFormData(prev => ({ ...prev, amount: formData.amountPerPeriod }));
    }
  }, [formData.amountPerPeriod, formData.frequency, activeTab]);

  const currentAnalysisWindow = useMemo(() => {
    const now = new Date();
    let start = new Date();
    let end = new Date();
    if (viewWindowType === 'This Month') {
      start = new Date(now.getFullYear(), now.getMonth(), 1);
      end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (viewWindowType === 'Last Month') {
      start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      end = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
    } else if (viewWindowType === 'This Quarter') {
      const q = Math.floor(now.getMonth() / 3);
      start = new Date(now.getFullYear(), q * 3, 1);
      end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
    } else if (viewWindowType === 'Financial Year') {
      const startYear = now.getMonth() < 3 ? now.getFullYear() - 1 : now.getFullYear();
      start = new Date(startYear, 3, 1);
      end = new Date(startYear + 1, 2, 31, 23, 59, 59);
    } else if (viewWindowType === 'Custom') {
      start = new Date(customViewStart);
      end = new Date(customViewEnd);
      end.setHours(23, 59, 59, 999);
    }
    return { start, end };
  }, [viewWindowType, customViewStart, customViewEnd]);

  const budgetsWithAnalytics = useMemo(() => {
    const now = new Date();
    const { start: windowStart, end: windowEnd } = currentAnalysisWindow;
    return (filteredState.budgets || []).map(b => {
      const bStart = new Date(b.startDate);
      const bEnd = new Date(b.endDate);
      const effectiveStart = new Date(Math.max(bStart.getTime(), windowStart.getTime()));
      const effectiveEnd = new Date(Math.min(bEnd.getTime(), windowEnd.getTime()));
      const hasOverlap = effectiveStart <= effectiveEnd;
      const windowActual = hasOverlap 
        ? (filteredState.transactions || [])
          .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= effectiveStart && new Date(t.date) <= effectiveEnd)
          .reduce((sum, t) => sum + t.amount, 0)
        : 0;
      const multiplier = getWindowMultiplier(viewWindowType, b.frequency);
      const amountPerFreq = b.amount / ANNUAL_MULTIPLIERS[b.frequency];
      const dynamicTarget = amountPerFreq * multiplier;
      const isInactive = now < bStart || now > bEnd;
      const windowDueDate = getBudgetDueDateForWindow(b.dueDate, windowStart);
      return { ...b, windowActual, dynamicTarget, amountPerFreq, isInactive, hasOverlap, windowDueDate };
    });
  }, [filteredState.budgets, filteredState.transactions, currentAnalysisWindow, viewWindowType]);

  const handleOpenModal = (item?: any) => {
    if (item) {
      setEditingId(item.id);
      if (activeTab === 'expense') {
        const b = item as Budget;
        setFormData({
            category: b.category,
            amount: b.amount,
            amountPerPeriod: b.amount / ANNUAL_MULTIPLIERS[b.frequency],
            frequency: b.frequency,
            periodType: b.periodType,
            startDate: b.startDate,
            endDate: b.endDate,
            dueDate: b.dueDate || '',
            dateOfReceipt: ''
        });
      } else {
        const i = item as IncomeStream;
        setFormData({
            category: i.name,
            amount: i.amount,
            amountPerPeriod: i.amount, // For income, base amount is per period
            frequency: i.periodicity,
            periodType: 'Financial',
            startDate: '',
            endDate: '',
            dueDate: '',
            dateOfReceipt: i.dateOfReceipt
        });
      }
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({ 
          category: '', 
          amount: 0, 
          amountPerPeriod: 0, 
          frequency: 'Monthly', 
          periodType: 'Financial', 
          startDate: dates.start, 
          endDate: dates.end, 
          dueDate: '',
          dateOfReceipt: ''
      });
    }
    setShowModal(true);
  };

  const handleLoadTemplate = () => {
    const dates = getPeriodDates('Financial');

    // Load Incomes
    DEFAULT_INCOMES.forEach(inc => {
       // Check for duplicates
       if (!filteredState.incomes.some(i => i.name === inc.name)) {
          addIncome({
             id: Math.random().toString(36).substr(2, 9),
             name: inc.name || 'Income',
             amount: 0, // User to fill
             periodicity: inc.periodicity || 'Monthly',
             dateOfReceipt: '',
             ownerId: ''
          });
       }
    });

    // Load Expenses
    DEFAULT_EXPENSES.forEach(exp => {
       if (!filteredState.budgets.some(b => b.category === exp.category)) {
          addBudget({
             id: Math.random().toString(36).substr(2, 9),
             category: exp.category || 'Expense',
             amount: 0, // User to fill
             frequency: exp.frequency || 'Monthly',
             startDate: dates.start,
             endDate: dates.end,
             periodType: 'Financial',
             ownerId: ''
          });
       }
    });

    alert("Template loaded! Default categories added to both Incomes and Expenses.");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeTab === 'expense') {
        const dates = getPeriodDates(formData.periodType as any);
        const budgetData: Budget = {
          id: editingId || Math.random().toString(36).substr(2, 9),
          category: formData.category || 'General',
          amount: Number(formData.amount),
          frequency: formData.frequency as Periodicity,
          startDate: dates.start,
          endDate: dates.end,
          dueDate: formData.dueDate,
          periodType: formData.periodType as any,
          ownerId: ''
        };
        if (editingId) updateBudget(budgetData);
        else addBudget(budgetData);
    } else {
        const incomeData: IncomeStream = {
            id: editingId || Math.random().toString(36).substr(2, 9),
            name: formData.category || 'Income',
            amount: Number(formData.amountPerPeriod),
            periodicity: formData.frequency,
            dateOfReceipt: formData.dateOfReceipt,
            ownerId: ''
        };
        if (editingId) updateIncome(incomeData);
        else addIncome(incomeData);
    }
    setShowModal(false);
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">

      {/* Dynamic Header & Options Bar */}
      {!isFocusMode && (
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0 animate-in slide-in-from-top-4 duration-300">
          <div>
            <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Budget Architect</h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
          </div>
          <div className="flex flex-wrap items-center gap-3">
             <button onClick={() => setIsFocusMode(true)} className="px-5 py-3.5 bg-slate-900 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl shadow-slate-200 transition-transform active:scale-95">Focus Mode</button>
             <button onClick={handleLoadTemplate} className="px-5 py-3.5 bg-white border border-slate-200 text-slate-600 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-slate-50 active:scale-95">Load Template</button>
             <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 active:scale-95 transition-all">+ Add {activeTab === 'expense' ? 'Target' : 'Stream'}</button>
          </div>
        </div>
      )}

      {/* Focus Mode Control Bar */}
      {isFocusMode && (
        <div className="sticky top-4 z-50 flex items-center justify-between bg-slate-900 text-white p-3 rounded-2xl shadow-2xl mx-4 md:mx-0 animate-in slide-in-from-top-4">
           <div className="flex items-center gap-4 px-3">
              <span className="text-sm">🧘</span>
              <p className="text-[10px] font-black uppercase tracking-[0.2em]">Focused Analysis</p>
           </div>
           <div className="flex items-center gap-2">
              <button onClick={() => handleOpenModal()} className="px-4 py-2 bg-indigo-600 text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95">+ Add</button>
              <button onClick={() => setIsFocusMode(false)} className="px-4 py-2 bg-white/10 hover:bg-white/20 text-[9px] font-black uppercase tracking-widest rounded-xl transition-colors">Exit Focus</button>
           </div>
        </div>
      )}

      {/* Tabs and Period Options */}
      {!isFocusMode && (
        <div className="flex flex-col gap-4 animate-in fade-in duration-500">
            {/* Main Tabs */}
            <div className="flex bg-slate-100 p-1 rounded-[1.5rem] self-start">
               <button onClick={() => setActiveTab('expense')} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'expense' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>Expense Targets</button>
               <button onClick={() => setActiveTab('income')} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'income' ? 'bg-white shadow-sm text-emerald-600' : 'text-slate-400 hover:text-slate-600'}`}>Income Streams</button>
            </div>

            {/* Period Filter (Only relevant for Expenses usually, but available for generic window) */}
            <div className="bg-white p-2 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex flex-wrap items-center gap-1 p-1 bg-slate-50/50 rounded-2xl">
                {(['This Month', 'Last Month', 'This Quarter', 'Financial Year', 'Custom'] as ViewWindow[]).map(type => (
                    <button 
                    key={type} 
                    onClick={() => setViewWindowType(type)}
                    className={`px-4 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${viewWindowType === type ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
                    >
                    {type}
                    </button>
                ))}
                </div>
                {viewWindowType === 'Custom' ? (
                <div className="flex items-center gap-3 px-4 animate-in slide-in-from-right-4">
                    <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none focus:ring-4 focus:ring-indigo-500/10" value={customViewStart} onChange={e => setCustomViewStart(e.target.value)} />
                    <input type="date" className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-[10px] font-black outline-none focus:ring-4 focus:ring-indigo-500/10" value={customViewEnd} onChange={e => setCustomViewEnd(e.target.value)} />
                </div>
                ) : (
                <div className="px-6 text-[10px] font-black text-indigo-600 uppercase hidden md:block">
                    Audit Range: {currentAnalysisWindow.start.toLocaleDateString()} — {currentAnalysisWindow.end.toLocaleDateString()}
                </div>
                )}
            </div>
        </div>
      )}

      {/* Main Table Area */}
      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col min-h-[400px]">
        <div className="overflow-x-auto custom-scrollbar relative flex-1">
          <table className="w-full text-left border-separate border-spacing-0 min-w-[1200px]">
            <thead className="bg-slate-50/80 backdrop-blur-md text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] sticky top-0 z-30">
              <tr>
                <th className="px-8 py-6 sticky left-0 z-40 bg-slate-50 border-b border-slate-100 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)]">{activeTab === 'expense' ? 'Expense Category' : 'Source Name'}</th>
                <th className="px-8 py-6 border-b border-slate-100">Recurrence</th>
                <th className="px-8 py-6 text-right border-b border-slate-100">{activeTab === 'expense' ? 'Target (For Period)' : 'Expected Amount'}</th>
                {activeTab === 'expense' && <th className="px-8 py-6 text-right border-b border-slate-100">Actual (In Window)</th>}
                {activeTab === 'expense' && <th className="px-8 py-6 text-center border-b border-slate-100">Efficiency Health</th>}
                <th className="px-8 py-6 text-right border-b border-slate-100">Projected Annual</th>
                <th className="px-8 py-6 text-center border-b border-slate-100">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {activeTab === 'expense' ? budgetsWithAnalytics.map(b => {
                const efficiency = b.dynamicTarget > 0 ? Math.min(100, (b.windowActual / b.dynamicTarget) * 100) : (b.windowActual > 0 ? 100 : 0);
                const isOver = b.windowActual > b.dynamicTarget;
                const isWarning = efficiency > 80;

                return (
                  <tr key={b.id} className={`hover:bg-slate-50/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    <td className="px-8 py-6 sticky left-0 z-20 bg-white group-hover:bg-[#f8fafc] border-b border-slate-50 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
                      <div className="flex justify-between items-start gap-3">
                        <div>
                          <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{b.category}</p>
                          <p className="text-[8px] font-black text-slate-300 uppercase mt-1 tracking-widest whitespace-nowrap">{b.startDate} to {b.endDate}</p>
                        </div>
                        {b.windowDueDate && (
                          <div className="flex flex-col items-center justify-center min-w-[32px] bg-rose-50 text-rose-500 p-1.5 rounded-xl border border-rose-100 shadow-sm animate-in zoom-in-90">
                             <span className="text-[8px] font-black uppercase leading-none mb-0.5">Due</span>
                             <span className="text-[10px] font-black leading-none">{b.windowDueDate.getDate()} {b.windowDueDate.toLocaleString('default', { month: 'short' })}</span>
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase tracking-widest inline-block">{b.frequency}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-indigo-600">
                      {formatCurrency(b.dynamicTarget, currency)}
                    </td>
                    <td className={`px-8 py-6 text-right font-black text-xs ${isOver ? 'text-rose-500' : 'text-slate-800'}`}>
                      {formatCurrency(b.windowActual, currency)}
                    </td>
                    <td className="px-8 py-6 text-center min-w-[140px]">
                       {!b.hasOverlap ? <span className="text-[8px] font-black text-slate-300 uppercase italic">Out of Range</span> : (
                         <div className="flex flex-col items-center">
                           <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden max-w-[100px] mb-1">
                              <div className={`h-full transition-all duration-700 ${isOver ? 'bg-rose-500' : isWarning ? 'bg-amber-400' : 'bg-emerald-500'}`} style={{ width: `${efficiency}%` }}></div>
                           </div>
                           <span className={`text-[8px] font-black uppercase tracking-widest ${isOver ? 'text-rose-400' : 'text-slate-400'}`}>{efficiency.toFixed(0)}% Utilized</span>
                         </div>
                       )}
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(b.amount, currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5 whitespace-nowrap">Annual Cap</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2.5 bg-white text-indigo-400 hover:text-indigo-600 rounded-lg shadow-sm border border-slate-100 transition-colors">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2.5 bg-white text-rose-300 hover:text-rose-500 rounded-lg shadow-sm border border-slate-100 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              }) : filteredState.incomes.map(inc => (
                 <tr key={inc.id} className="hover:bg-slate-50/30 transition-colors group">
                    <td className="px-8 py-6 sticky left-0 z-20 bg-white group-hover:bg-[#f8fafc] border-b border-slate-50 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{inc.name}</p>
                    </td>
                    <td className="px-8 py-6">
                       <span className="text-[9px] font-black bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full uppercase tracking-widest inline-block">{inc.periodicity}</span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-xs text-emerald-600">
                      {formatCurrency(inc.amount, currency)}
                    </td>
                    <td className="px-8 py-6 text-right">
                       <p className="text-[10px] font-black text-slate-800">{formatCurrency(inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity], currency)}</p>
                       <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mt-0.5 whitespace-nowrap">Annual Proj.</p>
                    </td>
                    <td className="px-8 py-6 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(inc)} className="p-2.5 bg-white text-indigo-400 hover:text-indigo-600 rounded-lg shadow-sm border border-slate-100 transition-colors">✎</button>
                          <button onClick={() => deleteIncome(inc.id)} className="p-2.5 bg-white text-rose-300 hover:text-rose-500 rounded-lg shadow-sm border border-slate-100 transition-colors">✕</button>
                       </div>
                    </td>
                 </tr>
              ))}
              {((activeTab === 'expense' && budgetsWithAnalytics.length === 0) || (activeTab === 'income' && filteredState.incomes.length === 0)) && (
                 <tr>
                    <td colSpan={7} className="py-24 text-center text-slate-300 italic text-[10px] uppercase tracking-widest">
                       No {activeTab} records found. Use "Load Template" to start.
                    </td>
                 </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto custom-scrollbar">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-10">
               {activeTab === 'expense' ? 'Target Protocol' : 'Income Stream Definition'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">{activeTab === 'expense' ? 'Category Head' : 'Source Name'}</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase focus:ring-4 focus:ring-indigo-500/10" placeholder={activeTab === 'expense' ? 'E.G. GROCERIES' : 'E.G. SALARY'} value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-6">
                 {activeTab === 'expense' && (
                    <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={formData.periodType} onChange={e => {
                        const dates = getPeriodDates(e.target.value as any);
                        setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                        }}><option value="Financial">Financial Year</option><option value="Calendar">Calendar Year</option><option value="Custom">Custom Range</option></select>
                    </div>
                 )}
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">{activeTab === 'expense' ? 'Monthly Payment Day (Ref)' : 'Expected Receipt Date'}</label>
                <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10" value={activeTab === 'expense' ? formData.dueDate : formData.dateOfReceipt} onChange={e => setFormData(activeTab === 'expense' ? {...formData, dueDate: e.target.value} : {...formData, dateOfReceipt: e.target.value})} />
              </div>

              <div className={`space-y-4 p-8 rounded-[2rem] border ${activeTab === 'expense' ? 'bg-indigo-50/30 border-indigo-100' : 'bg-emerald-50/30 border-emerald-100'}`}>
                <div className="space-y-2">
                  <label className={`text-[9px] font-black uppercase tracking-widest block ml-2 ${activeTab === 'expense' ? 'text-indigo-400' : 'text-emerald-500'}`}>Amount per {formData.frequency}</label>
                  <input required type="number" step="any" className={`w-full p-4 bg-white border rounded-2xl outline-none font-black text-2xl focus:ring-4 focus:ring-indigo-500/10 transition-all ${activeTab === 'expense' ? 'border-indigo-200 text-indigo-600' : 'border-emerald-200 text-emerald-600'}`} value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>
                {activeTab === 'expense' && (
                    <div className="flex justify-between items-center text-right pt-2 border-t border-indigo-100">
                    <div className="text-left">
                        <p className="text-[8px] font-black text-slate-400 uppercase">Multiplier</p>
                        <p className="text-[10px] font-black text-slate-600 uppercase mt-0.5">x{ANNUAL_MULTIPLIERS[formData.frequency as Periodicity]} (Annual)</p>
                    </div>
                    <div>
                        <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Calculated Annual Goal</p>
                        <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                    </div>
                    </div>
                )}
