                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Budget Span</label>
                        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={formData.periodType} onChange={e => {
                        const dates = getPeriodDates(e.target.value as any);
                        setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
