                    </div>
                 )}
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Frequency</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-black text-xs outline-none cursor-pointer" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">{activeTab === 'expense' ? 'Monthly Payment Day (Ref)' : 'Expected Receipt Date'}</label>
                <input type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10" value={activeTab === 'expense' ? formData.dueDate : formData.dateOfReceipt} onChange={e => setFormData(activeTab === 'expense' ? {...formData, dueDate: e.target.value} : {...formData, dateOfReceipt: e.target.value})} />
              </div>

              <div className={`space-y-4 p-8 rounded-[2rem] border ${activeTab === 'expense' ? 'bg-indigo-50/30 border-indigo-100' : 'bg-emerald-50/30 border-emerald-100'}`}>
                <div className="space-y-2">
                  <label className={`text-[9px] font-black uppercase tracking-widest block ml-2 ${activeTab === 'expense' ? 'text-indigo-400' : 'text-emerald-500'}`}>Amount per {formData.frequency}</label>
                  <input required type="number" step="any" className={`w-full p-4 bg-white border rounded-2xl outline-none font-black text-2xl focus:ring-4 focus:ring-indigo-500/10 transition-all ${activeTab === 'expense' ? 'border-indigo-200 text-indigo-600' : 'border-emerald-200 text-emerald-600'}`} value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>
                {activeTab === 'expense' && (
                    <div className="flex justify-between items-center text-right pt-2 border-t border-indigo-100">
                    <div className="text-left">
                        <p className="text-[8px] font-black text-slate-400 uppercase">Multiplier</p>
                        <p className="text-[10px] font-black text-slate-600 uppercase mt-0.5">x{ANNUAL_MULTIPLIERS[formData.frequency as Periodicity]} (Annual)</p>
                    </div>
                    <div>
                        <p className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">Calculated Annual Goal</p>
                        <p className="text-2xl font-black text-indigo-600">{formatCurrency(formData.amount || 0, currency)}</p>
                    </div>
                    </div>
                )}
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl hover:bg-slate-200 transition-colors">Abort</button>
                <button type="submit" className={`flex-[2] py-5 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl hover:opacity-90 transition-all active:scale-95 ${activeTab === 'expense' ? 'bg-indigo-600 shadow-indigo-100' : 'bg-emerald-600 shadow-emerald-100'}`}>Establish {activeTab === 'expense' ? 'Goal' : 'Stream'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

