          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12">
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">City</label>
              <input required placeholder="Current City" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
            </div>
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Currency Base</label>
              <select className="w-full bg-transparent outline-none font-black text-xl text-slate-900 cursor-pointer" value={formData.country} onChange={e => {
                const country = countries.find(c => c.name === e.target.value);
                setFormData({...formData, country: e.target.value, currency: country?.currency || 'USD'});
              }}>
                {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3 border-b-2 border-slate-100 pb-4 focus-within:border-indigo-600 transition-all">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Initial Liquidity (Cash)</label>
            <div className="flex items-center">
              <span className="text-indigo-600 font-black text-2xl mr-2">{formData.currency}</span>
              <input type="number" step="any" placeholder="0.00" className="w-full bg-transparent outline-none font-black text-4xl text-slate-900" value={formData.openingCash} onChange={e => setFormData({...formData, openingCash: e.target.value})} />
            </div>
          </div>

          <button type="submit" className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-3xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">Initialise Profile</button>
        </form>
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type RateDisplayMode = 'hourly' | 'daily' | 'monthly';

interface DashboardProps {
  onNavigate: (tab: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onNavigate }) => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [displayMode, setDisplayMode] = useState<RateDisplayMode>('hourly');
  const [hoursPerDay, setHoursPerDay] = useState(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;

  const familyNotifications = state.notifications.slice(0, 4);
  const isConsolidated = activeMemberIds.includes('all') || activeMemberIds.length > 1;

  // Permission Logic for Nav Cards
  const familyMembers = state.profile?.familyMembers || [];
  const activePermissions = useMemo(() => {
    if (activeMemberIds.length === 0 || activeMemberIds.includes('all')) return null;
    if (activeMemberIds.length === 1) {
      return familyMembers.find(m => m.id === activeMemberIds[0])?.permissions || null;
    }
    return null;
  }, [activeMemberIds, familyMembers]);

  const navItems = [
    { id: 'accounts', label: 'Accounts', icon: '🏦', perm: 'viewAccounts' as const },
    { id: 'budget', label: 'Budget', icon: '🎯', perm: 'viewBudget' as const },
    { id: 'calendar', label: 'Calendar', icon: '📅', perm: 'viewCalendar' as const },
    { id: 'decision', label: 'Decision Maker', icon: '⚖️', perm: 'viewDashboard' as const },
  ];

  const visibleNavItems = navItems.filter(item => {
    if (!activePermissions || !item.perm) return true;
    return (activePermissions as any)[item.perm];
  });

  // Actual "Live" Derived Calculations (Simple date-based division)
  const dailyIncome = rawRates.income / rawRates.daysPassed;
  const dailyExpense = rawRates.expense / rawRates.daysPassed;
  const dailySavings = dailyIncome - dailyExpense;

  const getDisplayValues = () => {
    switch (displayMode) {
      case 'monthly':
        return {
          income: rawRates.income,
          expense: rawRates.expense,
          savings: rawRates.monthlySurplus,
          cycle: 'mo'
        };
      case 'daily':
        return {
          income: dailyIncome,
          expense: dailyExpense,
          savings: dailySavings,
          cycle: 'day'
        };
      case 'hourly':
      default:
        return {
          income: dailyIncome / hoursPerDay,
          expense: dailyExpense / hoursPerDay,
          savings: dailySavings / hoursPerDay,
          cycle: 'hr'
        };
    }
  };

  const currentDisplay = getDisplayValues();

  // Planned "Budgeted" Derived Calculations (Simplified annual to daily/hourly/monthly)
  const budgetedAnnualIncome = (filteredState.incomes || []).reduce((acc, inc) => acc + (inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity]), 0);
  const budgetedAnnualExpense = (filteredState.budgets || []).reduce((acc, bud) => acc + (bud.amount), 0);

  const getBudgetedDisplayValues = () => {
    const dailyBIncome = budgetedAnnualIncome / 365;
    const dailyBExpense = budgetedAnnualExpense / 365;
    const dailyBSavings = dailyBIncome - dailyBExpense;

    switch (displayMode) {
      case 'monthly':
        return {
          income: budgetedAnnualIncome / 12,
          expense: budgetedAnnualExpense / 12,
          savings: (budgetedAnnualIncome - budgetedAnnualExpense) / 12
        };
      case 'daily':
        return {
          income: dailyBIncome,
          expense: dailyBExpense,
          savings: dailyBSavings
        };
      case 'hourly':
      default:
        return {
          income: dailyBIncome / hoursPerDay,
          expense: dailyBExpense / hoursPerDay,
          savings: dailyBSavings / hoursPerDay,
          cycle: 'hr'
        };
    }
  };

  const budgetedDisplay = getBudgetedDisplayValues();

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#4f46e5' },
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#cbd5e1' },
  ];

  // Greeting Logic
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 17) return "Good afternoon";
    return "Good evening";
  };

  const getGreetingName = () => {
    if (activeMemberIds.includes('all')) {
        // Consolidated View -> Surname
        const userSurname = state.profile.name?.trim().split(' ').pop();
        return userSurname ? `The ${userSurname}s` : 'Family';
    } else if (activeMemberIds.length > 0) {
        // Specific Member -> First Name
        const m = familyMembers.find(mem => mem.id === activeMemberIds[0]);
        return m ? m.name.split(' ')[0] : 'User';
    } else {
        // Self -> First Name
        return state.profile.name?.split(' ')[0] || 'User';
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-full">

      {/* Greeting Header */}
      <div className="mb-2">
         <h1 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight">
           {getGreeting()}, <span className="text-indigo-600">{getGreetingName()}</span>
         </h1>
         <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Financial Overview</p>
      </div>

      {/* MOBILE NAVIGATION GRID (Replaces Bottom Bar) */}
      <div className="md:hidden grid grid-cols-2 gap-3">
         {visibleNavItems.map(item => (
            <button 
              key={item.id} 
              onClick={() => onNavigate(item.id)}
              className="bg-white p-4 rounded-[1.5rem] border border-slate-100 shadow-sm flex flex-col items-center justify-center gap-2 active:scale-95 transition-transform hover:bg-slate-50"
            >
               <span className="text-2xl filter drop-shadow-sm">{item.icon}</span>
               <span className="text-[8px] font-black text-[#03246B] uppercase tracking-widest">{item.label}</span>
            </button>
         ))}
      </div>

      {/* Rate Metric Controls - Fixed layout for better mobile visibility */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white/50 p-3 rounded-[2rem] border border-slate-200 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-1 p-1 bg-slate-100/50 rounded-2xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button 
            onClick={() => setDisplayMode('hourly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'hourly' ? 'bg-[#03246B] text-[#FEFE1F] shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Hourly
          </button>
          <button 
            onClick={() => setDisplayMode('daily')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'daily' ? 'bg-[#03246B] text-[#FEFE1F] shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Daily
          </button>
          <button 
            onClick={() => setDisplayMode('monthly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'monthly' ? 'bg-[#03246B] text-[#FEFE1F] shadow-lg' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Monthly
          </button>
        </div>

        <div className={`flex items-center gap-3 px-2 w-full sm:w-auto justify-center sm:justify-end transition-opacity duration-300 ${displayMode === 'hourly' ? 'opacity-100' : 'opacity-30 pointer-events-none'}`}>
          <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Cycle Base</label>
          <select 
            value={hoursPerDay} 
            onChange={(e) => setHoursPerDay(Number(e.target.value))}
            disabled={displayMode !== 'hourly'}
            className="bg-white border border-slate-200 rounded-xl px-2 py-2 text-[9px] font-black outline-none focus:ring-4 focus:ring-indigo-500/10 disabled:opacity-30 cursor-pointer min-w-[100px]"
          >
            {[4, 6, 8, 10, 12, 16, 20, 24].map(h => (
              <option key={h} value={h}>{h} HR / Day</option>
            ))}
          </select>
        </div>
      </div>

      {/* Main Stats Grid: Table + Key Cards */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 md:gap-8">

         {/* Comparison Table */}
         <div className="xl:col-span-2 bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col justify-center">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[500px]">
                <thead>
                  <tr className="bg-slate-50/50 border-b border-slate-100">
                    <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Particulars</th>
                    <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-[#03246B]">Earnings / {currentDisplay.cycle || 'cycle'}</th>
                    <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-rose-500">Spends / {currentDisplay.cycle || 'cycle'}</th>
                    <th className="p-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-emerald-600">Savings / {currentDisplay.cycle || 'cycle'}</th>
                  </tr>
                </thead>
                <tbody>
                   {/* Budgeted Row */}
                   <tr className="border-b border-slate-50 hover:bg-slate-50/30 transition-colors">
                      <td className="p-6">
                         <span className="text-xs font-black text-slate-500 uppercase tracking-tight">Budgeted</span>
                      </td>
                      <td className="p-6 text-sm font-black text-slate-500">
                        {formatCurrency(budgetedDisplay.income, currency)}
                      </td>
                      <td className="p-6 text-sm font-black text-slate-500">
                        {formatCurrency(budgetedDisplay.expense, currency)}
                      </td>
                      <td className="p-6 text-sm font-black text-slate-500">
                        {formatCurrency(budgetedDisplay.savings, currency)}
                      </td>
                   </tr>
                   {/* Actuals Row */}
                   <tr className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-6">
                         <span className="text-xs font-black text-[#03246B] uppercase tracking-tight">Actuals</span>
                      </td>
                      <td className="p-6 text-xl font-black text-[#03246B]">
                        {formatCurrency(currentDisplay.income, currency)}
                      </td>
                      <td className="p-6 text-xl font-black text-rose-500">
                        {formatCurrency(currentDisplay.expense, currency)}
                      </td>
                      <td className={`p-6 text-xl font-black ${currentDisplay.savings >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                        {formatCurrency(currentDisplay.savings, currency)}
                      </td>
                   </tr>
                </tbody>
              </table>
            </div>
         </div>

         {/* Secondary Stats Cards */}
         <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-1 gap-6">
            <div className="p-6 rounded-[2rem] border border-slate-200 bg-white shadow-sm flex flex-col justify-center h-full min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-slate-800">ASSETS</div>
               <p className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-400">Total Assets</p>
               <h3 className="text-2xl font-black tracking-tight text-slate-800 mt-2">{formatCurrency(netWorthData.assets, currency)}</h3>
               <div className="w-full h-1 bg-slate-100 rounded-full mt-4 overflow-hidden">
                 <div className="h-full bg-indigo-600 w-full"></div>
               </div>
            </div>

            <div className="p-6 rounded-[2rem] border border-[#03246B] bg-[#03246B] shadow-lg flex flex-col justify-center h-full min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 text-6xl opacity-10 font-black text-white">NET</div>
               <p className="text-[9px] font-black uppercase tracking-[0.2em] text-white/60">Net Worth</p>
               <h3 className="text-2xl font-black tracking-tight text-white mt-2">{formatCurrency(netWorthData.netWorth, currency)}</h3>
               <div className="w-full h-1 bg-white/20 rounded-full mt-4 overflow-hidden">
                 <div className="h-full bg-[#FEFE1F] w-full"></div>
               </div>
            </div>
         </div>
      </div>

      {/* Main Charts Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="lg:col-span-2 bg-white p-6 md:p-10 rounded-[2.5rem] border border-slate-200 shadow-sm relative overflow-hidden">
