                  </div>
                  <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden mt-3">
                    <div className="bg-rose-400 h-full transition-all duration-1000" style={{ width: `${Math.min(100, (netWorthData.liabilities / Math.max(1, netWorthData.assets)) * 100)}%` }}></div>
