            )}
          </div>
          <button className="w-full mt-6 md:mt-10 py-4 md:py-5 bg-slate-100 text-slate-600 text-[9px] md:text-[10px] font-black uppercase tracking-[0.2em] rounded-2xl hover:bg-indigo-50 hover:text-indigo-600 transition-all active:scale-95">Verify All Records</button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

