      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-navy-800/95 backdrop-blur-xl border-t border-white/10 px-6 py-2 z-[60] flex justify-between items-center pb-[calc(env(safe-area-inset-bottom)+0.5rem)] soft-shadow">
