};

export default Layout;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type RateDisplayMode = 'hourly' | 'daily' | 'monthly';

interface DashboardProps {
  onNavigate: (tab: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onNavigate }) => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [displayMode, setDisplayMode] = useState<RateDisplayMode>('hourly');
  const [hoursPerDay, setHoursPerDay] = useState(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;

  const familyNotifications = state.notifications.slice(0, 4);
  const isConsolidated = activeMemberIds.includes('all') || activeMemberIds.length > 1;

  const familyMembers = state.profile?.familyMembers || [];

  // Actual "Live" Derived Calculations (Simple date-based division)
  const dailyIncome = rawRates.income / rawRates.daysPassed;
  const dailyExpense = rawRates.expense / rawRates.daysPassed;
  const dailySavings = dailyIncome - dailyExpense;

  const getDisplayValues = () => {
    switch (displayMode) {
      case 'monthly':
        return {
          income: rawRates.income,
          expense: rawRates.expense,
          savings: rawRates.monthlySurplus,
          cycle: 'mo'
        };
      case 'daily':
        return {
          income: dailyIncome,
          expense: dailyExpense,
          savings: dailySavings,
          cycle: 'day'
        };
      case 'hourly':
      default:
        return {
          income: dailyIncome / hoursPerDay,
          expense: dailyExpense / hoursPerDay,
          savings: dailySavings / hoursPerDay,
          cycle: 'hr'
        };
    }
  };

  const currentDisplay = getDisplayValues();

  // Planned "Budgeted" Derived Calculations (Simplified annual to daily/hourly/monthly)
  const budgetedAnnualIncome = (filteredState.incomes || []).reduce((acc, inc) => acc + (inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity]), 0);
  const budgetedAnnualExpense = (filteredState.budgets || []).reduce((acc, bud) => acc + (bud.amount), 0);

  const getBudgetedDisplayValues = () => {
    const dailyBIncome = budgetedAnnualIncome / 365;
    const dailyBExpense = budgetedAnnualExpense / 365;
    const dailyBSavings = dailyBIncome - dailyBExpense;

    switch (displayMode) {
      case 'monthly':
        return {
          income: budgetedAnnualIncome / 12,
          expense: budgetedAnnualExpense / 12,
          savings: (budgetedAnnualIncome - budgetedAnnualExpense) / 12
        };
      case 'daily':
        return {
          income: dailyBIncome,
          expense: dailyBExpense,
          savings: dailyBSavings
        };
      case 'hourly':
      default:
        return {
          income: dailyBIncome / hoursPerDay,
          expense: dailyBExpense / hoursPerDay,
          savings: dailyBSavings / hoursPerDay,
          cycle: 'hr'
        };
    }
  };

  const budgetedDisplay = getBudgetedDisplayValues();

  const pieData = [
    { name: 'Assets', value: netWorthData.assets, color: '#B08ED4' }, // Brand Primary
    { name: 'Liabilities', value: netWorthData.liabilities, color: '#222E4D' }, // Navy 700
  ];

  // Greeting Logic
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 17) return "Good afternoon";
    return "Good evening";
  };

  const getGreetingName = () => {
    if (activeMemberIds.includes('all')) {
        const userSurname = state.profile.name?.trim().split(' ').pop();
        return userSurname ? `The ${userSurname}s` : 'Family';
    } else if (activeMemberIds.length > 0) {
        const m = familyMembers.find(mem => mem.id === activeMemberIds[0]);
        return m ? m.name.split(' ')[0] : 'User';
    } else {
        return state.profile.name?.split(' ')[0] || 'User';
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 max-w-full">

      {/* Greeting Header */}
      <div className="mb-2">
         <h1 className="text-2xl md:text-3xl font-black text-white tracking-tight">
           {getGreeting()}, <span className="text-brand-primary">{getGreetingName()}</span>
         </h1>
         <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-1">Financial Overview</p>
      </div>

      {/* Rate Metric Controls */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-navy-800 p-3 rounded-[2rem] border border-white/5 soft-shadow backdrop-blur-sm">
        <div className="flex items-center gap-1 p-1 bg-navy-900 rounded-2xl w-full sm:w-auto overflow-x-auto no-scrollbar">
          <button 
            onClick={() => setDisplayMode('hourly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'hourly' ? 'bg-brand-gradient text-white shadow-lg' : 'text-brand-muted hover:text-white'}`}
          >
            Hourly
          </button>
          <button 
            onClick={() => setDisplayMode('daily')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'daily' ? 'bg-brand-gradient text-white shadow-lg' : 'text-brand-muted hover:text-white'}`}
          >
            Daily
          </button>
          <button 
            onClick={() => setDisplayMode('monthly')}
            className={`flex-1 sm:flex-none px-4 md:px-6 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${displayMode === 'monthly' ? 'bg-brand-gradient text-white shadow-lg' : 'text-brand-muted hover:text-white'}`}
          >
            Monthly
          </button>
        </div>

        <div className={`flex items-center gap-3 px-2 w-full sm:w-auto justify-center sm:justify-end transition-opacity duration-300 ${displayMode === 'hourly' ? 'opacity-100' : 'opacity-30 pointer-events-none'}`}>
          <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest whitespace-nowrap">Cycle Base</label>
          <select 
            value={hoursPerDay} 
            onChange={(e) => setHoursPerDay(Number(e.target.value))}
            disabled={displayMode !== 'hourly'}
            className="bg-navy-900 border border-white/10 rounded-xl px-2 py-2 text-[9px] font-black text-white outline-none focus:ring-4 focus:ring-brand-primary/20 disabled:opacity-30 cursor-pointer min-w-[100px]"
          >
            {[4, 6, 8, 10, 12, 16, 20, 24].map(h => (
              <option key={h} value={h}>{h} HR / Day</option>
            ))}
          </select>
        </div>
      </div>

      {/* Main Stats Grid: Table + Key Cards */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 md:gap-8">

         {/* Comparison Table */}
         <div className="xl:col-span-2 bg-navy-800 rounded-[2rem] border border-white/5 soft-shadow overflow-hidden flex flex-col justify-center">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[500px]">
                <thead>
                  <tr className="bg-navy-900/50 border-b border-white/5">
                    <th className="p-6 text-[10px] font-black text-brand-muted uppercase tracking-widest">Particulars</th>
                    <th className="p-6 text-[10px] font-black text-brand-muted uppercase tracking-widest text-brand-primary">Earnings / {currentDisplay.cycle || 'cycle'}</th>
                    <th className="p-6 text-[10px] font-black text-brand-muted uppercase tracking-widest text-rose-400">Spends / {currentDisplay.cycle || 'cycle'}</th>
                    <th className="p-6 text-[10px] font-black text-brand-muted uppercase tracking-widest text-brand-green">Savings / {currentDisplay.cycle || 'cycle'}</th>
                  </tr>
                </thead>
                <tbody>
                   {/* Budgeted Row */}
                   <tr className="border-b border-white/5 hover:bg-navy-700/50 transition-colors">
                      <td className="p-6">
                         <span className="text-xs font-black text-brand-muted uppercase tracking-tight">Budgeted</span>
                      </td>
                      <td className="p-6 text-sm font-black text-brand-muted">
                        {formatCurrency(budgetedDisplay.income, currency)}
                      </td>
                      <td className="p-6 text-sm font-black text-brand-muted">
                        {formatCurrency(budgetedDisplay.expense, currency)}
                      </td>
                      <td className="p-6 text-sm font-black text-brand-muted">
                        {formatCurrency(budgetedDisplay.savings, currency)}
                      </td>
                   </tr>
                   {/* Actuals Row */}
                   <tr className="hover:bg-navy-700/50 transition-colors">
                      <td className="p-6">
                         <span className="text-xs font-black text-brand-primary uppercase tracking-tight">Actuals</span>
                      </td>
                      <td className="p-6 text-xl font-black text-brand-primary">
                        {formatCurrency(currentDisplay.income, currency)}
                      </td>
                      <td className="p-6 text-xl font-black text-rose-400">
                        {formatCurrency(currentDisplay.expense, currency)}
                      </td>
                      <td className={`p-6 text-xl font-black ${currentDisplay.savings >= 0 ? 'text-brand-green' : 'text-rose-400'}`}>
                        {formatCurrency(currentDisplay.savings, currency)}
                      </td>
                   </tr>
                </tbody>
              </table>
            </div>
         </div>

         {/* Secondary Stats Cards */}
         <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-1 gap-6">
            <div className="p-6 rounded-[2rem] border border-white/5 bg-navy-800 soft-shadow flex flex-col justify-center h-full min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black text-white">ASSETS</div>
               <p className="text-[9px] font-black uppercase tracking-[0.2em] text-brand-muted">Total Assets</p>
               <h3 className="text-2xl font-black tracking-tight text-white mt-2">{formatCurrency(netWorthData.assets, currency)}</h3>
               <div className="w-full h-1 bg-navy-900 rounded-full mt-4 overflow-hidden">
                 <div className="h-full bg-brand-gradient w-full"></div>
               </div>
            </div>

            <div className="p-6 rounded-[2rem] border border-transparent bg-brand-gradient soft-shadow flex flex-col justify-center h-full min-h-[140px] relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-4 text-6xl opacity-10 font-black text-white">NET</div>
               <p className="text-[9px] font-black uppercase tracking-[0.2em] text-white/60">Net Worth</p>
               <h3 className="text-2xl font-black tracking-tight text-white mt-2">{formatCurrency(netWorthData.netWorth, currency)}</h3>
               <div className="w-full h-1 bg-white/20 rounded-full mt-4 overflow-hidden">
                 <div className="h-full bg-white w-full"></div>
               </div>
            </div>
         </div>
      </div>

      {/* Main Charts Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="lg:col-span-2 bg-navy-800 p-6 md:p-10 rounded-[2.5rem] border border-white/5 soft-shadow relative overflow-hidden">
           <div className="flex justify-between items-center mb-6 md:mb-10">
             <h4 className="text-[10px] md:text-xs font-black text-white uppercase tracking-widest">Wealth Composition</h4>
             <span className="text-[8px] md:text-[9px] font-black bg-navy-700 text-brand-primary px-3 py-1 rounded-full uppercase tracking-widest border border-brand-primary/20">Audit Ready</span>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 lg:gap-12 items-center">
              <div className="h-60 md:h-72 lg:h-80 relative">
