                    <Tooltip contentStyle={{ borderRadius: '20px', border: '1px solid rgba(255,255,255,0.1)', boxShadow: '0 10px 30px rgba(0,0,0,0.3)', padding: '12px', backgroundColor: '#1B2641', color: '#fff' }} itemStyle={{ color: '#fff' }} />
