const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, addAsset, updateAsset, addLiability, updateLiability, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: Math.abs(account.balance || account.value || account.amount || 0),
    balanceType: (account.balance < 0 && type === 'card') ? 'receivable' : 'outstanding',
    classification: (type === 'bank' || type === 'wallet') ? 'Current Asset' : (account.classification || 'Current Liability'),
    last4: account.last4 || '',
    billingDay: account.billingDay || 1,
    dueDate: account.dueDate || '',
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings'
  } : {
    ownerId: '',
    name: '',
    balance: '',
    balanceType: 'outstanding',
    classification: (type === 'bank' || type === 'wallet') ? 'Current Asset' : 'Current Liability',
    accNum: '',
    accountType: 'Savings',
    billingDay: 1,
    dueDate: '',
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId, classification: formData.classification };
    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const finalBalance = formData.balanceType === 'receivable' ? -Math.abs(Number(formData.balance)) : Math.abs(Number(formData.balance));
      const cardData = { ...commonProps, lenderName: formData.name, balance: finalBalance, last4: formData.last4, billingDay: Number(formData.billingDay), dueDate: formData.dueDate, offers: formData.offers };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    } else if (type === 'asset') {
      const assetData = { ...commonProps, name: formData.name, value: Number(formData.balance) };
      account ? updateAsset(assetData) : addAsset(assetData);
    } else if (type === 'liability') {
      const liabilityData = { ...commonProps, name: formData.name, amount: Number(formData.balance) };
      account ? updateLiability(liabilityData) : addLiability(liabilityData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Entity Owner</label>
          <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none cursor-pointer focus:border-brand-primary" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}><option value="">Me (Primary)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
        </div>
        <div className="space-y-2">
          <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Classification</label>
          <select disabled={type === 'bank' || type === 'wallet'} className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none disabled:opacity-50" value={formData.classification} onChange={e => setFormData({...formData, classification: e.target.value as AccountClassification})}>
            {CLASSIFICATIONS.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>
      <div className="space-y-2">
        <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Account Identifier</label>
        <input required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-sm text-white outline-none focus:ring-4 focus:ring-brand-primary/10 transition-all placeholder:text-white/20" placeholder="e.g. HDFC Infinity" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-2">
          <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Balance</label>
          <input required type="number" step="any" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-lg text-white outline-none focus:ring-4 focus:ring-brand-primary/10 transition-all" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
        </div>
        {type === 'bank' && (
          <div className="space-y-2">
            <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Type</label>
            <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none cursor-pointer" value={formData.accountType} onChange={e => setFormData({...formData, accountType: e.target.value})}><option>Savings</option><option>Current</option><option>Salary</option></select>
          </div>
        )}
        {type === 'card' && (
          <div className="space-y-2">
            <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Payment Due Day</label>
            <input type="date" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none focus:ring-4 focus:ring-brand-primary/10 transition-all" value={formData.dueDate} onChange={e => setFormData({...formData, dueDate: e.target.value})} />
          </div>
        )}
      </div>
      {type === 'card' && (
         <div className="space-y-2">
           <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-1">Last 4 Digits</label>
           <input maxLength={4} className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-sm text-white outline-none" value={formData.last4} onChange={e => setFormData({...formData, last4: e.target.value.replace(/\D/g, '')})} />
         </div>
      )}
      <button type="submit" className="w-full py-5 bg-brand-gradient text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-purple-500/20 transition-all hover:opacity-90 active:scale-95">Commit Record</button>
    </form>
  );
};

