  } | null>(null);

  const uploadInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || 'General',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  useEffect(() => {
    if (modalMode === 'broker_note' && scanResult) {
       const invAccount = allAccounts.find(a => a.name.toLowerCase().includes('zerodha') || a.name.toLowerCase().includes('demat') || a.name.toLowerCase().includes('investment'));
       if (invAccount) {
         setFormData(prev => ({ ...prev, accountId: invAccount.id }));
       }
    }
  }, [modalMode, scanResult, allAccounts]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve((reader.result as string).split(',')[1]);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const processDocumentWithAI = async (file: File) => {
    if (!file.type.startsWith('image/') && file.type !== 'application/pdf') return;

    setIsScanning(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(file);

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { mimeType: file.type, data: base64Data } },
            { text: "Analyze this financial document. Extract: netTotal (number), date (YYYY-MM-DD), merchant (string), description (string). If it is a stock contract note, extract trades array with scrip, type (BUY/SELL), units, netTotal for each trade line." }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              netTotal: { type: Type.NUMBER },
              date: { type: Type.STRING },
              merchant: { type: Type.STRING },
              description: { type: Type.STRING },
              trades: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    scrip: { type: Type.STRING },
                    type: { type: Type.STRING },
                    units: { type: Type.NUMBER },
                    netTotal: { type: Type.NUMBER },
                  }
                }
              }
            }
          }
        }
      });

      const text = response.text;
      if (text) {
        const data = JSON.parse(text);

        setFormData(prev => ({
          ...prev,
          amount: data.netTotal ? String(data.netTotal) : prev.amount,
          date: data.date || prev.date,
          description: data.description || (data.merchant ? `Payment to ${data.merchant}` : prev.description),
          nature: (data.trades && data.trades.length > 0) ? 'Investment' : prev.nature
        }));

        if (data.trades && data.trades.length > 0) {
           setScanResult({
             date: data.date || new Date().toISOString().split('T')[0],
             otherCharges: 0,
             trades: data.trades.map((t: any) => ({
               scrip: t.scrip,
               type: t.type?.toUpperCase() || 'BUY',
               units: t.units || 0,
               netTotal: t.netTotal || 0,
               grossValue: t.netTotal || 0,
               date: data.date || new Date().toISOString().split('T')[0],
               isin: '',
               stt: 0,
               allocatedCharges: 0
             }))
           });
           setModalMode('broker_note'); 
        }
      }
    } catch (e) {
      console.error("AI Scan failed", e);
      alert("Could not analyze document. Please try again or enter manually.");
    } finally {
      setIsScanning(false);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files) as File[];
      setPendingFiles(prev => [...prev, ...files]);
      if (files.length > 0) {
        processDocumentWithAI(files[0]);
      }
    }
  };

  const removeFile = (index: number) => {
    setPendingFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleQuickAdd = (type: TransactionType) => {
    setFormData({ ...initialFormState, type });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleBrokerAnalysis = () => {
    setFormData({ ...initialFormState, nature: 'Investment', type: 'Asset' });
    setModalMode('broker_note');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleEdit = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || '',
      estimatedLife: String(t.estimatedLife || 1)
    });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this record?')) {
      deleteTransaction(id);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select target account.");

    setIsUploading(true);

    const uploadedAttachments: TransactionAttachment[] = [];
    for (const file of pendingFiles) {
      try {
        const attachment = await uploadToDrive(file);
        uploadedAttachments.push(attachment);
      } catch (error) {
        console.error("Upload failed for file", file.name, error);
      }
    }

    if (modalMode === 'broker_note' && scanResult && scanResult.trades.length > 0) {
      for (const trade of scanResult.trades) {
        const tradeTx: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          type: trade.type === 'BUY' ? 'Asset' : 'Income', 
          amount: trade.netTotal,
          nature: 'Investment',
          description: `${trade.type} ${trade.units} ${trade.scrip}`,
          accountId: formData.accountId,
          accountType: account.type as any,
          date: scanResult.date,
          ownerId: formData.ownerId,
          stockName: trade.scrip,
          units: trade.units,
          status: 'active',
          attachments: uploadedAttachments
        };
        addTransaction(tradeTx);
      }
    } else {
      const transactionData: Transaction = {
        id: editingId || Math.random().toString(36).substr(2, 9),
        type: formData.type, 
        amount: Number(formData.amount), 
        nature: formData.nature,
        description: formData.description, 
        accountId: formData.accountId, 
        accountType: account.type as any,
        date: formData.date, 
        ownerId: formData.ownerId, 
        isin: formData.isin, 
        stockName: formData.stockName,
        units: formData.units ? Number(formData.units) : undefined, 
        billingPeriod: formData.billingPeriod,
        estimatedLife: Number(formData.estimatedLife), 
        status: 'active',
        attachments: uploadedAttachments
      };

      if (editingId) updateTransaction(transactionData);
      else addTransaction(transactionData);
    }

    setIsUploading(false);
    setPendingFiles([]);
    setShowModal(false);
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">

      {/* Top Action Bar */}
      <div className="flex flex-col md:flex-row gap-6 mb-8">
        <div className="flex-1 bg-navy-800 p-6 rounded-[2.5rem] border border-white/5 soft-shadow flex flex-col justify-between">
           <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-4">
              <div className="text-center sm:text-left">
                 <h3 className="text-lg font-black text-white uppercase tracking-tight">Quick Entry</h3>
                 <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-1">Select transaction class</p>
              </div>
              <div className="p-1.5 bg-navy-900 border border-white/5 rounded-xl flex gap-1 overflow-x-auto max-w-full no-scrollbar">
                 {['Expense', 'Income', 'Asset', 'Liability'].map((type) => (
                    <button 
                      key={type}
                      onClick={() => setSelectedQuickType(type as TransactionType)}
                      className={`px-3 md:px-4 py-2 rounded-lg text-[9px] md:text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                         selectedQuickType === type 
                           ? type === 'Expense' ? 'bg-rose-500 text-white shadow-lg shadow-rose-900/50'
                           : type === 'Income' ? 'bg-brand-green text-white shadow-lg shadow-green-900/50'
                           : type === 'Asset' ? 'bg-brand-primary text-white shadow-lg shadow-purple-900/50'
                           : 'bg-amber-500 text-white shadow-lg shadow-amber-900/50'
                           : 'text-brand-muted hover:bg-navy-700 hover:text-white'
                      }`}
                    >
                      {type}
                    </button>
                 ))}
              </div>
           </div>

           <button 
             onClick={() => handleQuickAdd(selectedQuickType)}
             className={`w-full py-4 md:py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${
                selectedQuickType === 'Expense' ? 'bg-rose-500/10 text-rose-400 hover:bg-rose-500/20 border border-rose-500/30'
                : selectedQuickType === 'Income' ? 'bg-brand-green/10 text-brand-green hover:bg-brand-green/20 border border-brand-green/30'
                : selectedQuickType === 'Asset' ? 'bg-brand-primary/10 text-brand-primary hover:bg-brand-primary/20 border border-brand-primary/30'
                : 'bg-amber-500/10 text-amber-500 hover:bg-amber-500/20 border border-amber-500/30'
             }`}
           >
              <span className="text-xl">
                 {selectedQuickType === 'Expense' ? '💸' : selectedQuickType === 'Income' ? '💰' : selectedQuickType === 'Asset' ? '💎' : '💳'}
              </span>
              Record New {selectedQuickType}
           </button>
        </div>

        <button onClick={handleBrokerAnalysis} className="md:w-72 bg-navy-800 text-white p-8 rounded-[2.5rem] shadow-xl border border-white/5 relative overflow-hidden group text-left">
            <div className="absolute top-0 right-0 p-6 text-6xl opacity-10 font-black group-hover:scale-110 transition-transform text-white">AI</div>
            <div className="relative z-10 h-full flex flex-col justify-between">
               <div>
                  <div className="w-12 h-12 bg-navy-700 rounded-2xl flex items-center justify-center text-2xl shadow-sm mb-4">🤖</div>
                  <h3 className="text-lg font-black uppercase tracking-tight text-white">Broker Import</h3>
                  <p className="text-[10px] font-black text-brand-primary uppercase tracking-widest mt-1">AI Contract Analysis</p>
               </div>
               <div className="mt-6 flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-brand-muted group-hover:text-white transition-colors">
                  <span>Launch Scanner</span>
                  <span>→</span>
               </div>
            </div>
        </button>
      </div>

      <div className="bg-navy-800 rounded-[2.5rem] border border-white/5 soft-shadow overflow-hidden flex flex-col">
        <div className="p-8 border-b border-white/5 flex justify-between items-center">
           <h3 className="text-lg font-black text-white uppercase tracking-tight">Audit Ledger</h3>
           <span className="text-[9px] font-black text-brand-muted uppercase tracking-widest">{transactionList.length} Records Verified</span>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[900px]">
            <thead className="bg-navy-900/50 text-brand-muted text-[9px] font-black uppercase tracking-[0.3em] border-b border-white/5">
              <tr>
                <th className="px-8 py-6">Date</th>
                <th className="px-8 py-6">Nature</th>
                <th className="px-8 py-6">Description</th>
                <th className="px-8 py-6">Entity</th>
                <th className="px-8 py-6 text-right">Amount</th>
                <th className="px-8 py-6 text-center">Docs</th>
                <th className="px-8 py-6 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-navy-700/30 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-brand-muted uppercase tracking-widest">{t.date}</td>
                  <td className="px-8 py-6">
                    <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${
                      t.type === 'Income' ? 'bg-brand-green/20 text-brand-green' :
                      t.type === 'Expense' ? 'bg-rose-500/20 text-rose-400' :
                      t.type === 'Asset' ? 'bg-brand-primary/20 text-brand-primary' : 'bg-amber-500/20 text-amber-500'
                    }`}>{t.type}</span>
                    <p className="text-[9px] font-bold text-white/40 uppercase mt-1 ml-1">{t.nature}</p>
                  </td>
                  <td className="px-8 py-6">
                    <p className="text-sm font-black text-white tracking-tight">{t.description}</p>
                    {t.stockName && <p className="text-[9px] text-brand-primary font-bold uppercase mt-0.5">{t.units} Units • {t.stockName}</p>}
                  </td>
                  <td className="px-8 py-6 text-[10px] font-black text-brand-muted uppercase tracking-widest">
                     {t.ownerId ? (familyMembers.find(m => m.id === t.ownerId)?.name || 'Member') : 'Me'}
                  </td>
                  <td className="px-8 py-6 text-right font-black tracking-tight text-sm text-white">
                     {formatCurrency(t.amount, currency)}
                  </td>
                  <td className="px-8 py-6 text-center">
                    {(t.attachments && t.attachments.length > 0) ? (
                      <button onClick={() => setViewingAttachments(t)} className="w-8 h-8 rounded-full bg-navy-700 text-brand-primary flex items-center justify-center hover:bg-navy-600 transition-colors">
                        📎
                      </button>
                    ) : (
                      <span className="text-white/10 text-lg">•</span>
                    )}
                  </td>
                  <td className="px-8 py-6 text-center">
                     <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => handleEdit(t)} className="text-white/40 hover:text-brand-primary font-black text-xs">✎</button>
                        <button onClick={() => handleDelete(t.id)} className="text-white/40 hover:text-rose-500 font-black text-xs">✕</button>
                     </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-navy-900/80 backdrop-blur-sm p-4 overflow-y-auto">
          <div className="glass-panel w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-white/10 shadow-2xl animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center mb-8 shrink-0">
               <h3 className="text-xl font-black text-white uppercase tracking-tight">
                 {modalMode === 'broker_note' ? 'Broker Note Extraction' : 'Record Transaction'}
               </h3>
               <button onClick={() => setShowModal(false)} className="text-white/50 hover:text-white text-2xl font-black">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar pr-2">
              <form onSubmit={handleSubmit} className="space-y-8">

                <div className="space-y-2">
                  <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Supporting Evidence (AI Scan)</label>
                  <div 
                    className={`border-2 border-dashed rounded-3xl p-8 text-center transition-all ${state.profile.googleDriveConfig?.isConnected ? 'border-white/20 hover:border-brand-primary cursor-pointer bg-navy-900/50' : 'border-white/10 bg-navy-900/30 opacity-60 cursor-not-allowed'}`}
                    onClick={() => state.profile.googleDriveConfig?.isConnected && uploadInputRef.current?.click()}
                  >
                     {state.profile.googleDriveConfig?.isConnected ? (
                       <>
                          <input type="file" ref={uploadInputRef} className="hidden" multiple onChange={handleFileSelect} accept="image/*,.pdf" />
                          <div className={`text-3xl mb-3 transition-transform ${isScanning ? 'animate-bounce' : ''}`}>
                             {isScanning ? '🤖' : '📄'}
                          </div>
                          <p className="text-[10px] font-black text-white uppercase tracking-tight">
                            {isScanning ? 'Analyzing Document Structure...' : 'Click to Upload & Scan'}
                          </p>
                          <p className="text-[8px] font-bold text-brand-muted uppercase mt-1">
                             {state.profile.googleDriveConfig.linkedEmail} • {state.profile.googleDriveConfig.folderName}
                          </p>
                       </>
                     ) : (
                       <div className="py-2">
                         <div className="text-2xl mb-2 grayscale opacity-50">☁️</div>
                         <p className="text-[10px] font-black text-white/50 uppercase tracking-tight">Cloud Storage Not Linked</p>
                         <p className="text-[8px] font-bold text-rose-400 uppercase mt-1">Login to Google Drive in Profile to enable uploads</p>
                       </div>
                     )}
                  </div>

                  {pendingFiles.length > 0 && (
                    <div className="flex flex-wrap gap-2 mt-4">
                       {pendingFiles.map((file, idx) => (
                         <div key={idx} className="flex items-center gap-2 px-3 py-2 bg-navy-700 text-brand-primary rounded-xl border border-white/5">
                            <span className="text-xs">📄</span>
                            <span className="text-[9px] font-black uppercase truncate max-w-[100px]">{file.name}</span>
                            <button type="button" onClick={() => removeFile(idx)} className="text-[9px] hover:text-rose-500 font-black ml-1">✕</button>
                         </div>
                       ))}
                    </div>
                  )}
                </div>

                {modalMode === 'broker_note' && scanResult && scanResult.trades.length > 0 ? (
                  <div className="space-y-6 animate-in slide-in-from-bottom-4">
                     <div className="flex items-center justify-between p-4 bg-brand-green/10 border border-brand-green/20 rounded-2xl">
                        <div>
                           <p className="text-[10px] font-black text-brand-green uppercase tracking-widest">Extraction Successful</p>
                           <p className="text-xs font-black text-white mt-1">{scanResult.trades.length} Trades Identified</p>
                        </div>
                        <div className="text-right">
                           <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Date</p>
                           <p className="text-xs font-black text-white">{scanResult.date}</p>
                        </div>
                     </div>

                     <div className="border border-white/10 rounded-2xl overflow-hidden">
                        <table className="w-full text-left">
                           <thead className="bg-navy-900 text-[8px] font-black text-brand-muted uppercase tracking-widest">
                              <tr>
                                 <th className="p-3">Scrip</th>
                                 <th className="p-3">Action</th>
                                 <th className="p-3 text-right">Units</th>
                                 <th className="p-3 text-right">Net Value</th>
                              </tr>
                           </thead>
                           <tbody className="divide-y divide-white/5">
                              {scanResult.trades.map((trade, idx) => (
                                <tr key={idx} className="text-[10px] font-black text-white">
                                   <td className="p-3">{trade.scrip}</td>
                                   <td className="p-3"><span className={trade.type === 'BUY' ? 'text-brand-green' : 'text-rose-400'}>{trade.type}</span></td>
                                   <td className="p-3 text-right">{trade.units}</td>
                                   <td className="p-3 text-right">{formatCurrency(trade.netTotal, currency)}</td>
                                </tr>
                              ))}
                           </tbody>
                        </table>
                     </div>

                     <div className="space-y-2">
                        <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Target Investment Account</label>
                        <select required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                          <option value="">Select Account</option>
                          {allAccounts.map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                        </select>
                     </div>
                  </div>
                ) : (
                  <div className="space-y-8 animate-in fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Transaction Type</label>
                        <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white appearance-none cursor-pointer" value={formData.type} onChange={e => setFormData({ ...formData, type: e.target.value as TransactionType })}>
                          <option value="Expense">Expense</option>
                          <option value="Income">Income</option>
                          <option value="Asset">Asset</option>
                          <option value="Liability">Liability</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Date</label>
                        <input required type="date" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white uppercase cursor-pointer" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Net Amount ({currency})</label>
                      <input required type="number" step="any" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-2xl text-white" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} placeholder="0.00" />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2">
                         <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Description</label>
                         <input className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} placeholder="Narrative..." />
                      </div>
                      <div className="space-y-2">
                         <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Nature / Category</label>
                         <input className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })} list="nature-list" />
                         <datalist id="nature-list">{natures.map(n => <option key={n} value={n} />)}</datalist>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                       <div className="space-y-2">
                          <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Account Instrument</label>
                          <select required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
