                          <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white appearance-none cursor-pointer" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value })}>
                            <option value="">Me (Primary)</option>
