                          </select>
                       </div>
                    </div>
                  </div>
                )}

                <div className="flex gap-4 pt-4 border-t border-white/10">
                   <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-navy-700 text-brand-muted font-black text-[10px] uppercase rounded-2xl hover:text-white transition-colors">Abort</button>
                   <button type="submit" disabled={isUploading} className="flex-[2] py-5 bg-brand-gradient text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl flex items-center justify-center gap-2 hover:opacity-90 transition-all active:scale-95 disabled:opacity-70">
                     {isUploading ? <span className="animate-spin">⏳ Processing...</span> : (modalMode === 'broker_note' && scanResult?.trades.length ? `Import ${scanResult.trades.length} Trades` : 'Commit Record')}
                   </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {viewingAttachments && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-navy-900/80 backdrop-blur-md p-4">
           <div className="glass-panel w-full max-w-md rounded-[2.5rem] p-8 border border-white/10 shadow-2xl animate-in zoom-in duration-200">
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-black text-white uppercase tracking-tight">Digital Evidence</h3>
                  <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest mt-1">Stored in Secure Vault</p>
                </div>
                <button onClick={() => setViewingAttachments(null)} className="text-white/50 hover:text-white text-2xl font-black">✕</button>
              </div>

              <div className="space-y-3">
                 {viewingAttachments.attachments?.map((att, idx) => (
                   <a key={idx} href={att.url} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-4 bg-navy-900/50 border border-white/10 rounded-2xl hover:bg-navy-700 hover:border-brand-primary/30 transition-all group">
                      <div className="flex items-center gap-4 overflow-hidden">
                         <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center text-lg shadow-sm text-white">📄</div>
                         <div>
                            <p className="text-[10px] font-black text-white uppercase truncate max-w-[150px]">{att.name}</p>
                            <p className="text-[8px] font-bold text-brand-muted uppercase">{new Date(att.uploadDate).toLocaleDateString()}</p>
                         </div>
                      </div>
                      <span className="text-xs text-white/30 group-hover:text-brand-primary">↗</span>
                   </a>
                 ))}
                 {(viewingAttachments.attachments || []).length === 0 && <p className="text-center text-[10px] font-black text-white/30 py-8">No files attached.</p>}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo, useEffect } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity, Budget, IncomeStream } from '../types';
import { ANNUAL_MULTIPLIERS } from '../utils/calculations';

const FREQUENCIES: Periodicity[] = [
  'Daily', 'Weekly', 'Fortnightly', 'Monthly', 'Quarterly', 'Half-Yearly', 'Annually'
];

type ViewWindow = 'This Month' | 'Last Month' | 'This Quarter' | 'Financial Year' | 'Custom';
type PlannerTab = 'expense' | 'income';

const DEFAULT_INCOMES: Partial<IncomeStream>[] = [
  { name: 'Salary', periodicity: 'Monthly' },
  { name: 'House Rent', periodicity: 'Monthly' }
];

const DEFAULT_EXPENSES: Partial<Budget>[] = [
  { category: 'Rent', frequency: 'Monthly' },
  { category: 'Term Insurance Premium', frequency: 'Monthly' },
  { category: 'Bike Insurance Premium', frequency: 'Annually' },
  { category: 'Car Insurance Premium', frequency: 'Annually' },
  { category: 'Internet Recharge', frequency: 'Monthly' },
  { category: 'Maintenance bill', frequency: 'Monthly' },
  { category: 'Electricity Bill', frequency: 'Monthly' },
  { category: 'Health Insurance Premium', frequency: 'Monthly' },
  { category: 'Phone Recharge', frequency: 'Annually' },
  { category: 'AMC Charges', frequency: 'Quarterly' },
  { category: 'Health and Fitness', frequency: 'Monthly' },
  { category: 'Conveyance', frequency: 'Monthly' },
  { category: 'Donation', frequency: 'Monthly' },
  { category: 'Entertainment Expenses', frequency: 'Monthly' },
  { category: 'Food', frequency: 'Monthly' },
  { category: 'Groceries', frequency: 'Monthly' },
  { category: 'Fuel Expenses', frequency: 'Monthly' },
  { category: 'Medical Expenses', frequency: 'Monthly' },
  { category: 'Miscellaneous Expenses', frequency: 'Monthly' },
  { category: 'Repairs and Maintenance', frequency: 'Monthly' },
  { category: 'Shopping Expenses', frequency: 'Monthly' },
  { category: 'Personal Care/ Grooming', frequency: 'Monthly' },
  { category: 'Social Expenses', frequency: 'Monthly' },
  { category: 'Travelling', frequency: 'Monthly' },
  { category: 'Gifting', frequency: 'Monthly' },
  { category: 'Education Expenses', frequency: 'Monthly' },
  { category: 'Daily House Help', frequency: 'Monthly' }
];

const getBudgetDueDateForWindow = (dueDateStr: string | undefined, windowStart: Date) => {
  if (!dueDateStr) return null;
  const refDate = new Date(dueDateStr);
  if (isNaN(refDate.getTime())) return null;

  const day = refDate.getDate();
  const targetDate = new Date(windowStart.getFullYear(), windowStart.getMonth(), day);

  if (targetDate.getMonth() !== windowStart.getMonth()) {
    targetDate.setDate(0); 
  }

  return targetDate;
};

const BudgetPlanner: React.FC = () => {
  const { filteredState, state, addBudget, updateBudget, deleteBudget, addIncome, updateIncome, deleteIncome } = useFinance();
  const [activeTab, setActiveTab] = useState<PlannerTab>('expense');
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isFocusMode, setIsFocusMode] = useState(false);
  const currency = state.profile.currency;

  const [viewWindowType, setViewWindowType] = useState<ViewWindow>('This Month');
  const [customViewStart, setCustomViewStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customViewEnd, setCustomViewEnd] = useState(new Date().toISOString().split('T')[0]);

  const [formData, setFormData] = useState<{
    category: string;
    amount: number;
    amountPerPeriod: number;
    frequency: Periodicity;
    periodType: 'Financial' | 'Calendar' | 'Custom';
    startDate: string;
    endDate: string;
    dueDate: string;
    dateOfReceipt: string; 
  }>({
    category: '',
    amount: 0,
    amountPerPeriod: 0,
    frequency: 'Monthly',
    periodType: 'Financial',
    startDate: '',
    endDate: '',
    dueDate: '',
    dateOfReceipt: ''
  });

  const getPeriodDates = (type: 'Financial' | 'Calendar' | 'Custom') => {
    const now = new Date();
    const currentYear = now.getFullYear();
    if (type === 'Calendar') {
      return { start: `${currentYear}-01-01`, end: `${currentYear}-12-31` };
    } else if (type === 'Financial') {
      const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
      return { start: `${startYear}-04-01`, end: `${startYear + 1}-03-31` };
    }
    return { start: formData.startDate || '', end: formData.endDate || '' };
  };

  const getWindowMultiplier = (view: ViewWindow, freq: Periodicity) => {
    if (view === 'Financial Year') return ANNUAL_MULTIPLIERS[freq];
    const map: Record<Exclude<ViewWindow, 'Financial Year'>, Record<Periodicity, number>> = {
      'This Month': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'Last Month': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 },
      'This Quarter': { 'Daily': 91, 'Weekly': 13, 'Fortnightly': 6, 'Monthly': 3, 'Quarterly': 1, 'Half-Yearly': 0.5, 'Annually': 0.25 },
      'Custom': { 'Daily': 30, 'Weekly': 4, 'Fortnightly': 2, 'Monthly': 1, 'Quarterly': 0.33, 'Half-Yearly': 0.16, 'Annually': 0.083 }
    };
    return map[view as Exclude<ViewWindow, 'Financial Year'>][freq] || 1;
  };

  useEffect(() => {
    const total = (formData.amountPerPeriod || 0) * ANNUAL_MULTIPLIERS[formData.frequency as Periodicity];
    if (activeTab === 'expense' && Math.abs((formData.amount || 0) - total) > 0.01) {
      setFormData(prev => ({ ...prev, amount: total }));
    } else if (activeTab === 'income') {
       setFormData(prev => ({ ...prev, amount: formData.amountPerPeriod }));
    }
  }, [formData.amountPerPeriod, formData.frequency, activeTab]);

  const currentAnalysisWindow = useMemo(() => {
    const now = new Date();
    let start = new Date();
    let end = new Date();
    if (viewWindowType === 'This Month') {
      start = new Date(now.getFullYear(), now.getMonth(), 1);
      end = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (viewWindowType === 'Last Month') {
      start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      end = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
    } else if (viewWindowType === 'This Quarter') {
      const q = Math.floor(now.getMonth() / 3);
      start = new Date(now.getFullYear(), q * 3, 1);
      end = new Date(now.getFullYear(), (q + 1) * 3, 0, 23, 59, 59);
    } else if (viewWindowType === 'Financial Year') {
      const startYear = now.getMonth() < 3 ? now.getFullYear() - 1 : now.getFullYear();
      start = new Date(startYear, 3, 1);
      end = new Date(startYear + 1, 2, 31, 23, 59, 59);
    } else if (viewWindowType === 'Custom') {
      start = new Date(customViewStart);
      end = new Date(customViewEnd);
      end.setHours(23, 59, 59, 999);
    }
    return { start, end };
  }, [viewWindowType, customViewStart, customViewEnd]);

  const budgetsWithAnalytics = useMemo(() => {
    const now = new Date();
    const { start: windowStart, end: windowEnd } = currentAnalysisWindow;
    return (filteredState.budgets || []).map(b => {
      const bStart = new Date(b.startDate);
      const bEnd = new Date(b.endDate);
      const effectiveStart = new Date(Math.max(bStart.getTime(), windowStart.getTime()));
      const effectiveEnd = new Date(Math.min(bEnd.getTime(), windowEnd.getTime()));
      const hasOverlap = effectiveStart <= effectiveEnd;
      const windowActual = hasOverlap 
        ? (filteredState.transactions || [])
          .filter(t => t.type === 'Expense' && t.nature === b.category && new Date(t.date) >= effectiveStart && new Date(t.date) <= effectiveEnd)
          .reduce((sum, t) => sum + t.amount, 0)
        : 0;
      const multiplier = getWindowMultiplier(viewWindowType, b.frequency);
      const amountPerFreq = b.amount / ANNUAL_MULTIPLIERS[b.frequency];
      const dynamicTarget = amountPerFreq * multiplier;
      const isInactive = now < bStart || now > bEnd;
      const windowDueDate = getBudgetDueDateForWindow(b.dueDate, windowStart);
      return { ...b, windowActual, dynamicTarget, amountPerFreq, isInactive, hasOverlap, windowDueDate };
    });
  }, [filteredState.budgets, filteredState.transactions, currentAnalysisWindow, viewWindowType]);

  const overallEfficiency = useMemo(() => {
    if (activeTab !== 'expense') return null;

    const totalTarget = budgetsWithAnalytics.reduce((acc, b) => acc + (b.hasOverlap ? b.dynamicTarget : 0), 0);
    const totalActual = budgetsWithAnalytics.reduce((acc, b) => acc + b.windowActual, 0);
    const percentage = totalTarget > 0 ? (totalActual / totalTarget) * 100 : 0;

    return {
      totalTarget,
      totalActual,
      percentage,
      status: percentage > 100 ? 'critical' : percentage > 85 ? 'warning' : 'safe'
    };
  }, [budgetsWithAnalytics, activeTab]);

  const handleOpenModal = (item?: any) => {
    if (item) {
      setEditingId(item.id);
      if (activeTab === 'expense') {
        const b = item as Budget;
        setFormData({
            category: b.category,
            amount: b.amount,
            amountPerPeriod: b.amount / ANNUAL_MULTIPLIERS[b.frequency],
            frequency: b.frequency,
            periodType: b.periodType,
            startDate: b.startDate,
            endDate: b.endDate,
            dueDate: b.dueDate || '',
            dateOfReceipt: ''
        });
      } else {
        const i = item as IncomeStream;
        setFormData({
            category: i.name,
            amount: i.amount,
            amountPerPeriod: i.amount, 
            frequency: i.periodicity,
            periodType: 'Financial',
            startDate: '',
            endDate: '',
            dueDate: '',
            dateOfReceipt: i.dateOfReceipt
        });
      }
    } else {
      setEditingId(null);
      const dates = getPeriodDates('Financial');
      setFormData({ 
          category: '', 
          amount: 0, 
          amountPerPeriod: 0, 
          frequency: 'Monthly', 
          periodType: 'Financial', 
          startDate: dates.start, 
          endDate: dates.end, 
          dueDate: '',
          dateOfReceipt: ''
      });
    }
    setShowModal(true);
  };

  const handleLoadTemplate = () => {
    const dates = getPeriodDates('Financial');

    // Load Incomes
    DEFAULT_INCOMES.forEach(inc => {
       if (!filteredState.incomes.some(i => i.name === inc.name)) {
          addIncome({
             id: Math.random().toString(36).substr(2, 9),
             name: inc.name || 'Income',
             amount: 0,
             periodicity: inc.periodicity || 'Monthly',
             dateOfReceipt: '',
             ownerId: ''
          });
       }
    });

    // Load Expenses
    DEFAULT_EXPENSES.forEach(exp => {
       if (!filteredState.budgets.some(b => b.category === exp.category)) {
          addBudget({
             id: Math.random().toString(36).substr(2, 9),
             category: exp.category || 'Expense',
             amount: 0,
             frequency: exp.frequency || 'Monthly',
             startDate: dates.start,
             endDate: dates.end,
             periodType: 'Financial',
             ownerId: ''
          });
       }
    });

    alert("Template loaded! Default categories added to both Incomes and Expenses.");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeTab === 'expense') {
        const dates = getPeriodDates(formData.periodType as any);
        const budgetData: Budget = {
          id: editingId || Math.random().toString(36).substr(2, 9),
          category: formData.category || 'General',
          amount: Number(formData.amount),
          frequency: formData.frequency as Periodicity,
          startDate: dates.start,
          endDate: dates.end,
          dueDate: formData.dueDate,
          periodType: formData.periodType as any,
          ownerId: ''
        };
        if (editingId) updateBudget(budgetData);
        else addBudget(budgetData);
    } else {
        const incomeData: IncomeStream = {
            id: editingId || Math.random().toString(36).substr(2, 9),
            name: formData.category || 'Income',
            amount: Number(formData.amountPerPeriod),
            periodicity: formData.frequency,
            dateOfReceipt: formData.dateOfReceipt,
            ownerId: ''
        };
        if (editingId) updateIncome(incomeData);
        else addIncome(incomeData);
    }
    setShowModal(false);
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">

      {/* Dynamic Header & Options Bar */}
      {!isFocusMode && (
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0 animate-in slide-in-from-top-4 duration-300">
          <div>
            <h2 className="text-2xl md:text-3xl font-black text-white tracking-tight uppercase">Budget Architect</h2>
            <p className="text-[10px] font-black text-brand-muted uppercase tracking-[0.2em] mt-2">Strategic Resource Allocation</p>
          </div>
          <div className="flex flex-wrap items-center gap-3">
             <button onClick={() => setIsFocusMode(true)} className="px-5 py-3.5 bg-navy-800 text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-xl border border-white/5 transition-transform active:scale-95">Focus Mode</button>
             <button onClick={handleLoadTemplate} className="px-5 py-3.5 bg-navy-700 border border-white/10 text-brand-muted rounded-2xl text-[9px] font-black uppercase tracking-widest hover:text-white active:scale-95">Load Template</button>
             <button onClick={() => handleOpenModal()} className="px-6 py-4 bg-brand-gradient text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-purple-500/20 active:scale-95 transition-all">+ Add {activeTab === 'expense' ? 'Target' : 'Stream'}</button>
          </div>
        </div>
      )}

      {/* Focus Mode Control Bar */}
      {isFocusMode && (
        <div className="sticky top-4 z-50 flex items-center justify-between bg-navy-800 text-white p-3 rounded-2xl shadow-2xl mx-4 md:mx-0 animate-in slide-in-from-top-4 border border-white/10 glass-panel">
           <div className="flex items-center gap-4 px-3">
              <span className="text-sm">🧘</span>
              <p className="text-[10px] font-black uppercase tracking-[0.2em]">Focused Analysis</p>
           </div>
           <div className="flex items-center gap-2">
              <button onClick={() => handleOpenModal()} className="px-4 py-2 bg-brand-primary text-[9px] font-black uppercase tracking-widest rounded-xl transition-all active:scale-95 text-white">+ Add</button>
              <button onClick={() => setIsFocusMode(false)} className="px-4 py-2 bg-white/10 hover:bg-white/20 text-[9px] font-black uppercase tracking-widest rounded-xl transition-colors">Exit Focus</button>
           </div>
        </div>
      )}

      {/* Tabs and Period Options */}
      {!isFocusMode && (
        <div className="flex flex-col gap-4 animate-in fade-in duration-500">
            {/* Main Tabs */}
            <div className="flex bg-navy-800 p-1 rounded-[1.5rem] self-start border border-white/5">
               <button onClick={() => setActiveTab('expense')} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'expense' ? 'bg-navy-900 shadow-sm text-brand-primary' : 'text-brand-muted hover:text-white'}`}>Expense Targets</button>
               <button onClick={() => setActiveTab('income')} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'income' ? 'bg-navy-900 shadow-sm text-brand-green' : 'text-brand-muted hover:text-white'}`}>Income Streams</button>
            </div>

            {/* Period Filter */}
            <div className="bg-navy-800 p-2 rounded-[2rem] border border-white/5 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex flex-wrap items-center gap-1 p-1 bg-navy-900/50 rounded-2xl">
                {(['This Month', 'Last Month', 'This Quarter', 'Financial Year', 'Custom'] as ViewWindow[]).map(type => (
                    <button 
                    key={type} 
                    onClick={() => setViewWindowType(type)}
                    className={`px-4 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${viewWindowType === type ? 'bg-brand-gradient text-white shadow-lg' : 'text-brand-muted hover:text-white'}`}
                    >
                    {type}
                    </button>
                ))}
                </div>
                {viewWindowType === 'Custom' ? (
                <div className="flex items-center gap-3 px-4 animate-in slide-in-from-right-4">
                    <input type="date" className="bg-navy-900 border border-white/10 rounded-xl px-3 py-2 text-[10px] font-black outline-none focus:ring-4 focus:ring-brand-primary/20 text-white" value={customViewStart} onChange={e => setCustomViewStart(e.target.value)} />
                    <input type="date" className="bg-navy-900 border border-white/10 rounded-xl px-3 py-2 text-[10px] font-black outline-none focus:ring-4 focus:ring-brand-primary/20 text-white" value={customViewEnd} onChange={e => setCustomViewEnd(e.target.value)} />
                </div>
                ) : (
                <div className="px-6 text-[10px] font-black text-brand-primary uppercase hidden md:block">
                    Audit Range: {currentAnalysisWindow.start.toLocaleDateString()} — {currentAnalysisWindow.end.toLocaleDateString()}
                </div>
                )}
            </div>
        </div>
      )}

      {/* Overall Efficiency Health Chart */}
      {overallEfficiency && (
        <div className="bg-navy-800 p-6 md:p-8 rounded-[2.5rem] border border-white/5 soft-shadow animate-in slide-in-from-bottom-4">
           <div className="flex justify-between items-end mb-4">
              <div>
                 <h3 className="text-sm font-black text-white uppercase tracking-widest">Overall Efficiency Health</h3>
                 <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-1">Utilization Across {viewWindowType}</p>
              </div>
              <div className="text-right">
                 <p className="text-2xl font-black text-white">{overallEfficiency.percentage.toFixed(1)}%</p>
                 <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">{formatCurrency(overallEfficiency.totalActual, currency)} / {formatCurrency(overallEfficiency.totalTarget, currency)}</p>
              </div>
           </div>

           <div className="w-full h-3 bg-navy-900 rounded-full overflow-hidden relative">
              <div 
                 className={`h-full transition-all duration-1000 ${
                    overallEfficiency.status === 'critical' ? 'bg-rose-500' : 
                    overallEfficiency.status === 'warning' ? 'bg-amber-400' : 'bg-brand-green'
                 }`} 
                 style={{ width: `${Math.min(100, overallEfficiency.percentage)}%` }}
              ></div>
           </div>

           <div className="flex justify-between items-center mt-3">
              <span className="text-[9px] font-black text-brand-green uppercase tracking-widest">Under Budget</span>
              <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest">Over Budget</span>
           </div>
        </div>
      )}

      {/* Main Table Area */}
      <div className="bg-navy-800 rounded-[2.5rem] border border-white/5 soft-shadow overflow-hidden flex flex-col min-h-[400px]">
        <div className="overflow-x-auto custom-scrollbar relative flex-1">
          <table className="w-full text-left border-separate border-spacing-0 min-w-[800px]">
            <thead className="bg-navy-900/80 backdrop-blur-md text-brand-muted text-[9px] font-black uppercase tracking-[0.3em] sticky top-0 z-30">
              <tr>
                <th className="px-8 py-6 sticky left-0 z-40 bg-navy-900 border-b border-white/5 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)]">{activeTab === 'expense' ? 'Category' : 'Source Name'}</th>
                <th className="px-8 py-6 text-right border-b border-white/5">{activeTab === 'expense' ? 'Target (Period)' : 'Expected Amount'}</th>
                {activeTab === 'expense' && <th className="px-8 py-6 text-right border-b border-white/5">Actual (In Window)</th>}
                <th className="px-8 py-6 text-right border-b border-white/5">Projected Annual</th>
                <th className="px-8 py-6 text-center border-b border-white/5">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {activeTab === 'expense' ? budgetsWithAnalytics.map(b => {
                const isOver = b.windowActual > b.dynamicTarget;

                return (
                  <tr key={b.id} className={`hover:bg-navy-700/30 transition-colors group ${b.isInactive ? 'opacity-40 grayscale' : ''}`}>
                    <td className="px-8 py-4 sticky left-0 z-20 bg-navy-800 group-hover:bg-navy-700/30 border-b border-white/5 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
                      <div className="flex justify-between items-center gap-3">
                        <p className="text-xs font-black text-white uppercase tracking-tight">{b.category}</p>
                        {b.windowDueDate && (
                          <div className="flex items-center justify-center min-w-[32px] bg-rose-500/10 text-rose-400 px-2 py-1 rounded-lg border border-rose-500/20 shadow-sm animate-in zoom-in-90">
                             <span className="text-[8px] font-black leading-none uppercase">Due {b.windowDueDate.getDate()}</span>
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-xs text-brand-primary">
                      {formatCurrency(b.dynamicTarget, currency)}
                    </td>
                    <td className={`px-8 py-4 text-right font-black text-xs ${isOver ? 'text-rose-400' : 'text-white'}`}>
                      {formatCurrency(b.windowActual, currency)}
                    </td>
                    <td className="px-8 py-4 text-right">
                       <p className="text-[10px] font-black text-white">{formatCurrency(b.amount, currency)}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(b)} className="p-2 bg-navy-700 text-brand-primary hover:text-white rounded-lg shadow-sm border border-white/5 transition-colors">✎</button>
                          <button onClick={() => deleteBudget(b.id)} className="p-2 bg-navy-700 text-rose-400 hover:text-rose-300 rounded-lg shadow-sm border border-white/5 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              }) : filteredState.incomes.map(inc => (
                 <tr key={inc.id} className="hover:bg-navy-700/30 transition-colors group">
                    <td className="px-8 py-4 sticky left-0 z-20 bg-navy-800 group-hover:bg-navy-700/30 border-b border-white/5 shadow-[4px_0_12px_-4px_rgba(0,0,0,0.1)] transition-colors">
                      <p className="text-xs font-black text-white uppercase tracking-tight">{inc.name}</p>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-xs text-brand-green">
                      {formatCurrency(inc.amount, currency)}
                    </td>
                    <td className="px-8 py-4 text-right">
                       <p className="text-[10px] font-black text-white">{formatCurrency(inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity], currency)}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                          <button onClick={() => handleOpenModal(inc)} className="p-2 bg-navy-700 text-brand-primary hover:text-white rounded-lg shadow-sm border border-white/5 transition-colors">✎</button>
                          <button onClick={() => deleteIncome(inc.id)} className="p-2 bg-navy-700 text-rose-400 hover:text-rose-300 rounded-lg shadow-sm border border-white/5 transition-colors">✕</button>
                       </div>
                    </td>
                 </tr>
              ))}
              {((activeTab === 'expense' && budgetsWithAnalytics.length === 0) || (activeTab === 'income' && filteredState.incomes.length === 0)) && (
                 <tr>
                    <td colSpan={5} className="py-24 text-center text-brand-muted italic text-[10px] uppercase tracking-widest">
                       No {activeTab} records found. Use "Load Template" to start.
                    </td>
                 </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-navy-900/80 backdrop-blur-md p-4">
          <div className="glass-panel w-full max-w-xl rounded-[3rem] p-8 md:p-12 border border-white/10 shadow-2xl animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto custom-scrollbar">
            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-10">
               {activeTab === 'expense' ? 'Target Protocol' : 'Income Stream Definition'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">{activeTab === 'expense' ? 'Category Head' : 'Source Name'}</label>
                <input required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white uppercase focus:ring-4 focus:ring-brand-primary/20" placeholder={activeTab === 'expense' ? 'E.G. GROCERIES' : 'E.G. SALARY'} value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-6">
                 {activeTab === 'expense' && (
                    <div className="space-y-2">
                        <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Budget Span</label>
                        <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none cursor-pointer" value={formData.periodType} onChange={e => {
                        const dates = getPeriodDates(e.target.value as any);
                        setFormData({...formData, periodType: e.target.value as any, startDate: dates.start, endDate: dates.end});
                        }}><option value="Financial">Financial Year</option><option value="Calendar">Calendar Year</option><option value="Custom">Custom Range</option></select>
                    </div>
                 )}
                 <div className="space-y-2">
                    <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Frequency</label>
                    <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none cursor-pointer" value={formData.frequency} onChange={e => setFormData({...formData, frequency: e.target.value as Periodicity})}>
                       {FREQUENCIES.map(f => <option key={f} value={f}>{f}</option>)}
                    </select>
                 </div>
              </div>

              <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">{activeTab === 'expense' ? 'Monthly Payment Day (Ref)' : 'Expected Receipt Date'}</label>
                <input type="date" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl outline-none font-black text-xs text-white focus:ring-4 focus:ring-brand-primary/20" value={activeTab === 'expense' ? formData.dueDate : formData.dateOfReceipt} onChange={e => setFormData(activeTab === 'expense' ? {...formData, dueDate: e.target.value} : {...formData, dateOfReceipt: e.target.value})} />
              </div>

              <div className={`space-y-4 p-8 rounded-[2rem] border ${activeTab === 'expense' ? 'bg-brand-primary/10 border-brand-primary/20' : 'bg-brand-green/10 border-brand-green/20'}`}>
                <div className="space-y-2">
                  <label className={`text-[9px] font-black uppercase tracking-widest block ml-2 ${activeTab === 'expense' ? 'text-brand-primary' : 'text-brand-green'}`}>Amount per {formData.frequency}</label>
                  <input required type="number" step="any" className={`w-full p-4 bg-navy-900 border rounded-2xl outline-none font-black text-2xl focus:ring-4 focus:ring-brand-primary/20 transition-all ${activeTab === 'expense' ? 'border-brand-primary/30 text-brand-primary' : 'border-brand-green/30 text-brand-green'}`} value={formData.amountPerPeriod} onChange={e => setFormData({...formData, amountPerPeriod: Number(e.target.value)})} />
                </div>
                {activeTab === 'expense' && (
                    <div className="flex justify-between items-center text-right pt-2 border-t border-brand-primary/20">
                    <div className="text-left">
                        <p className="text-[8px] font-black text-brand-muted uppercase">Multiplier</p>
                        <p className="text-[10px] font-black text-white uppercase mt-0.5">x{ANNUAL_MULTIPLIERS[formData.frequency as Periodicity]} (Annual)</p>
                    </div>
                    <div>
                        <p className="text-[8px] font-black text-brand-primary uppercase tracking-widest">Calculated Annual Goal</p>
                        <p className="text-2xl font-black text-brand-primary">{formatCurrency(formData.amount || 0, currency)}</p>
                    </div>
                    </div>
                )}
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-navy-700 text-brand-muted font-black text-[10px] uppercase rounded-2xl hover:text-white transition-colors">Abort</button>
                <button type="submit" className={`flex-[2] py-5 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl hover:opacity-90 transition-all active:scale-95 ${activeTab === 'expense' ? 'bg-brand-gradient shadow-purple-500/20' : 'bg-brand-green shadow-green-500/20'}`}>Establish {activeTab === 'expense' ? 'Goal' : 'Stream'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetPlanner;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth, calculateAllocatedExpense, calculateAllocatedExpenseBreakdown } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time' | 'custom';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');
  const [customStart, setCustomStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().split('T')[0]);
  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity', 'P_L_Income', 'P_L_Expense']);
  const currency = filteredState.profile.currency;

  const { start, end } = useMemo(() => {
    const now = new Date();
    let s = new Date(0);
    let e = new Date();
    if (activePeriod === 'current_month') {
      s = new Date(now.getFullYear(), now.getMonth(), 1);
      e = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);
    } else if (activePeriod === 'last_90_days') {
      s = new Date(); s.setDate(now.getDate() - 90);
    } else if (activePeriod === 'ytd') {
      s = new Date(now.getFullYear(), 0, 1);
    } else if (activePeriod === 'custom') {
      s = new Date(customStart);
      e = new Date(customEnd);
      e.setHours(23, 59, 59, 999);
    }
    return { start: s, end: e };
  }, [activePeriod, customStart, customEnd]);

  const incomeBreakdown = useMemo(() => {
    const breakdown: Record<string, number> = {};
    (filteredState.transactions || [])
      .filter(t => t.type === 'Income' && new Date(t.date) >= start && new Date(t.date) <= end)
      .forEach(t => {
        const nature = t.nature || 'General Income';
        breakdown[nature] = (breakdown[nature] || 0) + t.amount;
      });
    return breakdown;
  }, [filteredState.transactions, start, end]);

  const expenseBreakdown = useMemo(() => {
    return calculateAllocatedExpenseBreakdown(filteredState.transactions || [], start, end);
  }, [filteredState.transactions, start, end]);

  const totalIncome = (Object.values(incomeBreakdown) as number[]).reduce((a, b) => a + b, 0);
  const totalExpense = (Object.values(expenseBreakdown) as number[]).reduce((a, b) => a + b, 0);
  const netSurplus = totalIncome - totalExpense;

  const { netWorth } = calculateNetWorth(filteredState);
  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: any[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    const processAccount = (id: string, name: string, balance: number, classification: AccountClassification, source: string) => {
      let cls = classification;
      let val = balance;
      if (source === 'Bank' || source === 'Wallet') cls = 'Current Asset';
      if (val < 0 && (cls === 'Current Asset' || cls === 'Non-Current Asset')) { cls = 'Current Liability'; val = Math.abs(val); }

      data[cls].total += val;
      data[cls].items.push({ id, name, value: val, source });
    };

    filteredState.banks.forEach(b => processAccount(b.id, b.name, b.balance, b.classification || 'Current Asset', 'Bank'));
    filteredState.wallets.forEach(w => processAccount(w.id, w.name, w.balance, w.classification || 'Current Asset', 'Wallet'));
    filteredState.cards.forEach(c => processAccount(c.id, c.lenderName, c.balance, c.classification || 'Current Liability', 'Credit'));
    filteredState.assets.forEach(a => processAccount(a.id, a.name, a.value, a.classification || 'Non-Current Asset', 'Manual Asset'));
    filteredState.liabilities.forEach(l => processAccount(l.id, l.name, l.amount, l.classification || 'Current Liability', 'Manual Debt'));

    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital Account', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });
    return data;
  }, [filteredState, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-xl md:text-3xl font-black text-white tracking-tight uppercase">Audit Statements</h2>
          <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-1">Verified Performance & Position</p>
        </div>
        <div className="flex flex-wrap items-center gap-1 bg-navy-800 p-1 border border-white/5 rounded-full shadow-sm">
          {(['current_month', 'all_time', 'custom'] as Period[]).map(p => (
            <button key={p} onClick={() => setActivePeriod(p)} className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase transition-all ${activePeriod === p ? 'bg-brand-gradient text-white shadow-md' : 'text-brand-muted hover:text-white'}`}>
              {p.replace('_', ' ')}
            </button>
          ))}
        </div>
      </div>

      {activePeriod === 'custom' && (
        <div className="bg-navy-800 p-6 rounded-[2rem] border border-white/5 soft-shadow flex flex-col md:flex-row gap-4 items-center animate-in slide-in-from-top-4">
           <div className="flex-1 space-y-1 w-full">
             <label className="text-[8px] font-black text-brand-muted uppercase tracking-widest ml-1">Range Start</label>
             <input type="date" className="w-full p-3 bg-navy-900 border border-white/10 rounded-xl text-xs text-white font-black outline-none" value={customStart} onChange={e => setCustomStart(e.target.value)} />
           </div>
           <div className="flex-1 space-y-1 w-full">
             <label className="text-[8px] font-black text-brand-muted uppercase tracking-widest ml-1">Range End</label>
             <input type="date" className="w-full p-3 bg-navy-900 border border-white/10 rounded-xl text-xs text-white font-black outline-none" value={customEnd} onChange={e => setCustomEnd(e.target.value)} />
           </div>
        </div>
      )}

      {/* Summary P&L Card */}
      <section className="bg-navy-800 md:rounded-[2.5rem] p-10 md:p-12 text-white shadow-xl relative overflow-hidden group border border-white/5">
        <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/5 pointer-events-none uppercase">AUDIT</div>
        <div className="flex flex-col md:flex-row justify-between items-center gap-8 relative z-10">
          <div className="text-center md:text-left">
            <h3 className="text-[10px] font-black tracking-[0.3em] text-brand-primary uppercase mb-2">Profit & Loss Summary</h3>
            <p className={`text-4xl md:text-6xl font-black tracking-tighter ${netSurplus >= 0 ? 'text-brand-green' : 'text-rose-400'}`}>
              {formatCurrency(netSurplus, currency)}
            </p>
            <p className="text-[9px] font-black text-white/30 uppercase tracking-widest mt-3">Period Result Verification: PASSED</p>
          </div>
          <div className="grid grid-cols-2 gap-8 text-center md:text-right border-l border-white/10 pl-8">
            <div><p className="text-[9px] font-black text-brand-muted uppercase mb-1">Total Income</p><p className="text-xl font-black text-brand-green">{formatCurrency(totalIncome, currency)}</p></div>
            <div><p className="text-[9px] font-black text-brand-muted uppercase mb-1">Amortized Expense</p><p className="text-xl font-black text-rose-400">{formatCurrency(totalExpense, currency)}</p></div>
          </div>
        </div>
      </section>

      {/* Detailed P&L Breakdown */}
      <section className="bg-navy-800 border md:rounded-[2.5rem] border-white/5 overflow-hidden soft-shadow">
        <div className="bg-navy-900/50 p-6 md:p-10 border-b border-white/5">
           <h3 className="text-sm font-black tracking-[0.2em] text-white uppercase">Performance Audit Breakdown</h3>
           <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest mt-1">Nature-wise categorization of wealth movement</p>
        </div>
        <div className="divide-y divide-white/5">
          {/* Income Drilldown */}
          <div className="overflow-hidden">
             <button onClick={() => toggleHead('P_L_Income')} className="w-full flex justify-between items-center p-6 md:p-8 hover:bg-navy-700/30 transition-colors">
                <div className="flex items-center gap-4">
                   <div className="w-10 h-10 bg-brand-green/20 text-brand-green rounded-xl flex items-center justify-center text-xl shadow-sm">💰</div>
                   <div className="text-left">
                      <span className="text-[10px] font-black text-white uppercase tracking-widest">Gross Income Items</span>
                      <p className="text-[9px] text-brand-muted font-bold uppercase mt-0.5">Verified Credits to Vault</p>
                   </div>
                </div>
                <span className="text-lg font-black text-brand-green">{formatCurrency(totalIncome, currency)}</span>
             </button>
             {expandedHeads.includes('P_L_Income') && (
               <div className="px-8 md:px-12 pb-8 space-y-3 animate-in slide-in-from-top-2">
                  {Object.entries(incomeBreakdown).map(([nature, amount]) => (
                    <div key={nature} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0">
                       <span className="text-[11px] font-black text-brand-muted uppercase tracking-tight">{nature}</span>
                       <span className="text-[11px] font-black text-white">{formatCurrency(amount as number, currency)}</span>
                    </div>
                  ))}
                  {Object.keys(incomeBreakdown).length === 0 && <p className="text-[9px] font-black text-white/30 uppercase italic py-4">No income records in range</p>}
               </div>
             )}
          </div>

          {/* Expense Drilldown */}
          <div className="overflow-hidden">
             <button onClick={() => toggleHead('P_L_Expense')} className="w-full flex justify-between items-center p-6 md:p-8 hover:bg-navy-700/30 transition-colors">
                <div className="flex items-center gap-4">
                   <div className="w-10 h-10 bg-rose-500/20 text-rose-400 rounded-xl flex items-center justify-center text-xl shadow-sm">💸</div>
                   <div className="text-left">
                      <span className="text-[10px] font-black text-white uppercase tracking-widest">Amortized Expenses</span>
                      <p className="text-[9px] text-brand-muted font-bold uppercase mt-0.5">Strategic Consumption Audit</p>
                   </div>
                </div>
                <span className="text-lg font-black text-rose-400">{formatCurrency(totalExpense, currency)}</span>
             </button>
             {expandedHeads.includes('P_L_Expense') && (
               <div className="px-8 md:px-12 pb-8 space-y-3 animate-in slide-in-from-top-2">
                  {Object.entries(expenseBreakdown).map(([nature, amount]) => (
                    <div key={nature} className="flex justify-between items-center py-2 border-b border-white/5 last:border-0">
                       <span className="text-[11px] font-black text-brand-muted uppercase tracking-tight">{nature}</span>
                       <span className="text-[11px] font-black text-white">{formatCurrency(amount as number, currency)}</span>
                    </div>
                  ))}
                  {Object.keys(expenseBreakdown).length === 0 && <p className="text-[9px] font-black text-white/30 uppercase italic py-4">No expense records in range</p>}
               </div>
             )}
          </div>

          {/* Surplus/Deficit Reconciliation */}
          <div className={`p-6 md:p-10 flex justify-between items-center ${netSurplus >= 0 ? 'bg-brand-green/10' : 'bg-rose-500/10'}`}>
             <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl shadow-sm ${netSurplus >= 0 ? 'bg-brand-green text-white' : 'bg-rose-600 text-white'}`}>
                  {netSurplus >= 0 ? '📈' : '📉'}
                </div>
                <div className="text-left">
                   <span className="text-[11px] font-black text-white uppercase tracking-widest">Net Surplus / (Deficit)</span>
                   <p className={`text-[8px] font-black uppercase tracking-widest mt-0.5 ${netSurplus >= 0 ? 'text-brand-green' : 'text-rose-400'}`}>
                      Final Period Settlement
                   </p>
                </div>
             </div>
             <span className={`text-2xl font-black ${netSurplus >= 0 ? 'text-brand-green' : 'text-rose-400'}`}>
                {formatCurrency(netSurplus, currency)}
             </span>
          </div>
        </div>
      </section>

      {/* Balance Sheet section */}
      <section className="bg-navy-800 border md:rounded-[2.5rem] border-white/5 overflow-hidden soft-shadow">
        <div className="bg-navy-900/50 p-10 border-b border-white/5 flex justify-between items-center">
          <div>
             <h3 className="text-sm font-black tracking-widest uppercase mb-1 text-white">Financial Position (Balance Sheet)</h3>
             <p className="text-4xl font-black tracking-tighter text-brand-primary">{formatCurrency(netWorth, currency)}</p>
          </div>
          <span className="px-4 py-1.5 bg-brand-primary text-white rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg">Static Audit Verified</span>
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-white/5">
           <div className="p-8 space-y-4">
              <h4 className="text-[10px] font-black text-brand-muted uppercase tracking-widest mb-6">Asset Controls</h4>
              {['Current Asset', 'Non-Current Asset'].map(head => (
                <div key={head} className="border border-white/5 rounded-2xl overflow-hidden">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-5 bg-navy-900/30 hover:bg-navy-700/50 transition-colors">
                    <span className="text-[10px] font-black text-white uppercase tracking-tight">{head}</span>
                    <span className="text-xs font-black text-white">{formatCurrency(heads[head as AccountClassification].total, currency)}</span>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="p-4 space-y-2 bg-navy-900 animate-in slide-in-from-top-2">
                       {heads[head as AccountClassification].items.map(item => (
                         <div key={item.id} className="flex justify-between text-[11px] font-bold text-brand-muted">
                           <span className="uppercase">{item.name}</span>
                           <span>{formatCurrency(item.value, currency)}</span>
                         </div>
                       ))}
                    </div>
                  )}
                </div>
              ))}
           </div>
           <div className="p-8 space-y-4">
              <h4 className="text-[10px] font-black text-brand-muted uppercase tracking-widest mb-6">Equities & Obligations</h4>
              {['Current Liability', 'Non-Current Liability', 'Equity'].map(head => (
                <div key={head} className="border border-white/5 rounded-2xl overflow-hidden">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-5 bg-navy-900/30 hover:bg-navy-700/50 transition-colors">
                    <span className="text-[10px] font-black text-white uppercase tracking-tight">{head}</span>
                    <span className="text-xs font-black text-white">{formatCurrency(heads[head as AccountClassification].total, currency)}</span>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="p-4 space-y-2 bg-navy-900 animate-in slide-in-from-top-2">
                       {heads[head as AccountClassification].items.map(item => (
                         <div key={item.id} className="flex justify-between text-[11px] font-bold text-brand-muted">
                           <span className="uppercase">{item.name}</span>
                           <span>{formatCurrency(item.value, currency)}</span>
                         </div>
                       ))}
                    </div>
                  )}
                </div>
              ))}
           </div>
        </div>
      </section>
    </div>
  );
};

