        ...profile,
        googleDriveConfig: {
          isConnected: false,
          linkedEmail: '',
          folderId: '',
          folderName: '',
        }
      });
    }
  };

  const togglePermission = (id: string, key: keyof MemberPermissions) => {
    const member = profile.familyMembers.find(m => m.id === id);
    if (member) {
      updateMemberPermissions(id, { ...member.permissions, [key]: !member.permissions[key] });
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20 px-3 md:px-0 mx-auto">
      <div className="bg-navy-800 md:rounded-[3rem] border border-white/5 soft-shadow overflow-hidden">
        <div className="h-40 bg-brand-gradient p-8 flex items-end relative">
           <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/10 tracking-tighter uppercase">MF</div>
           <div className="w-24 h-24 bg-navy-800 p-1 translate-y-12 z-10 shadow-xl rounded-[2rem]">
               <div className="w-full h-full bg-navy-900 flex items-center justify-center text-4xl font-black text-brand-primary rounded-2xl uppercase">{profile?.name?.charAt(0) || '?'}</div>
           </div>
        </div>
        <div className="px-8 pt-16 pb-10">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="text-3xl font-black text-white tracking-tight uppercase">{profile?.name}</h3>
              <p className="text-xs font-black text-brand-primary uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4 p-6 bg-navy-900 border border-white/5 rounded-[2rem]">
             <div><p className="text-[8px] font-black text-brand-muted uppercase tracking-widest mb-1">Local Identity</p><p className="text-xs font-black text-white uppercase">{profile?.city}, {profile?.country}</p></div>
             <div><p className="text-[8px] font-black text-brand-muted uppercase tracking-widest mb-1">Audit Currency</p><p className="text-xs font-black text-brand-primary uppercase">{profile?.currency}</p></div>
          </div>
        </div>
      </div>

      <div className="bg-navy-800 p-8 rounded-[3rem] border border-white/5 soft-shadow overflow-hidden">
        <div className="flex justify-between items-center mb-8">
           <h4 className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Data Management</h4>
        </div>

        <div className="space-y-8">
           <div className="p-6 bg-navy-900 border border-white/5 rounded-[2rem] space-y-6">
              <div className="flex justify-between items-center">
                 <div>
                    <p className="text-sm font-black text-white uppercase tracking-tight">Data Backup</p>
                    <p className="text-[8px] font-bold text-brand-muted uppercase mt-1">
                       Last Backup: {profile.lastBackupDate ? new Date(profile.lastBackupDate).toLocaleDateString() : 'Never'}
                    </p>
                 </div>
                 <button onClick={exportData} className="px-5 py-3 bg-brand-gradient text-white rounded-2xl text-[9px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">
                    Download JSON
                 </button>
              </div>

              <div className="space-y-2">
                 <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Automated Frequency (Preference)</label>
                 <select 
                    className="w-full p-4 bg-navy-800 border border-white/10 rounded-2xl outline-none font-black text-xs text-white cursor-pointer"
