              <button onClick={() => { if(confirm("Are you sure? This will wipe all application data and log you out immediately.")) wipeData(); }} className="px-6 py-3 bg-navy-800 text-rose-400 border border-rose-500/30 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-rose-500 hover:text-white transition-all shadow-sm">
