};

export default Profile;

import React from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { getAnnualPeriodStart, getAnnualPeriodEnd, getBillingCycleDates, getPreviousBillingCycleDates } from '../utils/calculations';
import { CreditCard } from '../types';

const Rewards: React.FC = () => {
  const { filteredState, state } = useFinance();
  const currency = filteredState.profile.currency;
  const cards = filteredState.cards || [];

  const getCycleSpend = (cardId: string, start: Date, end: Date) => {
    return state.transactions
      .filter(t => t.accountId === cardId && t.type === 'Expense' && new Date(t.date) >= start && new Date(t.date) <= end)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const calculateAnnualProgress = (card: CreditCard) => {
    if (!card.anniversaryDate) return { spend: 0, startDate: null, endDate: null };
    const start = getAnnualPeriodStart(card.anniversaryDate);
    const end = getAnnualPeriodEnd(start);
    const spend = state.transactions
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= start && new Date(t.date) <= end)
      .reduce((acc, t) => acc + t.amount, 0);
    return { spend, start, end };
  };

  const now = new Date();
  const currentMonthName = now.toLocaleString('default', { month: 'long' });

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-white tracking-tight uppercase">Privilege Vault</h2>
          <p className="text-[10px] font-black text-brand-muted uppercase tracking-[0.2em] mt-2">Active Credit Benefit Applicability</p>
        </div>
        <div className="bg-brand-primary px-6 py-3 rounded-2xl text-white shadow-xl shadow-purple-500/20">
          <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Status Dashboard</p>
          <p className="text-sm font-black uppercase tracking-tight">{currentMonthName} {now.getFullYear()}</p>
        </div>
      </div>

      {cards.length === 0 ? (
        <div className="py-24 text-center bg-navy-800 border border-dashed border-white/10 rounded-[2.5rem]">
          <div className="text-4xl mb-4">💳</div>
          <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest">No active credit cards identified in vault</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-12">
          {cards.map(card => {
            const billingDay = card.billingDay || 1;
            const currentCycle = getBillingCycleDates(billingDay);
            const prevCycle = getPreviousBillingCycleDates(billingDay);

            const currentCycleSpend = getCycleSpend(card.id, currentCycle.start, currentCycle.end);
            const prevCycleSpend = getCycleSpend(card.id, prevCycle.start, prevCycle.end);
            const annual = calculateAnnualProgress(card);

            const loungeSpendThreshold = card.loungeAccess?.spendLimit || 0;

            const isLoungeUnlockedNow = prevCycleSpend >= loungeSpendThreshold;

            const nextCycleProgress = loungeSpendThreshold > 0 ? Math.min(100, (currentCycleSpend / loungeSpendThreshold) * 100) : 100;
            const isQualifiedForNextCycle = currentCycleSpend >= loungeSpendThreshold;

            const formatRange = (start: Date, end: Date) => {
              return `${start.toLocaleDateString('default', { day: 'numeric', month: 'short' })} - ${end.toLocaleDateString('default', { day: 'numeric', month: 'short' })}`;
            };

            return (
              <div key={card.id} className="bg-navy-800 border border-white/5 rounded-[3rem] shadow-sm overflow-hidden flex flex-col lg:flex-row transition-all hover:shadow-md soft-shadow">
                {/* Left Section: Identity & Static Perks */}
                <div className="p-8 lg:w-1/3 bg-navy-900 text-white flex flex-col justify-between relative overflow-hidden border-r border-white/5">
                  <div className="absolute top-0 right-0 p-4 text-6xl opacity-5 font-black">CREDIT</div>
                  <div className="relative z-10">
                    <span className="text-[8px] font-black text-brand-primary uppercase tracking-widest block mb-2">{card.classification || 'Privilege Line'}</span>
                    <h3 className="text-2xl font-black tracking-tight uppercase leading-none">{card.lenderName}</h3>
                    <p className="text-[10px] font-mono text-white/40 mt-2 tracking-[0.25em]">•••• {card.last4}</p>
                    <div className="mt-4 bg-white/5 p-3 rounded-xl border border-white/10 inline-block">
                       <p className="text-[7px] font-black text-brand-muted uppercase tracking-widest">Billing Cycle</p>
                       <p className="text-[10px] font-black">{billingDay} to {billingDay === 1 ? 'End' : billingDay - 1}</p>
                    </div>
                  </div>

                  <div className="mt-12 space-y-6 relative z-10">
                    <div>
                      <p className="text-[8px] font-black text-white/30 uppercase tracking-widest mb-3">Core Privileges (No Spend Required)</p>
                      <div className="flex flex-wrap gap-2">
                        {card.offers.movie && <span className="bg-white/5 px-2.5 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-tight border border-white/5">🎬 1+1 Movies</span>}
                        {card.offers.dining && <span className="bg-white/5 px-2.5 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-tight border border-white/5">🍽️ Dining</span>}
                        {card.fuelSurchargeWaiver && <span className="bg-white/5 px-2.5 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-tight border border-white/5">⛽ Fuel Waiver</span>}
                        {card.cashbackPct && <span className="bg-brand-primary px-2.5 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-tight">{card.cashbackPct}% CB</span>}
                      </div>
                    </div>
                  </div>
                </div>

                {/* Right Section: Conditional Performance Stats */}
                <div className="p-8 lg:flex-1 grid grid-cols-1 md:grid-cols-2 gap-10">

                  {/* Monthly Spend-Based Perks (Lounge) */}
                  <div className="space-y-8">
                    <div className="space-y-4">
                      <div className="flex justify-between items-start">
                        <div className="flex flex-col">
                          <h4 className="text-[11px] font-black text-white uppercase tracking-widest">Active Benefits (This Cycle)</h4>
                          <p className="text-[8px] font-bold text-brand-muted uppercase mt-0.5 italic">{formatRange(currentCycle.start, currentCycle.end)}</p>
                        </div>
                        {isLoungeUnlockedNow ? (
                          <span className="bg-brand-green/20 text-brand-green text-[8px] font-black px-3 py-1 rounded-full uppercase border border-brand-green/30">Verified: Active</span>
                        ) : (
                          <span className="bg-rose-500/20 text-rose-400 text-[8px] font-black px-3 py-1 rounded-full uppercase border border-rose-500/30">Locked This Cycle</span>
                        )}
                      </div>

                      <div className="p-6 bg-navy-900 border border-white/5 rounded-[2rem] flex items-center justify-between group">
                         <div className="space-y-1">
                            <p className="text-base font-black text-white uppercase leading-none">
                              {isLoungeUnlockedNow ? `${card.loungeAccess?.count || 0} Lounge Entries` : 'Access Restricted'}
                            </p>
                            <p className="text-[8px] font-bold text-brand-muted uppercase tracking-widest mt-1">Earned from Prev Cycle: {formatCurrency(prevCycleSpend, currency)}</p>
                            <p className="text-[7px] text-white/30 italic">({formatRange(prevCycle.start, prevCycle.end)})</p>
                         </div>
                         <div className={`text-3xl transition-transform group-hover:scale-110 ${isLoungeUnlockedNow ? 'grayscale-0' : 'grayscale opacity-30'}`}>
                           {isLoungeUnlockedNow ? '✨' : '🔒'}
                         </div>
                      </div>
                    </div>

                    {/* Next Cycle Qualification */}
                    <div className="space-y-4 pt-6 border-t border-white/5">
                      <div className="flex justify-between items-end">
                        <div className="flex flex-col">
                          <h4 className="text-[10px] font-black text-brand-primary uppercase tracking-widest">Qualifying for Next Cycle</h4>
                          <p className="text-[8px] font-bold text-brand-muted uppercase mt-0.5">Threshold Target Progress</p>
                        </div>
                        <p className="text-[10px] font-black text-white">{formatCurrency(currentCycleSpend, currency)} / {formatCurrency(loungeSpendThreshold, currency)}</p>
                      </div>
                      <div className="w-full h-2.5 bg-navy-900 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ${isQualifiedForNextCycle ? 'bg-brand-green shadow-[0_0_15px_rgba(108,192,112,0.3)]' : 'bg-brand-primary'}`}
                          style={{ width: `${nextCycleProgress}%` }}
                        ></div>
                      </div>
                      {isQualifiedForNextCycle ? (
                        <div className="flex items-center gap-2 bg-brand-green/10 p-3 rounded-xl border border-brand-green/20 animate-in slide-in-from-left-2">
                           <span className="text-brand-green text-sm">✔</span>
                           <p className="text-[8px] font-black text-brand-green uppercase tracking-tight">Threshold met. Benefits will be available in next cycle.</p>
                        </div>
                      ) : (
                        <div className="flex justify-between items-center">
                          <p className="text-[8px] font-black text-brand-muted uppercase">Need {formatCurrency(loungeSpendThreshold - currentCycleSpend, currency)} more</p>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Annual Milestone Progression */}
                  <div className="space-y-4">
                    <div className="flex justify-between items-start">
                      <div className="flex flex-col">
                        <h4 className="text-[11px] font-black text-white uppercase tracking-widest">Annual Milestone Tracker</h4>
                        <p className="text-[8px] font-bold text-brand-muted uppercase mt-0.5">Yearly Fee Waiver/Rewards</p>
                      </div>
                    </div>

                    <div className="bg-brand-primary/10 p-8 rounded-[2.5rem] border border-brand-primary/20 space-y-8 relative overflow-hidden group">
                      <div className="absolute bottom-0 right-0 p-6 text-6xl opacity-5 grayscale group-hover:rotate-12 transition-transform">🏆</div>

                      <div className="space-y-1">
                        <p className="text-[8px] font-black uppercase text-brand-primary tracking-[0.2em]">Target Spend Milestone</p>
                        <p className="text-lg font-black text-white tracking-tight">
                          {card.annualLimit ? formatCurrency(card.annualLimit, currency) : 'No Limit Defined'}
                        </p>
                      </div>

                      <div className="space-y-4 relative z-10">
                        <div className="flex justify-between items-end">
                          <div className="flex flex-col">
                            <p className="text-[8px] font-black uppercase text-brand-muted tracking-[0.1em]">Accumulated Year-to-Date</p>
                            {annual.start && annual.end && (
                              <p className="text-[7px] font-black text-brand-primary/50 uppercase mt-0.5">
                                Cycle: {annual.start.toLocaleDateString()} - {annual.end.toLocaleDateString()}
                              </p>
                            )}
                          </div>
                          <p className="text-sm font-black text-brand-primary">{formatCurrency(annual.spend, currency)}</p>
                        </div>
                        <div className="w-full h-2 bg-navy-900 border border-white/5 rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-brand-primary transition-all duration-1000"
                            style={{ width: `${card.annualLimit ? Math.min(100, (annual.spend / card.annualLimit) * 100) : 100}%` }}
                          ></div>
                        </div>
                        {card.annualLimit && annual.spend < card.annualLimit && (
                           <p className="text-[7px] font-black text-brand-muted uppercase text-right tracking-widest">
                             {((annual.spend / card.annualLimit) * 100).toFixed(1)}% Completed
                           </p>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Performance Vouchers */}
                  {(card.otherBenefits || []).length > 0 && (
                    <div className="md:col-span-2 space-y-6 pt-8 border-t border-white/5">
                      <div className="flex justify-between items-center">
                        <h4 className="text-[10px] font-black text-white uppercase tracking-widest">🎯 Targeted Achievement Rewards</h4>
                        <span className="text-[7px] font-black text-brand-muted uppercase italic">Benefits applied in next billing cycle</span>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        {card.otherBenefits?.map((benefit, idx) => (
                          <div key={idx} className="flex items-center justify-between p-5 bg-navy-900 border border-white/5 rounded-3xl group hover:border-brand-primary/30 hover:shadow-sm transition-all">
                             <div className="space-y-1">
                                <p className="text-[10px] font-black text-white uppercase tracking-tight leading-tight">{benefit.benefitName}</p>
                                <p className="text-[8px] font-bold text-brand-muted uppercase">Rule: {benefit.condition}</p>
                             </div>
                             <div className="text-xl opacity-20 group-hover:opacity-100 transition-all group-hover:rotate-12">🎁</div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default Rewards;

import React, { useMemo, useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Periodicity } from '../types';
import { ANNUAL_MULTIPLIERS } from '../utils/calculations';

const getBudgetDueDateForWindow = (dueDateStr: string | undefined, windowStart: Date) => {
  if (!dueDateStr) return null;
  const refDate = new Date(dueDateStr);
  if (isNaN(refDate.getTime())) return null;

  const day = refDate.getDate();
  const targetDate = new Date(windowStart.getFullYear(), windowStart.getMonth(), day);

  if (targetDate.getMonth() !== windowStart.getMonth()) {
    targetDate.setDate(0); 
  }
  return targetDate;
};

const FiscalSentinel: React.FC = () => {
  const { filteredState } = useFinance();
  const currency = filteredState.profile.currency;

  const [viewDate, setViewDate] = useState(new Date());

  const calendarData = useMemo(() => {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const windowStart = new Date(year, month, 1);

    // Calculate Previous Month Total Income
    const prevMonthStart = new Date(year, month - 1, 1);
    const prevMonthEnd = new Date(year, month, 0, 23, 59, 59);
    const prevMonthIncome = (filteredState.transactions || [])
      .filter(t => t.type === 'Income' && new Date(t.date) >= prevMonthStart && new Date(t.date) <= prevMonthEnd)
      .reduce((acc, t) => acc + t.amount, 0);

    const dailyThresholdWarning = prevMonthIncome * 0.2;
    const cumulativeBlowoutThreshold = prevMonthIncome * 0.5;

    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const dailyMap: Record<number, { amount: number, items: { name: string, amount: number }[], hasScheduledDue: boolean }> = {};
    const dailyActualSpent: Record<number, number> = {};

    for (let d = 1; d <= daysInMonth; d++) {
      dailyMap[d] = { amount: 0, items: [], hasScheduledDue: false };
      dailyActualSpent[d] = 0;
    }

    (filteredState.budgets || []).forEach(b => {
      const windowDueDate = getBudgetDueDateForWindow(b.dueDate, windowStart);
      if (windowDueDate && windowDueDate.getMonth() === month) {
        const day = windowDueDate.getDate();
        const amountPerFreq = b.amount / ANNUAL_MULTIPLIERS[b.frequency];
        if (dailyMap[day]) {
          dailyMap[day].amount += amountPerFreq;
          dailyMap[day].hasScheduledDue = true;
          dailyMap[day].items.push({ name: b.category, amount: amountPerFreq });
        }
      }
    });

    (filteredState.cards || []).forEach(c => {
      if (c.dueDate) {
        const refDate = new Date(c.dueDate);
        const day = refDate.getDate();
        if (dailyMap[day]) {
          const bal = Math.abs(c.balance);
          if (refDate.getMonth() === month && refDate.getFullYear() === year) {
             dailyMap[day].amount += bal;
             dailyMap[day].items.push({ name: c.lenderName, amount: bal });
          }
          dailyMap[day].hasScheduledDue = true;
        }
      }
    });

    (filteredState.transactions || [])
      .filter(t => t.type === 'Expense' && new Date(t.date).getMonth() === month && new Date(t.date).getFullYear() === year)
      .forEach(t => {
        const d = new Date(t.date).getDate();
        if (dailyActualSpent[d] !== undefined) {
          dailyActualSpent[d] += t.amount;
        }
      });

    let cumulativeSum = 0;
    let firstBlowoutDay: number | null = null;
    for (let d = 1; d <= daysInMonth; d++) {
      cumulativeSum += dailyActualSpent[d];
      if (firstBlowoutDay === null && cumulativeSum > cumulativeBlowoutThreshold) {
        firstBlowoutDay = d;
      }
    }

    return { 
      dailyMap, 
      dailyThresholdWarning, 
      cumulativeBlowoutThreshold, 
      firstBlowoutDay, 
      year, 
      month, 
      daysInMonth, 
      prevMonthIncome,
      cumulativeTotalSpent: cumulativeSum 
    };
  }, [filteredState, viewDate]);

  const monthName = new Date(calendarData.year, calendarData.month).toLocaleString('default', { month: 'long' });
  const startDayOfWeek = new Date(calendarData.year, calendarData.month, 1).getDay();

  const handlePrevMonth = () => setViewDate(new Date(calendarData.year, calendarData.month - 1, 1));
  const handleNextMonth = () => setViewDate(new Date(calendarData.year, calendarData.month + 1, 1));

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 px-4 md:px-0">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-white tracking-tight uppercase">Fiscal Sentinel</h2>
          <p className="text-[10px] font-black text-brand-muted uppercase tracking-[0.2em] mt-2">Due Date Pressure Analysis Protocol</p>
        </div>
        <div className="flex items-center gap-2 bg-navy-800 p-1.5 rounded-2xl border border-white/5 shadow-sm">
          <button onClick={handlePrevMonth} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-navy-700 text-white transition-colors">←</button>
          <span className="px-6 text-[10px] font-black uppercase tracking-widest text-white">{monthName} {calendarData.year}</span>
          <button onClick={handleNextMonth} className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-navy-700 text-white transition-colors">→</button>
        </div>
      </div>

      <section className="bg-navy-800 p-6 md:p-10 rounded-[3rem] border border-white/5 soft-shadow animate-in fade-in duration-700">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-10">
          <div>
            <h3 className="text-xl font-black text-white uppercase tracking-tight">Liquidity Forecast</h3>
            <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-1">Status Report for {monthName} cycle</p>
          </div>
          <div className="flex flex-wrap items-center gap-6">
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-rose-500"></div>
               <span className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Blowout</span>
             </div>
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-amber-400"></div>
               <span className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Pressure</span>
             </div>
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-brand-green"></div>
               <span className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Safe</span>
             </div>
             <div className="flex items-center gap-2">
               <div className="w-3 h-3 rounded-full bg-brand-primary"></div>
               <span className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Due Date</span>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-7 gap-2 md:gap-4">
          {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
            <div key={d} className="text-center text-[9px] font-black text-brand-muted uppercase tracking-widest mb-4">{d}</div>
          ))}

          {Array.from({ length: startDayOfWeek }).map((_, i) => (
            <div key={`empty-${i}`} className="aspect-square bg-navy-900/50 rounded-2xl"></div>
          ))}

          {Array.from({ length: calendarData.daysInMonth }).map((_, i) => {
            const day = i + 1;
            const info = calendarData.dailyMap[day];
            const hasAmount = info.amount > 0;
            const hasScheduledDue = info.hasScheduledDue;
            const isBlowout = calendarData.firstBlowoutDay !== null && day >= calendarData.firstBlowoutDay;
            const isWarning = hasAmount && info.amount > calendarData.dailyThresholdWarning && !isBlowout;
            const isSafe = hasAmount && !isWarning && !isBlowout;

            return (
              <div 
                key={day} 
                className={`relative aspect-square flex flex-col items-center justify-center transition-all group cursor-default border-2 ${
                  isBlowout 
                    ? 'bg-rose-500 border-rose-500 text-white shadow-xl shadow-rose-900/50 rounded-full scale-105' 
                    : isWarning
                        ? 'bg-amber-400 border-amber-400 text-white shadow-xl shadow-amber-500/20 rounded-full scale-105'
                        : isSafe
                          ? 'bg-brand-green border-brand-green text-white shadow-xl shadow-green-500/20 rounded-full scale-105'
                          : hasScheduledDue
                            ? 'bg-brand-primary border-brand-secondary text-white shadow-xl shadow-purple-500/20 rounded-full scale-105 ring-4 ring-brand-primary/20'
                            : 'bg-navy-900 border-white/5 rounded-2xl hover:border-white/10 text-brand-muted'
                }`}
              >
                <div className={`w-full h-full flex flex-col items-center justify-center p-1`}>
                   <span className={`text-[10px] md:text-sm font-black ${isBlowout || isWarning || isSafe || hasScheduledDue ? 'text-white' : 'text-white/50'}`}>{day}</span>
                   {hasScheduledDue && (
                     <div className="mt-0.5 hidden md:block">
                        <p className={`text-[8px] font-black ${isBlowout || isWarning || isSafe ? 'text-white/70' : 'text-white/80'}`}>
                          {hasAmount ? formatCurrency(info.amount, currency) : 'DUE'}
                        </p>
                     </div>
                   )}
                </div>

                {hasScheduledDue && (
                  <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 w-48 bg-navy-900 text-white p-4 rounded-2xl shadow-2xl opacity-0 group-hover:opacity-100 pointer-events-none transition-all z-50 border border-white/10">
                     <p className="text-[8px] font-black text-brand-muted uppercase tracking-widest mb-2">Audit Detail • {day} {monthName}</p>
                     <div className="space-y-1.5">
                        {info.items.length > 0 ? info.items.map((item, idx) => (
                          <div key={idx} className="flex justify-between items-center text-[10px] font-black">
                            <span className="uppercase tracking-tight truncate max-w-[100px]">{item.name}</span>
                            <span>{item.amount > 0 ? formatCurrency(item.amount, currency) : 'Recurring'}</span>
                          </div>
                        )) : (
                          <p className="text-[10px] font-black text-brand-muted italic">Scheduled Occurrence</p>
                        )}
                     </div>
                     {hasAmount && (
                       <div className="mt-3 pt-3 border-t border-white/10 flex justify-between items-center text-[10px] font-black text-brand-primary">
                         <span>Total Due</span>
                         <span>{formatCurrency(info.amount, currency)}</span>
                       </div>
                     )}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <div className="mt-12 p-6 bg-navy-900 rounded-[2rem] border border-white/5 flex flex-col md:flex-row justify-between items-center gap-6">
           <div className="flex items-center gap-4">
             <div className="w-10 h-10 bg-white/10 rounded-xl shadow-sm flex items-center justify-center text-xl text-white">📊</div>
             <div>
               <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Basis Reference</p>
               <p className="text-sm font-black text-white uppercase">Prev. Month Income: <span className="text-brand-primary">{formatCurrency(calendarData.prevMonthIncome, currency)}</span></p>
             </div>
           </div>
           <div className="flex flex-col md:flex-row gap-8">
             <div className="text-right">
