        </div>
        <div className="bg-brand-primary px-6 py-3 rounded-2xl text-white shadow-xl shadow-purple-500/20">
           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Engine Status</p>
           <p className="text-sm font-black uppercase tracking-tight">Online & Ready</p>
        </div>
      </div>

      {/* Context Summary Card */}
      <div className="bg-navy-800 p-6 md:p-8 rounded-[2.5rem] border border-white/5 soft-shadow relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 text-8xl opacity-5 font-black grayscale select-none text-white">⚖️</div>

        <h3 className="text-sm font-black text-white uppercase tracking-widest mb-6 relative z-10">Active Context Snapshot</h3>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 relative z-10">
          <div>
            <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Monthly Surplus</p>
            <p className={`text-lg font-black ${rates.monthlySurplus >= 0 ? 'text-brand-green' : 'text-rose-400'}`}>
              {formatCurrency(rates.monthlySurplus, currency)}
            </p>
          </div>
          <div>
            <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Liquid Cash</p>
            <p className="text-lg font-black text-brand-primary">{formatCurrency(liquidity, currency)}</p>
          </div>
          <div>
            <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Net Worth</p>
            <p className="text-lg font-black text-white">{formatCurrency(netWorth.netWorth, currency)}</p>
