          <div>
            <p className="text-[9px] font-black text-brand-muted uppercase tracking-widest">Runway Status</p>
            <p className="text-lg font-black text-white">
               {rates.expense > 0 ? (liquidity / rates.expense).toFixed(1) + ' Months' : '∞'}
            </p>
          </div>
        </div>
      </div>

      {/* Input Section */}
      <div className="bg-navy-800 rounded-[2.5rem] border border-white/5 soft-shadow overflow-hidden flex flex-col md:flex-row">
        <div className="p-8 md:p-12 flex-1 space-y-6">
           <div className="space-y-2">
              <label className="text-[10px] font-black text-brand-muted uppercase tracking-widest block ml-2">What financial choice are you weighing?</label>
              <textarea 
                className="w-full h-32 p-6 bg-navy-900 border border-white/10 rounded-3xl outline-none font-black text-sm text-white resize-none focus:ring-4 focus:ring-brand-primary/20 transition-all placeholder:text-white/20"
                placeholder="e.g., Should I buy a new car for $25,000 given my current savings? Or, how can I increase my monthly surplus?"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
