                 <span>Compare Prices</span>
               </a>
           </div>
        </div>

        {/* Result Panel */}
        <div className="bg-navy-900 border-t md:border-t-0 md:border-l border-white/5 p-8 md:p-12 md:w-[45%] flex flex-col justify-center">
           {result ? (
             <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4">
                <div className="flex items-center gap-2 mb-2">
                   <div className="w-8 h-8 bg-brand-primary text-white rounded-lg flex items-center justify-center text-sm shadow-md">⚖️</div>
