             <div className="w-8 h-8 bg-brand-gradient text-white rounded-lg flex items-center justify-center font-black">M</div>
             <h1 className="text-xl font-bold tracking-tight text-white">MyFin</h1>
          </div>
        </div>
        <nav className="flex-1 px-4 py-4 space-y-1 overflow-y-auto custom-scrollbar">
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-brand-gradient text-white shadow-lg shadow-purple-500/20' : 'text-brand-muted hover:text-white hover:bg-white/5'}`}>
              <span className="text-xl">{item.icon}</span><span className="uppercase tracking-widest text-[11px]">{item.label}</span>
