          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto custom-scrollbar md:ml-72 pb-28 md:pb-0 bg-navy-900">
        <header className={`sticky top-0 bg-navy-900/90 backdrop-blur-xl border-b border-white/5 px-4 md:px-8 z-40 flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'}`}>
          <div className="flex items-center gap-4">
             {/* Mobile Logo / Back Button */}
             <div className="md:hidden flex items-center gap-2">
                {activeTab !== 'dashboard' ? (
                   <button onClick={() => setActiveTab('dashboard')} className="flex items-center gap-2 px-3 py-2 bg-navy-800 rounded-xl text-brand-primary active:scale-95 transition-transform">
                      <span className="text-sm font-bold">←</span>
                      <span className="text-[10px] font-black uppercase tracking-widest">Home</span>
                   </button>
                ) : (
                   <>
                      <div className="w-8 h-8 bg-brand-gradient rounded-lg flex items-center justify-center font-bold text-white text-xs">M</div>
                      <h1 className="text-lg font-black text-white tracking-tight">MyFin</h1>
                   </>
                )}
             </div>
          </div>

          <div className="flex items-center gap-3">
            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 bg-navy-800 rounded-2xl text-white flex items-center justify-center border border-white/5 transition-all hover:bg-navy-700">
               <span className="text-xl">🔔</span>
               {pendingApprovals.length > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-navy-800"></span>}
            </button>

            <button onClick={() => setActiveTab('rankings')} className={`relative w-10 h-10 rounded-2xl flex items-center justify-center border transition-all ${activeTab === 'rankings' ? 'bg-brand-gradient text-white border-transparent' : 'bg-navy-800 text-white border-white/5 hover:bg-navy-700'}`}>
               <span className="text-xl">🏆</span>
            </button>

            <div className="relative">
              <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="relative flex items-center justify-start px-4 py-2.5 bg-navy-800 rounded-2xl text-[9px] font-black uppercase tracking-widest border border-white/5 text-brand-primary shadow-lg pr-7">
                <span className="max-w-[100px] truncate">{getSelectionLabel()}</span>
                <span className="text-xs absolute top-0.5 right-1">👥</span>
              </button>
              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-navy-800 border border-white/10 rounded-[2rem] soft-shadow z-50 p-3 space-y-1">
                    <button onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isMeSelected ? 'bg-brand-gradient text-white shadow-lg' : 'hover:bg-navy-700 text-brand-muted'}`}>👤 My Vault</button>
                    <button onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${isAllSelected ? 'bg-brand-gradient text-white shadow-lg' : 'hover:bg-navy-700 text-brand-muted'}`}>🌍 Consolidated</button>
                    <div className="h-px bg-white/5 my-2"></div>
                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { setActiveMemberIds([m.id]); setShowMemberSelector(false); }} className={`w-full text-left px-5 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest ${activeMemberIds.includes(m.id) ? 'bg-brand-gradient text-white shadow-lg' : 'hover:bg-navy-700 text-brand-muted'}`}>
