          {mobileNavItems.map(item => (
            <button 
               key={item.id} 
               onClick={() => setActiveTab(item.id)}
               className={`flex flex-col items-center justify-center w-14 h-14 rounded-2xl transition-all active:scale-95 group ${activeTab === item.id ? 'text-brand-primary' : 'text-brand-muted hover:text-white'}`}
            >
               <span className={`text-2xl mb-1 transition-transform ${activeTab === item.id ? 'scale-110 -translate-y-1' : ''}`}>{item.icon}</span>
               {activeTab === item.id && <span className="w-1 h-1 rounded-full bg-brand-primary animate-in zoom-in"></span>}
               {activeTab !== item.id && <span className="text-[9px] font-black uppercase tracking-widest scale-0 group-hover:scale-100 transition-transform absolute -top-8 bg-navy-700 text-white px-2 py-1 rounded opacity-0 group-hover:opacity-100">{item.label}</span>}
            </button>
          ))}
      </nav>

    </div>
  );
};

export default Layout;

