  { id: 'app2', name: 'Google Pay', icon: '🌀', isEnabled: true, category: 'UPI' },
  { id: 'app3', name: 'Paytm', icon: '🅿️', isEnabled: false, category: 'UPI' },
  { id: 'app4', name: 'HDFC Mobile', icon: '🏦', isEnabled: true, category: 'Banking' },
  { id: 'app5', name: 'ICICI iMobile', icon: '🏰', isEnabled: false, category: 'Banking' },
  { id: 'app6', name: 'Zerodha', icon: '📈', isEnabled: true, category: 'Investment' },
  { id: 'app7', name: 'Binance', icon: '🪙', isEnabled: false, category: 'Investment' },
];

const DEFAULT_INCOME_TEMPLATE: { name: string, periodicity: Periodicity }[] = [
  { name: 'Salary', periodicity: 'Monthly' },
  { name: 'House Rent', periodicity: 'Monthly' }
];

const DEFAULT_EXPENSE_TEMPLATE: { category: string, frequency: Periodicity }[] = [
  { category: 'Rent', frequency: 'Monthly' },
  { category: 'Term Insurance Premium', frequency: 'Monthly' },
  { category: 'Bike Insurance Premium', frequency: 'Annually' },
  { category: 'Car Insurance Premium', frequency: 'Annually' },
  { category: 'Internet Recharge', frequency: 'Monthly' },
  { category: 'Maintenance bill', frequency: 'Monthly' },
  { category: 'Electricity Bill', frequency: 'Monthly' },
  { category: 'Health Insurance Premium', frequency: 'Monthly' },
  { category: 'Phone Recharge', frequency: 'Annually' },
  { category: 'AMC Charges', frequency: 'Quarterly' },
  { category: 'Health and Fitness', frequency: 'Monthly' },
  { category: 'Conveyance', frequency: 'Monthly' },
  { category: 'Donation', frequency: 'Monthly' },
  { category: 'Entertainment Expenses', frequency: 'Monthly' },
  { category: 'Food', frequency: 'Monthly' },
  { category: 'Groceries', frequency: 'Monthly' },
  { category: 'Fuel Expenses', frequency: 'Monthly' },
  { category: 'Medical Expenses', frequency: 'Monthly' },
  { category: 'Miscellaneous Expenses', frequency: 'Monthly' },
  { category: 'Repairs and Maintenance', frequency: 'Monthly' },
  { category: 'Shopping Expenses', frequency: 'Monthly' },
  { category: 'Personal Care/ Grooming', frequency: 'Monthly' },
  { category: 'Social Expenses', frequency: 'Monthly' },
  { category: 'Travelling', frequency: 'Monthly' },
  { category: 'Gifting', frequency: 'Monthly' },
  { category: 'Education Expenses', frequency: 'Monthly' },
  { category: 'Daily House Help', frequency: 'Monthly' }
];

const Onboarding: React.FC = () => {
  const { state, updateProfile, setAuthenticated, addWallet, addIncome, addBudget, loadStateFromCloud, updateMonitoredApps } = useFinance();
  const [authState, setAuthState] = useState<'MOBILE' | 'MFA' | 'PROFILE' | 'APP_SENTINEL'>('MOBILE');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [isVerifyingCloud, setIsVerifyingCloud] = useState(false);
  const [isExistingUser, setIsExistingUser] = useState(false);

  const [isScanning, setIsScanning] = useState(false);
  const [detectedApps, setDetectedApps] = useState<MonitoredApp[]>([]);
  const [hasScanned, setHasScanned] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    age: '',
    city: '',
    country: 'India',
    currency: 'INR',
    openingCash: '0'
  });

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 8) {
      setIsVerifyingCloud(true);
      const exists = await loadStateFromCloud(mobileNumber);
      setIsExistingUser(exists);
      setIsVerifyingCloud(false);
      setAuthState('MFA');
    }
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) {
      if (isExistingUser) setAuthenticated(true);
      else setAuthState('PROFILE');
    }
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthState('APP_SENTINEL');
  };

  const startScanning = () => {
    setIsScanning(true);
    setTimeout(() => {
      setDetectedApps(SUGGESTED_APPS);
      setIsScanning(false);
      setHasScanned(true);
    }, 3000);
  };

  const toggleApp = (id: string) => {
    setDetectedApps(prev => prev.map(a => a.id === id ? { ...a, isEnabled: !a.isEnabled } : a));
  };

  const finalizeOnboarding = () => {
    updateProfile({ 
      ...formData, 
      age: Number(formData.age), 
      mobileNumber, 
      isBoarded: true, 
      familyMembers: [],
      cloudDatabaseName: 'Default_Vault',
      monitoredApps: detectedApps.filter(a => a.isEnabled),
      remindersEnabled: true
    });

    addWallet({ id: 'default-cash', name: 'Cash', balance: Number(formData.openingCash) });

    DEFAULT_INCOME_TEMPLATE.forEach(template => {
       addIncome({
         id: Math.random().toString(36).substr(2, 9),
         name: template.name,
         amount: 0,
         periodicity: template.periodicity,
         dateOfReceipt: '',
         ownerId: ''
       });
    });

    const now = new Date();
    const currentYear = now.getFullYear();
    const startYear = now.getMonth() < 3 ? currentYear - 1 : currentYear;
    const startDate = `${startYear}-04-01`;
    const endDate = `${startYear + 1}-03-31`;

    DEFAULT_EXPENSE_TEMPLATE.forEach(template => {
       addBudget({
         id: Math.random().toString(36).substr(2, 9),
         category: template.category,
         amount: 0,
         frequency: template.frequency,
         startDate: startDate,
         endDate: endDate,
         periodType: 'Financial',
         ownerId: ''
       });
    });

    setAuthenticated(true);
  };

  const containerClasses = "min-h-[100dvh] bg-navy-900 flex items-stretch md:items-center justify-center overflow-hidden";
  const cardClasses = "w-full md:max-w-md bg-navy-800 p-8 md:p-12 md:rounded-[3rem] md:soft-shadow md:border md:border-white/5 flex flex-col justify-center animate-in fade-in zoom-in-95 duration-500";

  if (authState === 'MOBILE') {
    return (
      <div className={containerClasses}>
        <div className={cardClasses}>
          <div className="mb-12 text-center">
            <div className="w-16 h-16 mx-auto bg-brand-gradient rounded-2xl flex items-center justify-center text-3xl font-black text-white shadow-lg mb-6">M</div>
            <h2 className="text-2xl font-black text-white uppercase tracking-tight">Identity Verification</h2>
            <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-2">Secure Vault Access</p>
          </div>
          <form onSubmit={handleSendOtp} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Mobile Number</label>
              <input 
                type="tel" 
                required 
                className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-lg text-white outline-none focus:ring-4 focus:ring-brand-primary/20 text-center tracking-widest placeholder:text-white/10" 
                placeholder="9876543210"
                value={mobileNumber}
                onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))}
              />
            </div>
            <button type="submit" disabled={mobileNumber.length < 8 || isVerifyingCloud} className="w-full py-5 bg-brand-gradient text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-purple-500/20 active:scale-95 transition-all disabled:opacity-50 flex items-center justify-center gap-2">
               {isVerifyingCloud ? 'Locating Vault...' : 'Send Verification Code'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (authState === 'MFA') {
    return (
       <div className={containerClasses}>
        <div className={cardClasses}>
          <div className="mb-12 text-center">
            <h2 className="text-2xl font-black text-white uppercase tracking-tight">Enter Code</h2>
            <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-2">Sent to +91 {mobileNumber}</p>
          </div>
          <form onSubmit={handleVerifyMfa} className="space-y-8">
            <div className="flex gap-4 justify-center">
              {otp.map((d, i) => (
                <input
                  key={i}
                  type="text"
                  maxLength={1}
                  className="w-14 h-16 bg-navy-900 border border-white/10 rounded-2xl text-center text-2xl font-black text-white outline-none focus:ring-4 focus:ring-brand-primary/20 focus:border-brand-primary transition-all"
                  value={d}
                  onChange={e => {
                    const val = e.target.value;
                    if (!/^\d*$/.test(val)) return;
                    const newOtp = [...otp];
                    newOtp[i] = val;
                    setOtp(newOtp);
                    if (val && i < 3) {
                      const next = document.getElementById(`otp-${i+1}`);
                      if (next) next.focus();
                    }
                  }}
                  id={`otp-${i}`}
                />
              ))}
            </div>
            <button type="submit" className="w-full py-5 bg-brand-gradient text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-purple-500/20 active:scale-95 transition-all">
               Verify Access
            </button>
            <button type="button" onClick={() => setAuthState('MOBILE')} className="w-full text-[9px] font-black text-brand-muted uppercase tracking-widest hover:text-white">Change Number</button>
          </form>
        </div>
       </div>
    );
  }

  if (authState === 'PROFILE') {
    return (
      <div className={containerClasses}>
        <div className="w-full max-w-2xl bg-navy-800 p-8 md:p-12 md:rounded-[3rem] md:soft-shadow md:border md:border-white/5 animate-in slide-in-from-right-10 duration-500 max-h-[100dvh] overflow-y-auto">
          <div className="mb-10">
            <h2 className="text-2xl font-black text-white uppercase tracking-tight">Profile Setup</h2>
            <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-2">Initialize your financial persona</p>
          </div>
          <form onSubmit={handleProfileSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Full Name</label>
                <input required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none focus:ring-4 focus:ring-brand-primary/20" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="e.g. John Doe" />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Designation / Role</label>
                <input required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none focus:ring-4 focus:ring-brand-primary/20" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} placeholder="e.g. Senior Architect" />
              </div>
            </div>
            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Age</label>
                <input required type="number" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none focus:ring-4 focus:ring-brand-primary/20" value={formData.age} onChange={e => setFormData({...formData, age: e.target.value})} />
              </div>
              <div className="space-y-2 col-span-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Base City</label>
                <input required className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none focus:ring-4 focus:ring-brand-primary/20" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-6">
               <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Country</label>
                <select className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white outline-none cursor-pointer" value={formData.country} onChange={e => {
                  const c = countries.find(x => x.name === e.target.value);
                  setFormData({...formData, country: e.target.value, currency: c?.currency || 'USD'});
                }}>
                  {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                </select>
               </div>
               <div className="space-y-2">
                <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Currency</label>
                <input disabled className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xs text-white/50 outline-none" value={formData.currency} />
               </div>
            </div>
            <div className="space-y-2 pt-4">
              <label className="text-[9px] font-black text-brand-muted uppercase tracking-widest block ml-2">Initial Cash in Hand</label>
              <input type="number" className="w-full p-4 bg-navy-900 border border-white/10 rounded-2xl font-black text-xl text-white outline-none focus:ring-4 focus:ring-brand-primary/20" value={formData.openingCash} onChange={e => setFormData({...formData, openingCash: e.target.value})} />
            </div>
            <button type="submit" className="w-full py-5 bg-brand-gradient text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-purple-500/20 active:scale-95 transition-all mt-4">
               Proceed to App Sentinel
            </button>
          </form>
        </div>
      </div>
    );
  }

  // APP_SENTINEL State
  return (
     <div className={containerClasses}>
        <div className="w-full max-w-2xl bg-navy-800 p-8 md:p-12 md:rounded-[3rem] md:soft-shadow md:border md:border-white/5 animate-in slide-in-from-right-10 duration-500">
           <div className="mb-10 flex justify-between items-start">
              <div>
                <h2 className="text-2xl font-black text-white uppercase tracking-tight">App Sentinel</h2>
                <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mt-2">Scan device for financial footprint</p>
              </div>
              <div className="w-12 h-12 bg-navy-700 rounded-2xl flex items-center justify-center text-2xl shadow-sm">🛡️</div>
           </div>

           {!hasScanned ? (
              <div className="text-center py-12 bg-navy-900 rounded-[2rem] border border-white/5">
                 {isScanning ? (
                    <div className="flex flex-col items-center">
                       <div className="w-16 h-16 border-4 border-brand-primary border-t-transparent rounded-full animate-spin mb-6"></div>
                       <p className="text-[10px] font-black text-white uppercase tracking-widest animate-pulse">Scanning Installed Packages...</p>
                    </div>
                 ) : (
                    <div className="flex flex-col items-center">
                       <p className="text-[10px] font-black text-brand-muted uppercase tracking-widest mb-6 max-w-xs leading-relaxed">
                          We can scan your device to detect installed banking and finance apps to auto-configure your dashboard.
                       </p>
                       <button onClick={startScanning} className="px-8 py-4 bg-brand-primary text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-purple-500/20 active:scale-95 transition-all">
                          Start Deep Scan
                       </button>
                    </div>
                 )}
              </div>
           ) : (
              <div className="space-y-6">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                    {detectedApps.map(app => (
                       <div key={app.id} onClick={() => toggleApp(app.id)} className={`p-4 rounded-2xl border cursor-pointer transition-all flex items-center justify-between ${app.isEnabled ? 'bg-brand-primary/10 border-brand-primary' : 'bg-navy-900 border-white/5 opacity-60'}`}>
                          <div className="flex items-center gap-3">
                             <span className="text-xl">{app.icon}</span>
                             <div>
                                <p className="text-[10px] font-black text-white uppercase tracking-tight">{app.name}</p>
                                <p className="text-[8px] font-bold text-brand-muted uppercase">{app.category}</p>
                             </div>
                          </div>
                          <div className={`w-5 h-5 rounded-md border flex items-center justify-center ${app.isEnabled ? 'bg-brand-primary border-brand-primary text-white' : 'border-white/20'}`}>
                             {app.isEnabled && <span className="text-[8px]">✓</span>}
                          </div>
                       </div>
                    ))}
                 </div>
                 <button onClick={finalizeOnboarding} className="w-full py-5 bg-brand-gradient text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-purple-500/20 active:scale-95 transition-all">
                    Initialize Vault ({detectedApps.filter(a => a.isEnabled).length} Apps)
                 </button>
              </div>
           )}
        </div>
     </div>
  );
};

export default Onboarding;

