import React, { useState } from 'react';
import { FinanceProvider, useFinance } from './store/FinanceContext';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Accounts from './components/Accounts';
import Statements from './components/Statements';
import Profile from './components/Profile';
import Onboarding from './components/Onboarding';
import Transactions from './components/Transactions';
import Rewards from './components/Rewards';
import BudgetPlanner from './components/BudgetPlanner';
import FiscalSentinel from './components/FiscalSentinel';
import Ranking from './components/Ranking';
import DecisionMaker from './components/DecisionMaker';

const MainApp: React.FC = () => {
  const { state, isAuthenticated } = useFinance();
  const [activeTab, setActiveTab] = useState('dashboard');

  if (!isAuthenticated || !state.profile.isBoarded) {
    return <Onboarding />;
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && <Dashboard onNavigate={setActiveTab} />}
      {activeTab === 'rankings' && <Ranking />}
      {activeTab === 'transactions' && <Transactions />}
      {activeTab === 'accounts' && <Accounts />}
      {activeTab === 'statements' && <Statements />}
      {activeTab === 'profile' && <Profile />}
      {activeTab === 'rewards' && <Rewards />}
      {activeTab === 'budget' && <BudgetPlanner />}
      {activeTab === 'calendar' && <FiscalSentinel />}
      {activeTab === 'decision' && <DecisionMaker />}
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <FinanceProvider>
      <MainApp />
    </FinanceProvider>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import BulkAuditModal from './BulkAuditModal';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, setActiveMemberIds, resetBoarding, approveTransaction, rejectTransaction, handleFamilyRequest } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);
  const [showBulkAudit, setShowBulkAudit] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];

  const activePermissions = React.useMemo(() => {
    if (activeMemberIds.length === 0 || activeMemberIds.includes('all')) return null;
    if (activeMemberIds.length === 1) {
      return familyMembers.find(m => m.id === activeMemberIds[0])?.permissions || null;
    }
    return null;
  }, [activeMemberIds, familyMembers]);

  useEffect(() => {
    const handleScroll = () => { if (mainRef.current) setIsShrunk(mainRef.current.scrollTop > 30); };
    const currentMain = mainRef.current;
    if (currentMain) currentMain.addEventListener('scroll', handleScroll);
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  const rawNavItems = [
    { id: 'dashboard', label: 'Home', icon: '📊', perm: 'viewDashboard' },
    { id: 'accounts', label: 'Banks', icon: '🏦', perm: 'viewAccounts' },
    { id: 'transactions', label: 'History', icon: '💸', perm: 'viewTransactions' },
    { id: 'budget', label: 'Goals', icon: '🎯', perm: 'viewBudget' },
    { id: 'calendar', label: 'Plan', icon: '📅', perm: 'viewCalendar' },
    { id: 'statements', label: 'Audit', icon: '📜', perm: 'viewStatements' },
    { id: 'profile', label: 'You', icon: '👤', perm: null },
  ];

  const navItems = rawNavItems.filter(item => {
    if (!activePermissions || !item.perm) return true;
    return (activePermissions as any)[item.perm];
  });

  const mobileTabIds = ['dashboard', 'transactions', 'statements', 'profile'];
  const mobileNavItems = navItems.filter(item => mobileTabIds.includes(item.id));

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Family';
    if (isMeSelected) return state.profile.name || 'Me';
    const member = familyMembers.find(m => m.id === activeMemberIds[0]);
    return member ? member.name : 'View';
  };

  const pendingApprovals = state.notifications.filter(n => n.type === 'approval_request' || n.type === 'family_request');

  return (
    <div className="h-[100dvh] w-full flex bg-slate-50 font-sans selection:bg-brand-yellow/30 overflow-hidden relative">

      {/* Desktop Sidebar */}
      <aside className="hidden md:flex fixed top-0 left-0 bottom-0 w-72 bg-slate-900 z-[70] flex-col text-white border-r border-white/5">
        <div className="p-8 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-[#FEFE1F] text-[#03246B] rounded-lg flex items-center justify-center font-black">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
        </div>
        <nav className="flex-1 px-4 py-4 space-y-1 overflow-y-auto custom-scrollbar">
          {navItems.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all ${activeTab === item.id ? 'bg-[#FEFE1F] text-[#03246B] shadow-lg shadow-yellow-500/20' : 'text-slate-400 hover:text-white hover:bg-white/10'}`}>
              <span className="text-xl">{item.icon}</span><span className="uppercase tracking-widest text-[11px]">{item.label}</span>
            </button>
          ))}
          <div className="my-4 mx-5 h-px bg-white/10"></div>
          <button onClick={() => resetBoarding()} className="w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-black transition-all text-slate-400 hover:text-rose-400 hover:bg-white/5 group">
            <span className="text-xl group-hover:scale-110 transition-transform">🚪</span><span className="uppercase tracking-widest text-[11px]">Sign Out</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto custom-scrollbar md:ml-72 pb-[calc(4rem+env(safe-area-inset-bottom))] md:pb-0">
        <header className={`sticky top-0 bg-white/90 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-[60] flex justify-between items-center transition-all ${isShrunk ? 'h-14' : 'h-16 md:h-24'}`}>
          <div className="flex items-center gap-2">
             <div className="md:hidden flex items-center">
                <button onClick={() => setActiveTab('dashboard')} className="p-2 -ml-2">
                  <div className="w-8 h-8 bg-[#03246B] text-white rounded-lg flex items-center justify-center font-black text-xs">M</div>
                </button>
             </div>
             <h1 className={`text-lg font-black text-[#03246B] tracking-tight md:hidden ${isShrunk ? 'opacity-0' : 'opacity-100'}`}>MyFin</h1>
          </div>

          <div className="flex items-center gap-2 md:gap-3">
            <button onClick={() => setShowNotifications(!showNotifications)} className="relative w-10 h-10 bg-slate-50 rounded-xl text-[#03246B] flex items-center justify-center border border-slate-200">
               <span className="text-xl">🔔</span>
               {pendingApprovals.length > 0 && <span className="absolute top-2 right-2 bg-rose-500 w-2.5 h-2.5 rounded-full border-2 border-white"></span>}
            </button>

            <button onClick={() => setActiveTab('rankings')} className={`w-10 h-10 rounded-xl flex items-center justify-center border transition-all ${activeTab === 'rankings' ? 'bg-[#03246B] text-white' : 'bg-slate-50 text-[#03246B] border-slate-200'}`}>
               <span className="text-xl">🏆</span>
            </button>

            <div className="relative">
              <button onClick={() => setShowMemberSelector(!showMemberSelector)} className="flex items-center gap-2 px-3 py-2 bg-white rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-200 text-[#03246B] shadow-sm">
                <span className="max-w-[60px] md:max-w-[100px] truncate">{getSelectionLabel()}</span>
                <span>▼</span>
              </button>
              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-2 w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl z-[70] p-2 space-y-1 animate-in slide-in-from-top-2">
                    <button onClick={() => { setActiveMemberIds([]); setShowMemberSelector(false); }} className={`w-full text-left px-4 py-3 rounded-xl text-[10px] font-black uppercase ${isMeSelected ? 'bg-[#03246B] text-white' : 'hover:bg-slate-50 text-slate-500'}`}>👤 My Vault</button>
                    <button onClick={() => { setActiveMemberIds(['all']); setShowMemberSelector(false); }} className={`w-full text-left px-4 py-3 rounded-xl text-[10px] font-black uppercase ${isAllSelected ? 'bg-[#03246B] text-white' : 'hover:bg-slate-50 text-slate-500'}`}>🌍 Entire Family</button>
                    <div className="h-px bg-slate-100 my-1"></div>
                    {familyMembers.map(m => (
                      <button key={m.id} onClick={() => { setActiveMemberIds([m.id]); setShowMemberSelector(false); }} className={`w-full text-left px-4 py-3 rounded-xl text-[10px] font-black uppercase ${activeMemberIds.includes(m.id) ? 'bg-[#03246B] text-white' : 'hover:bg-slate-50 text-slate-500'}`}>
                        {m.name} {m.status === 'pending_invitation' && '⏳'}
                      </button>
                    ))}
                    <div className="h-px bg-slate-100 my-1"></div>
                    <button onClick={() => { resetBoarding(); setShowMemberSelector(false); }} className="w-full text-left px-4 py-3 rounded-xl text-[10px] font-black uppercase text-rose-500 hover:bg-rose-50">🚪 Sign Out</button>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-12 pb-12">
          {children}
        </div>

        {showNotifications && (
          <div className="fixed inset-x-4 bottom-[calc(5rem+env(safe-area-inset-bottom))] md:inset-x-auto md:top-24 md:right-8 md:bottom-auto md:w-80 bg-white border border-slate-200 rounded-3xl shadow-2xl z-[80] p-4 flex flex-col max-h-[60vh] md:max-h-[70vh]">
            <div className="flex justify-between items-center mb-4">
               <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Audit Queue</h4>
               {pendingApprovals.length > 1 && (
                 <button onClick={() => { setShowBulkAudit(true); setShowNotifications(false); }} className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-lg">Bulk Audit</button>
               )}
            </div>
            <div className="space-y-3 overflow-y-auto custom-scrollbar flex-1 pr-1">
               {pendingApprovals.length > 0 ? pendingApprovals.map(n => {
                 const isFamilyRequest = n.type === 'family_request';
                 return (
                   <div key={n.id} className={`p-4 rounded-2xl border ${isFamilyRequest ? 'bg-indigo-50 border-indigo-100' : 'bg-slate-50 border-slate-100'}`}>
                      <p className="text-[10px] font-black text-slate-800 uppercase mb-1">{n.title}</p>
                      <p className="text-[9px] text-slate-500 font-medium mb-3">{n.message}</p>
                      <div className="flex gap-2">
                         {isFamilyRequest ? (
                           <>
                              <button onClick={() => handleFamilyRequest(n.id, true)} className="flex-1 py-2 bg-[#03246B] text-white text-[9px] font-black uppercase rounded-lg">Approve</button>
                              <button onClick={() => handleFamilyRequest(n.id, false)} className="flex-1 py-2 bg-white text-slate-400 border border-slate-200 text-[9px] font-black uppercase rounded-lg">Ignore</button>
                           </>
                         ) : (
                           <>
                              <button onClick={() => approveTransaction(n.transactionId!)} className="flex-1 py-2 bg-emerald-600 text-white text-[9px] font-black uppercase rounded-lg">Verify</button>
                              <button onClick={() => rejectTransaction(n.transactionId!)} className="flex-1 py-2 bg-rose-50 text-rose-500 text-[9px] font-black uppercase rounded-lg">Reject</button>
                           </>
                         )}
                      </div>
                   </div>
                 );
               }) : <p className="text-center py-10 text-[10px] text-slate-300 uppercase font-black">Clear Ledger</p>}
            </div>
          </div>
        )}

        {showBulkAudit && <BulkAuditModal onClose={() => setShowBulkAudit(false)} />}
      </main>

      {/* Mobile Bottom Navigation */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-xl border-t border-slate-200 px-2 py-2 pb-[calc(0.5rem+env(safe-area-inset-bottom))] z-[70] flex justify-around items-center">
          {mobileNavItems.map(item => (
            <button 
               key={item.id} 
               onClick={() => setActiveTab(item.id)}
               className={`flex flex-col items-center justify-center w-14 h-12 rounded-xl transition-all ${activeTab === item.id ? 'text-[#03246B]' : 'text-slate-400'}`}
            >
               <span className={`text-2xl transition-transform ${activeTab === item.id ? 'scale-110 -translate-y-0.5' : ''}`}>{item.icon}</span>
               <span className="text-[7px] font-black uppercase tracking-widest mt-0.5">{item.label}</span>
            </button>
          ))}
      </nav>

    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateRates, calculateNetWorth, ANNUAL_MULTIPLIERS } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

type RateDisplayMode = 'hourly' | 'daily' | 'monthly';

interface DashboardProps {
  onNavigate: (tab: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onNavigate }) => {
  const { filteredState, state, activeMemberIds } = useFinance();
  const [displayMode, setDisplayMode] = useState<RateDisplayMode>('daily');
  const [hoursPerDay, setHoursPerDay] = useState(24);

  const rawRates = calculateRates(filteredState);
  const netWorthData = calculateNetWorth(filteredState);
  const currency = filteredState.profile.currency;
  const familyMembers = state.profile?.familyMembers || [];

  const dailyIncome = rawRates.income / rawRates.daysPassed;
  const dailyExpense = rawRates.expense / rawRates.daysPassed;
  const dailySavings = dailyIncome - dailyExpense;

  const currentDisplay = useMemo(() => {
    switch (displayMode) {
      case 'monthly': return { income: rawRates.income, expense: rawRates.expense, savings: rawRates.monthlySurplus, cycle: 'mo' };
      case 'daily': return { income: dailyIncome, expense: dailyExpense, savings: dailySavings, cycle: 'day' };
      default: return { income: dailyIncome / hoursPerDay, expense: dailyExpense / hoursPerDay, savings: dailySavings / hoursPerDay, cycle: 'hr' };
    }
  }, [displayMode, hoursPerDay, rawRates, dailyIncome, dailyExpense, dailySavings]);

  const budgetedAnnualIncome = (filteredState.incomes || []).reduce((acc, inc) => acc + (inc.amount * ANNUAL_MULTIPLIERS[inc.periodicity]), 0);
  const budgetedAnnualExpense = (filteredState.budgets || []).reduce((acc, bud) => acc + (bud.amount), 0);

  const budgetedDisplay = useMemo(() => {
    const dailyBIncome = budgetedAnnualIncome / 365;
    const dailyBExpense = budgetedAnnualExpense / 365;
    switch (displayMode) {
      case 'monthly': return { income: budgetedAnnualIncome / 12, expense: budgetedAnnualExpense / 12, savings: (budgetedAnnualIncome - budgetedAnnualExpense) / 12 };
      case 'daily': return { income: dailyBIncome, expense: dailyBExpense, savings: dailyBIncome - dailyBExpense };
      default: return { income: dailyBIncome / hoursPerDay, expense: dailyBExpense / hoursPerDay, savings: (dailyBIncome - dailyBExpense) / hoursPerDay };
    }
  }, [displayMode, hoursPerDay, budgetedAnnualIncome, budgetedAnnualExpense]);

  const pieData = [{ name: 'Assets', value: netWorthData.assets, color: '#03246B' }, { name: 'Liabilities', value: netWorthData.liabilities, color: '#cbd5e1' }];

  const getGreetingName = () => {
    if (activeMemberIds.includes('all')) return 'Family';
    if (activeMemberIds.length > 0) return familyMembers.find(m => m.id === activeMemberIds[0])?.name.split(' ')[0] || 'Member';
    return state.profile.name?.split(' ')[0] || 'User';
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 max-w-full">

      <div className="flex justify-between items-center">
         <div>
            <h1 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight">
              Hey, <span className="text-indigo-600">{getGreetingName()}</span>
            </h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Audit Overview</p>
         </div>
         <div className="md:hidden flex gap-2">
            <button onClick={() => onNavigate('decision')} className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center text-lg">⚖️</button>
         </div>
      </div>

      {/* Mode Selectors - Horizontal Scroll for Mobile */}
      <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl overflow-x-auto no-scrollbar">
        {(['hourly', 'daily', 'monthly'] as RateDisplayMode[]).map(mode => (
          <button 
            key={mode} 
            onClick={() => setDisplayMode(mode)}
            className={`flex-1 min-w-[80px] px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${displayMode === mode ? 'bg-[#03246B] text-white shadow-lg' : 'text-slate-500'}`}
          >
            {mode}
          </button>
        ))}
      </div>

      {/* Core Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">

         {/* Earnings Card */}
         <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
            <div className="flex justify-between items-start mb-4">
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Earnings / {currentDisplay.cycle}</p>
               <span className="text-[8px] font-black text-emerald-500 bg-emerald-50 px-2 py-0.5 rounded-full">Actual</span>
            </div>
            <div className="flex items-baseline gap-2">
               <h3 className="text-2xl font-black text-[#03246B]">{formatCurrency(currentDisplay.income, currency)}</h3>
               <p className="text-[10px] font-black text-slate-300">Target: {formatCurrency(budgetedDisplay.income, currency)}</p>
            </div>
         </div>

         {/* Burn Rate Card */}
         <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
            <div className="flex justify-between items-start mb-4">
               <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Burn / {currentDisplay.cycle}</p>
               <span className="text-[8px] font-black text-rose-500 bg-rose-50 px-2 py-0.5 rounded-full">Actual</span>
            </div>
            <div className="flex items-baseline gap-2">
               <h3 className="text-2xl font-black text-rose-500">{formatCurrency(currentDisplay.expense, currency)}</h3>
               <p className="text-[10px] font-black text-slate-300">Target: {formatCurrency(budgetedDisplay.expense, currency)}</p>
            </div>
         </div>

         {/* Net Worth (Prominent on Mobile) */}
         <div className="bg-slate-900 p-6 rounded-3xl text-white shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 text-5xl opacity-10 font-black">NET</div>
            <p className="text-[9px] font-black uppercase tracking-widest text-indigo-300">Net Position</p>
            <h3 className="text-2xl font-black mt-1">{formatCurrency(netWorthData.netWorth, currency)}</h3>
            <div className="mt-4 flex gap-4">
               <div className="flex-1">
                  <p className="text-[7px] uppercase font-black text-white/40">Assets</p>
                  <p className="text-[10px] font-black">{formatCurrency(netWorthData.assets, currency)}</p>
               </div>
               <div className="flex-1">
                  <p className="text-[7px] uppercase font-black text-white/40">Debt</p>
                  <p className="text-[10px] font-black">{formatCurrency(netWorthData.liabilities, currency)}</p>
               </div>
            </div>
         </div>
      </div>

      {/* Composition & Activity Area */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 md:p-8 rounded-[2rem] border border-slate-200 shadow-sm">
           <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest mb-6">Wealth Balance</h4>
           <div className="h-56 w-full relative">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={pieData} cx="50%" cy="50%" innerRadius="60%" outerRadius="80%" paddingAngle={5} dataKey="value" stroke="none">
                    {pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
              <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                <span className="text-[8px] font-black text-slate-400 uppercase">Equity</span>
                <span className="text-lg font-black">{((netWorthData.netWorth / Math.max(1, netWorthData.assets)) * 100).toFixed(0)}%</span>
              </div>
           </div>
        </div>

        <div className="bg-white p-6 md:p-8 rounded-[2rem] border border-slate-200 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Audit Logs</h4>
            <button onClick={() => onNavigate('transactions')} className="text-[9px] font-black text-indigo-600">See All</button>
          </div>
          <div className="space-y-4">
            {state.notifications.slice(0, 3).map(n => (
              <div key={n.id} className="flex gap-4 items-center p-3 hover:bg-slate-50 rounded-2xl transition-all">
                <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-lg">{n.type === 'transaction' ? '💸' : '🔔'}</div>
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] font-black text-slate-800 uppercase truncate">{n.title}</p>
                  <p className="text-[9px] text-slate-500 font-medium line-clamp-1">{n.message}</p>
                </div>
              </div>
            ))}
            {state.notifications.length === 0 && <p className="text-center py-10 text-[9px] font-black text-slate-300 uppercase italic">Ledger Empty</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import { GoogleGenAI, Type } from "@google/genai";
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useFinance } from '../store/FinanceContext';
import { Transaction, TransactionType, TransactionAttachment } from '../types';
import { formatCurrency } from '../utils/formatters';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, uploadToDrive } = useFinance();
  const familyMembers = (state.profile?.familyMembers || []).filter(m => m.status === 'verified');
  const natures = state.transactionNatures || [];

  const [showModal, setShowModal] = useState(false);
  const [modalMode, setModalMode] = useState<'single' | 'broker_note'>('single');
  const [editingId, setEditingId] = useState<string | null>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [pendingFiles, setPendingFiles] = useState<File[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [viewingAttachments, setViewingAttachments] = useState<Transaction | null>(null);

  const [scanResult, setScanResult] = useState<{ date: string; trades: any[]; } | null>(null);
  const uploadInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || 'General',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    estimatedLife: '1' 
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank', ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card', ownerId: c.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet', ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets];
  }, [state.banks, state.cards, state.wallets]);

  const handleQuickAdd = (type: TransactionType) => {
    setFormData({ ...initialFormState, type });
    setModalMode('single');
    setScanResult(null);
    setPendingFiles([]);
    setEditingId(null);
    setShowModal(true);
  };

  const handleEdit = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      estimatedLife: String(t.estimatedLife || 1)
    });
    setModalMode('single');
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select account.");

    setIsUploading(true);
    const uploadedAttachments: TransactionAttachment[] = [];
    for (const file of pendingFiles) {
       const att = await uploadToDrive(file);
       uploadedAttachments.push(att);
    }

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type, 
      amount: Number(formData.amount), 
      nature: formData.nature,
      description: formData.description, 
      accountId: formData.accountId, 
      accountType: account.type as any,
      date: formData.date, 
      ownerId: formData.ownerId, 
      isin: formData.isin, 
      stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined, 
      status: 'active',
      attachments: uploadedAttachments
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);

    setIsUploading(false);
    setShowModal(false);
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 max-w-full">

      {/* Thumb-friendly Quick Actions */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
         <button onClick={() => handleQuickAdd('Expense')} className="p-4 bg-rose-50 border border-rose-100 rounded-2xl flex flex-col items-center gap-1 active:scale-95 transition-all shadow-sm">
            <span className="text-2xl">💸</span>
            <span className="text-[9px] font-black text-rose-600 uppercase tracking-widest">Expense</span>
         </button>
         <button onClick={() => handleQuickAdd('Income')} className="p-4 bg-emerald-50 border border-emerald-100 rounded-2xl flex flex-col items-center gap-1 active:scale-95 transition-all shadow-sm">
            <span className="text-2xl">💰</span>
            <span className="text-[9px] font-black text-emerald-600 uppercase tracking-widest">Income</span>
         </button>
         <button onClick={() => handleQuickAdd('Asset')} className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl flex flex-col items-center gap-1 active:scale-95 transition-all shadow-sm">
            <span className="text-2xl">💎</span>
            <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">Asset</span>
         </button>
         <button onClick={() => { setModalMode('broker_note'); setShowModal(true); }} className="p-4 bg-slate-900 border border-slate-800 rounded-2xl flex flex-col items-center gap-1 active:scale-95 transition-all shadow-lg">
            <span className="text-2xl">🤖</span>
            <span className="text-[9px] font-black text-white uppercase tracking-widest">AI Import</span>
         </button>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
           <h3 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">Recent Ledger</h3>
           <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{filteredState.transactions.length} Records</span>
        </div>

        {/* Mobile-First Card View (Desktop fallback to table if screen is large) */}
        <div className="divide-y divide-slate-50">
          {filteredState.transactions.map(t => (
            <div key={t.id} onClick={() => handleEdit(t)} className="p-5 hover:bg-slate-50 transition-all flex items-center justify-between group active:bg-slate-100 cursor-pointer">
               <div className="flex items-center gap-4 min-w-0">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg flex-shrink-0 ${
                    t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' :
                    t.type === 'Expense' ? 'bg-rose-50 text-rose-500' : 'bg-indigo-50 text-indigo-600'
                  }`}>
                    {t.type === 'Income' ? '💰' : t.type === 'Expense' ? '💸' : '💎'}
                  </div>
                  <div className="min-w-0">
                    <p className="text-[10px] font-black text-slate-800 uppercase tracking-tight truncate">{t.description || t.nature}</p>
                    <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{t.date} • {t.nature}</p>
                  </div>
               </div>
               <div className="text-right ml-4">
                  <p className={`text-sm font-black tracking-tight ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                    {formatCurrency(t.amount, currency)}
                  </p>
                  {t.attachments && t.attachments.length > 0 && <span className="text-[8px] font-black text-indigo-500 uppercase">📎 Doc</span>}
               </div>
            </div>
          ))}
          {filteredState.transactions.length === 0 && <p className="py-20 text-center text-[10px] font-black text-slate-300 uppercase italic">Empty Vault</p>}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex justify-center items-end md:items-center bg-slate-900/60 backdrop-blur-md p-0 md:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] md:rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in slide-in-from-bottom-10 duration-300 flex flex-col max-h-[95vh] overflow-hidden">
            <div className="flex justify-between items-center mb-6 shrink-0">
               <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Audit Record</h3>
               <button onClick={() => setShowModal(false)} className="text-slate-300 p-2">✕</button>
            </div>

            <div className="flex-1 overflow-y-auto no-scrollbar pb-10">
              <form onSubmit={handleSubmit} className="space-y-6">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">Type</label>
                    <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[11px] uppercase" value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}>
                      <option>Expense</option><option>Income</option><option>Asset</option><option>Liability</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">Date</label>
                    <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[11px] uppercase" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} />
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">Net Amount</label>
                  <input required type="number" step="any" inputMode="decimal" className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-black text-3xl text-[#03246B]" value={formData.amount} onChange={e => setFormData({...formData, amount: e.target.value})} placeholder="0.00" />
                </div>

                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">Instrument / Account</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[11px] uppercase" value={formData.accountId} onChange={e => setFormData({...formData, accountId: e.target.value})}>
                    <option value="">Select Target</option>
                    {allAccounts.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                  </select>
                </div>

                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest ml-1">Narrative</label>
                  <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl font-black text-[11px] uppercase" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} placeholder="What was this for?" />
                </div>

                <div className="flex gap-4 pt-4 sticky bottom-0 bg-white">
                   <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-4 bg-slate-50 text-slate-400 font-black text-[10px] uppercase rounded-2xl">Cancel</button>
                   <button type="submit" className="flex-[2] py-4 bg-[#03246B] text-white rounded-2xl font-black text-[10px] uppercase shadow-xl active:scale-95 transition-all">Establish Audit</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState } from 'react';
import { FinanceProvider, useFinance } from './store/FinanceContext';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Accounts from './components/Accounts';
import Statements from './components/Statements';
import Profile from './components/Profile';
import Onboarding from './components/Onboarding';
import Transactions from './components/Transactions';
import Rewards from './components/Rewards';
import BudgetPlanner from './components/BudgetPlanner';
import FiscalSentinel from './components/FiscalSentinel';
import Ranking from './components/Ranking';
import DecisionMaker from './components/DecisionMaker';

const MainApp: React.FC = () => {
  const { state, isAuthenticated } = useFinance();
  const [activeTab, setActiveTab] = useState('dashboard');

  if (!isAuthenticated || !state.profile.isBoarded) {
    return <Onboarding />;
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {activeTab === 'dashboard' && <Dashboard onNavigate={setActiveTab} />}
      {activeTab === 'rankings' && <Ranking />}
      {activeTab === 'transactions' && <Transactions />}
      {activeTab === 'accounts' && <Accounts />}
      {activeTab === 'statements' && <Statements />}
      {activeTab === 'profile' && <Profile />}
      {activeTab === 'rewards' && <Rewards />}
      {activeTab === 'budget' && <BudgetPlanner />}
      {activeTab === 'calendar' && <FiscalSentinel />}
      {activeTab === 'decision' && <DecisionMaker />}
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <FinanceProvider>
      <MainApp />
    </FinanceProvider>
  );
};

export default App;
